        //*Tao 62-11-12 ����������� �������?�??�������
        public bool C_PRCbPmtInit(bool pbPrcActivePmt = false) //Step 0 (True=��?�?�?����), Step 1 (False=�������?������)
        {
            try
            {
                if (cCNSP.C_PRCDeCryptStr(tDllKey, tDllPass, 256) != "AdaNewPmt") return false;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPmtInit] ============ START ============");
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPmtInit] ActivePmt : " + pbPrcActivePmt);
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPmtInit] SaleDate : " + cCNSP.SP_DTEtByFormat(dSaleDate) + ", PosCode : " + tPosCode);

                //Create Active Promotion
                if (pbPrcActivePmt)
                {
                    return C_PRCbPmtChkActive();
                }
                else
                {
                    //Create Temp Sale

                    //cCNSP.SP_TBLbChkTempTable("TSPT" + tPosCode, true, false);
                    //cCNSP.SP_TBLbChkTempTable("TSPS" + tPosCode, true, false);
                    //cCNSP.SP_TBLbChkTempTable("TSPX" + tPosCode, true, false);
                    //cCNSP.SP_TBLbChkTempTable("TSPY" + tPosCode, true, false);
                    //cCNSP.SP_TBLbChkTempTable("TSPZ" + tPosCode, true, false);
                    cCNSP.SP_TBLbChkTempTable("TSHD" + tPosCode, false, false);
                    cCNSP.SP_TBLbChkTempTable("TSDT" + tPosCode, false, false);
                    cCNSP.SP_TBLbChkTempTable("TSRC" + tPosCode, false, false);
                    cCNSP.SP_TBLbChkTempTable("TSDP" + tPosCode, false, false);
                    cCNSP.SP_TBLbChkTempTable("TXML" + tPosCode, false, false);
                    cCNSP.SP_TBLbChkTempTable("TSVT" + tPosCode, false, false);
                    cCNSP.SP_TBLbChkTempTable("TSCD" + tPosCode, false, false); //*Tao 62-01-03 ���?���� �?�������??
                    cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPmtInit] ============  END  ============");
                    return true;
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbPmtInit] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 62-11-19 �����������������??�?��?���?
        public bool C_PRCbPdtGenPmt(int pnPdtSeq, string ptPdtBarCode, int pnPdtQty = 1, bool pbInsDT = false) //Step 2
        {
            try
            {
                if (cCNSP.C_PRCDeCryptStr(tDllKey, tDllPass, 256) != "AdaNewPmt") return false;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[cAdaNewPmt] V." + VersionDll + "");
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPdtGenPmt] ============ START ============");
                bool bResult = false;
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPdtGenPmt] DocNo : " + tShdDocNo + ", Seq : " + pnPdtSeq.ToString() + ", BarCode : " + ptPdtBarCode + ", Qty : " + pnPdtQty.ToString());
                cCNVB.tVB_ShdDocNo = tShdDocNo;
                if (pbInsDT)
                {
                    if (!C_PRCbSavePdt2DT(pnPdtSeq, ptPdtBarCode, pnPdtQty)) //*Tao 62-11-22 Insert �?��� ���� TSDTxxx
                    {
                        cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbPdtGenPmt] Result : False");
                        return false;
                    }
                    bResult = true;
                }
                else
                {
                    using (DataTable oDbTblCheckPmt = C_GEToPdtFindPmtExist(ptPdtBarCode))
                    {
                        if (oDbTblCheckPmt.Rows.Count > 0)
                        {
                            string tPmtCode = "";
                            string tPmtType = "";
                            string tPdtName = "";
                            string tDT = "TSDT" + tPosCode;
                            string tSql = "";
                            for (int i = 0; i < oDbTblCheckPmt.Rows.Count; i++)
                            {
                                tPmtCode = oDbTblCheckPmt.Rows[0]["FTPmhDocNo"].ToString();
                                tPmtType = oDbTblCheckPmt.Rows[0]["FNSpmType"].ToString();
                                tPdtName = "*" + tPdtName;
                                i = oDbTblCheckPmt.Rows.Count; //�����������? ��?���?�?
                            }
                            tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                            tSql += "\n SET FTPmhCode='" + tPmtCode + "'";
                            tSql += "\n ,FTPmhType='" + tPmtType + "'";
                            tSql += "\n ,FTPdtName='*'+FTPdtName";
                            tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                            tSql += "\n AND FNSdtSeqNo=" + pnPdtSeq;
                            bResult = cCNSP.SP_SQLbExecute(tSql);
                        }
                    }
                }
                //===============================================
                if (C_PRCbSavePdt2PT(pnPdtSeq, ptPdtBarCode, pnPdtQty)) //Insert �?��� ������������ ���� TSPTxxx
                {
                    if (C_PRCbSavePdt2DP(pnPdtSeq, ptPdtBarCode, pnPdtQty)) //Insert �?��� ������������ ���� TSDPxxx
                    {
                        bResult = C_GETbPmtProduct(); //�??�������                     
                    }
                    else
                    {
                        bResult = false;
                    }
                }
                else
                {
                    bResult = false;
                }
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbPdtGenPmt] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbPdtGenPmt] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 62-11-21 �??������?������ �?��?�����������
        public bool C_PRCbCALSubTotal() //Step 3
        {
            try
            {
                if (cCNSP.C_PRCDeCryptStr(tDllKey, tDllPass, 256) != "AdaNewPmt") return false;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALSubTotal] ============ START ============");
