                C_SETxAllValue();
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALSubTotal] DocNo : " + tShdDocNo);
                C_PRCbClearSalePmt(false); //63-04-23 Clear Promotion
                oW_SqlHDPmtGroup2 = new StringBuilder();
                oW_SqlDTPmtGroup2 = new StringBuilder();
                oW_SqlRCPmtGroup2 = new StringBuilder();
                oW_SqlDPPmtGroup2 = new StringBuilder();
                oW_SqlCDPmtGroup2 = new StringBuilder();
