                nW_DTSeqNO = int.Parse(cCNSP.SP_SQLtFunction("MAX", "FNSdtSeqNo", cCNVB.tVB_TmpDT, "WHERE FTShdDocNo='" + cCNVB.tVB_ShdDocNo + "'", "0")); //Seq ����?� DT
                nW_RCSeqNO = int.Parse(cCNSP.SP_SQLtFunction("MAX", "FNSrcSeqNo", cCNVB.tVB_TmpRC, "WHERE FTShdDocNo='" + cCNVB.tVB_ShdDocNo + "'", "0")); //Seq ����?� RC
                cCNVB.cVB_SubTotal = double.Parse(cCNSP.SP_SQLtFunction("SUM", "FCSdtNet", cCNVB.tVB_TmpDT, "WHERE FTShdDocNo='" + cCNVB.tVB_ShdDocNo + "' AND FTSdtStaPdt='1' AND ISNULL(FTCpnCode,'')=''", "0")); //�?�����?���?��� ��?�??�������
                cCNVB.cVB_CNSumDiscPmt = 0;

