                tSql = "DECLARE @tUserIns VARCHAR(50)";
                tSql += "\n SET @tUserIns = '" + tUserName + "'";
                oW_SqlDTPmtGroup2.AppendLine(tSql);
                oW_SqlRCPmtGroup2.AppendLine(tSql);
                C_PRCbCALDiscPmt(); //*Tao 63-04-16 Promotion Type 12-15 N=95,96,97,98 16-17 N=99,100
                //C_PRCbCALPmtGP(); //�?���? Promotion Type 18, N=93
                C_PRCbCALPmtCpn(); //Promotion Type 19, N=92
                ////C_PRCbCALPdtRePack(); //RePack ��?�?� �������?
                C_PRCbCALPmtType20(); //*Tao 63-04-27 Prprotion Type 20 N=91
                if (!W_SQLbExecute(2))
                {
                    bResult = false;
                    cCNVB.cVB_CNSumDiscPmt = 0; //Update Promotion Group2 (������?��?��) �������� ���?��??���??���?��?
                }
                //*Tao 63-05-04 �?? Staff Discount
                if ((tShdDocType == "1") && (bIsMember) && (tSegLevelID != ""))
                {
                    //C_PRCbCALStaffDisc();
                }

                ////Sum Disc Member
                //cCNVB.cVB_SumPmtNoVat = C_PRCcCALPmtNoVat(); //*Tao 63-04-28 �?�?�?��?����������� ��������������?������
                //cCNVB.cVB_SumPmtNoDis = C_PRCcCALPmtNoDisc(); //*Tao 63-04-28 �?�?�?��?����������� �������?
                //cCNVB.cVB_SumNoDisNoVat = C_PRCcCALPdtNoVatNoDisc(); //*Tao 63-04-28 �?�?�?��� ��������������?������ ��� ����?
                //cCNVB.cVB_SumNoDis = C_PRCcCALPdtNoDisc(); //*Tao 63-04-28 �?�?�?��� �������?
                //cCNVB.cVB_SumNoVat = C_PRCcCALPdtNoVat(); //*Tao 63-04-28 �?�?�?��� ��������������?������
                //cCNVB.cVB_SumVat = C_PRCcCALPdtVat(); //*Tao 63-04-28 �?�?�?��� �����������?������
                //cCNVB.cVB_SumPmt = C_PRCcCALPdtPmt(); //*Tao 63-04-28 �?�?�?��� ������������
                //cCNVB.cVB_SumNoPmt = C_PRCcCALPdtNoPmt(); //*Tao 63-04-28 �?�?�?��� ���������������
                ////cCNVB.cVB_Rounding = C_PRCcCALRounding(); //*Tao 63-04-28 �?�?��??���
                ////cCNVB.cVB_Disc = C_PRCcCALSumDisc(); //*Tao 63-04-28 �?��??������?��
                ////cCNVB.cVB_TotalDisc = (cCNVB.cVB_Disc - cCNVB.cVB_Rounding); //*Tao 63-04-28 �?�����??������?�� ��?�?���
                //if (cCNVB.bVB_CNAlwDisPmt) //?��������������?���?��?��?��
                //{
                //    cCNVB.cVB_SumNoPmt = (cCNVB.cVB_SumNoPmt + cCNVB.cVB_SumPmt - cCNVB.cVB_SumNoDis); //�??�� =(�?���������������+�?������������)-�?����������������?
                //    cCNVB.cVB_SumPmt = 0;
                //    cCNVB.cVB_SumPmtNoVat = 0;
                //}
                //else
