                //    cCNVB.cVB_SumPmtNoVat = cCNVB.cVB_SumPmtNoVat - (cCNVB.cVB_SumPmtNoDis - (cCNVB.cVB_SumNoDis - cCNVB.cVB_SumPmtNoDis));
                //}
                //63-04-29 Sum Vat Promotion
                if (tRetVATInOrEx == "")
                {
                    tRetVATInOrEx = cCNSP.SP_SQLtFunction("TOP 1", "FTCmpRetInOrEx", "TCNMComp", "WHERE FTCmpCode='001'", "1");
