                }
                //*Tao 63-04-24 ��?����??���?�� Type 12-15,18 ����� HD ����
                cDis = cCNVB.cVB_CNSumDiscPmt + cCNVB.cVB_StaffDiscAmt;
                cTotal = (cShdTotal - cDis);
                cAft = (cShdTotal - cDis + cChg);
                cRoundRcv = cCNSP.SP_GETcRoundDiff(cAft + cCNVB.cVB_SumPmt + cCNVB.cVB_SumNoDis);
                if (cDis > 0)
                {
                    if (cCNVB.cVB_CNSumDiscPmt > 0) { tDisChgTxt = tDisChgTxt == "" ? String.Format("{0:F2}", cCNVB.cVB_CNSumDiscPmt) : ";" + String.Format("{0:F2}", cCNVB.cVB_CNSumDiscPmt); }
                    if (cCNVB.cVB_StaffDiscAmt > 0) { tDisChgTxt = (tDisChgTxt == "" ? String.Format("{0:F2}", cCNVB.cVB_StaffDiscRate) : ";" + String.Format("{0:F2}", cCNVB.cVB_StaffDiscRate)) + "%"; } //Staff Discount ?�� %
                }
                cVat = (cCNVB.tVB_CNRetVATInOrEx == "1" ? cCNSP.SP_CALcVatValue((tRetVATInOrEx == "1" ? false : true), (cAft - cRoundRcv), cVatRate) : 0);
                cVatable = ((cCNVB.tVB_CNRetVATInOrEx == "1") ? (cAft - cRoundRcv) - cVat : 0);  //1:vat, 2:novat (0)
                tSql = "UPDATE " + tHD + " WITH(ROWLOCK)"; //�������?? / ���� = Total - NoVat - Promotion
                tSql += "\n SET FCShdNonVat=" + String.Format("{0:F2}", cCNVB.cVB_SumNoVat);
                tSql += "\n ,FCShdMnyCls=" + String.Format("{0:F2}", cCNVB.cVB_SumNoVat);
                tSql += "\n ,FCShdB4DisChg=" + String.Format("{0:F2}", cShdTotal); //Vat No Pmt
                tSql += "\n ,FCShdAftDisChg=" + String.Format("{0:F2}", cAft); //Vat No Pmt
                tSql += "\n ,FCShdDisPmt=" + String.Format("{0:F2}", cShdDisPmt); //DisPmtBill
                tSql += "\n ,FTPmhDocNoBill='" + tPmtDocNo + "'";
                tSql += "\n ,FTShdCpnCodeRef='" + cCNVB.tVB_CNPmtCpnCode + "/" + cCNVB.nVB_CNPmtCpnQty + "'"; //Coupon No & Coupon Qty
                tSql += "\n ,FCShdCpnRcv=" + String.Format("{0:F2}", cCNVB.cVB_CNPmtCpnAmt); //Coupon Value
                tSql += "\n ,FCShdTotal=" + String.Format("{0:F2}", cAft); //Total
                tSql += "\n ,FCShdVat=" + String.Format("{0:F2}", cVat); //Vat
                tSql += "\n ,FCShdVatable=" + String.Format("{0:F2}", cVatable); //Vatable
                tSql += "\n ,FCShdGrand=" + String.Format("{0:F2}", cAft); //Grand
                tSql += "\n ,FCShdReceive=" + String.Format("{0:F2}", cAft); //Receive
                tSql += "\n ,FTShdGndText='" + cCNSP.SP_GETtThaiBaht(cAft) + "'"; //Grand Text
                tSql += "\n ,FCShdRnd=" + String.Format("{0:F2}", cRoundRcv); //Rounding
                tSql += "\n ,FCShdDis=" + String.Format("{0:F2}", cDis); //DisPmt
                tSql += "\n ,FTShdDisChgTxt='" + tDisChgTxt + "'"; //DisPmt
                tSql += "\n  WHERE FTShdDocNo='" + tShdDocNo + "'";
                bResult = cCNSP.SP_SQLbExecute(tSql);

                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALSubTotal] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbCALSubTotal] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-05-05 �??��?? Staff Discount
        private bool C_PRCbCALStaffDisc()
        {
            try
            {
                string tDT = "TSDT" + tPosCode;
                string tDP = "TSDP" + tPosCode;
                string tCD = "TSCD" + tPosCode;
                bool bResult = false;
                string tSql = "";
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALStaffDisc] ============ START ============");
                //���?��?���?�����??������� (��� get ��� buy)
                tSql = "SELECT SUM(FCSumNet) AS FCAllowDisc FROM ("; //�?�?���?�� ��� �?����?��?����� - �?����?��?����������������
                tSql += "\n SELECT SUM(ISNULL(FCSdtB4DisChg,0)) AS FCSumNet FROM " + tDT + " WITH(NOLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                tSql += "\n AND FTPdtNoDis='2'"; //���?��?��?��
                tSql += "\n AND FNSdtSeqNo NOT IN (SELECT FNSdtSeqNo FROM " + tDP + " WITH(NOLOCK) WHERE FTShdDocNo='" + tShdDocNo + "' AND FNSpmType = 28)"; //*Thana 2026-05-21 Exclude Non-Sale
                tSql += "\n GROUP BY FNSdtSeqNo";
                tSql += "\n UNION ALL";
                tSql += "\n SELECT SUM(ISNULL(FCDtpNet,0)*(-1)) AS FCSumNet FROM " + tDP + " WITH(NOLOCK)"; //�?����?��?����� ����?��� Void ��� ���??�� ��� ���?��?����������������
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND ISNULL(FNSpmType,0)<>0"; //���?��?����������������
                tSql += "\n AND FNSpmType <> 28"; //*Thana 2026-05-21 Exclude Non-Sale
                tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                tSql += "\n AND FTPdtNoDis='2'"; //���?��?��?��
                tSql += "\n GROUP BY FNSdtSeqNo";
                tSql += "\n ) StaffDisc";
                using (DataTable oDbTblTmp = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblTmp != null)
                    {
                        if (oDbTblTmp.Rows.Count > 0)
                        {
                            double cAllowDisc = double.Parse(oDbTblTmp.Rows[0]["FCAllowDisc"].ToString()); //*Thana 2026-05-21 Fix column name
                            if (cAllowDisc > 0)
                            {
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALStaffDisc] Amount Staff Disc : " + cAllowDisc.ToString());
                                tSql = "SELECT TOP 1 FCDiscRate, FTSegmentDescription, FTDiscountID FROM TCNTStaffDiscountT1 WITH(NOLOCK)";
                                tSql += "\n WHERE FTSegmentLevelID='" + tSegLevelID + "'";
                                tSql += "\n AND '" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN FDDiscStartDate AND FDDiscEndDate";
                                tSql += "\n AND FTBchCode='" + tBchCode + "'";
                                tSql += "\n ORDER BY FDDiscStartDate";
                                using (DataTable oDbTblStd = cCNSP.SP_SQLoExecute(tSql))
                                {
                                    if (oDbTblStd != null)
                                    {
                                        if (oDbTblStd.Rows.Count > 0)
                                        {
                                            double cDiscRate = double.Parse(oDbTblStd.Rows[0]["FCDiscRate"].ToString());
                                            string tDiscDesc = oDbTblStd.Rows[0]["FTSegmentDescription"].ToString();
                                            string tStaffDiscID = oDbTblStd.Rows[0]["FTDiscountID"].ToString();
                                            cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALStaffDisc] DiscRate : " + cDiscRate.ToString());
                                            if ((cDiscRate > 0) && (cDiscRate < 100))
                                            {
                                                if (cAllowDisc >= ((cDiscRate / 100) * cAllowDisc))
                                                {
                                                    cCNVB.cVB_StaffDiscRate = cDiscRate;
                                                    cCNVB.cVB_StaffDiscAmt = ((cDiscRate / 100) * cAllowDisc);
                                                    nW_CDSeqNo += 1;
                                                    tSql = "INSERT INTO " + tCD + " WITH(ROWLOCK)";
                                                    tSql += "\n SELECT FTBchCode,FTShdDocNo," + nW_CDSeqNo + ",0,''";
                                                    tSql += "\n ,0,'','','',FTShdDocType";
                                                    tSql += "\n ,FDShdDocDate,0,0," + cCNVB.cVB_StaffDiscAmt + ",''";
                                                    tSql += "\n ,'',0,0,NULL,NULL";
                                                    tSql += "\n ,0,'7',0,0,0"; //7=Staff Discount
                                                    tSql += "\n ,0,0,0,0,0";
                                                    tSql += "\n ,'',''";
                                                    tSql += "\n ,FDDateUpd,FTTimeUpd,FTWhoUpd,FDDateIns,FTTimeIns,FTWhoIns";
                                                    tSql += "\n FROM " + tDP + " WITH(NOLOCK)";
                                                    tSql += "\n WHERE FNDtpSeqNo=1";
                                                    tSql += "\n AND FTShdDocNo='" + tShdDocNo + "'";
                                                    tSql += "\n ;";
                                                    cCNSP.SP_SQLbExecute(tSql);
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                bResult = true;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALStaffDisc] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbCALStaffDisc] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-04-30 �???���
        private bool C_PRCbUpdQtyBillbyType(int pnType, string ptPosCode = "", string ptPmhDocNo = "")
        {
            try
            {
                string tHD = "TSHD" + tPosCode;
                string tPG = "TSPG" + tPosCode;
                bool bResult = false;
                string tSql = "";
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUpdQtyBillbyType] ============ START ============");
                string tInsDate = "";
                string tUpdDate = "";
                string tWhereDate = "";

                switch (pnType)
                {
                    case 0: //Day
                        tInsDate = ",'" + cCNSP.SP_DTEtByFormat(dSaleDate) + "'";
                        tUpdDate = " AND FDCptStartDate='" + cCNSP.SP_DTEtByFormat(dSaleDate) + "'";
                        tWhereDate = " AND FDCptStartDate='" + cCNSP.SP_DTEtByFormat(dSaleDate) + "'";
                        break;
                    case 1: //Month
                        tInsDate = ",'" + dSaleDate.ToString("yyyy") + "-" + dSaleDate.ToString("MM") + "-01'";
                        tUpdDate = " AND YEAR(FDCptStartDate)=" + dSaleDate.Year + " AND MONTH(FDCptStartDate)=" + dSaleDate.Month;
                        tWhereDate = " AND YEAR(FDCptStartDate)=" + dSaleDate.Year + " AND MONTH(FDCptStartDate)=" + dSaleDate.Month;
                        break;
                    case 2: //Year
                        tInsDate = ",'" + dSaleDate.ToString("yyyy") + "01-01'";
                        tUpdDate = " AND YEAR(FDCptStartDate)=" + dSaleDate.Year;
                        tWhereDate = " AND YEAR(FDCptStartDate)=" + dSaleDate.Year;
                        break;
                }
                tSql = "DECLARE @tUserIns VARCHAR(50)";
                tSql += "\n SET @tUserIns = '" + tUserName + "'";
                tSql += "DECLARE @tUserUpd VARCHAR(50)";
                tSql += "\n SET @tUserUpd = '" + tUserName + "'";
                tSql += "IF NOT EXISTS(";
                tSql += tSql + "\n SELECT FNCptQty";
                tSql += tSql + "\n FROM TSysCountPmt WITH(NOLOCK)";
                tSql += tSql + "\n WHERE FTPosCode='" + ptPosCode == "" ? "ADA" : ptPosCode + "'";
                tSql += tSql + "\n AND FTCptType='" + (pnType + 1) + "'";
                tSql += tSql + "\n AND FTPmhDocNo='" + ptPmhDocNo == "" ? "AdaSoft" : ptPmhDocNo + "'";
                tSql += tSql + "\n " + tWhereDate + ")";
                tSql += tSql + "\n BEGIN";
                tSql += tSql + "\n INSERT INTO TSysCountPmt (";
                tSql += tSql + "\n FTPosCode,FTCptType,FTPmhDocNo,FDCptStartDate,FNCptQty";
                tSql += tSql + "\n ," + cCNCS.tCS_CNLastFedIns;
                tSql += tSql + "\n ) VALUES ('" + ptPosCode == "" ? "ADA" : ptPosCode + "','" + (pnType + 1) + "','" + ptPmhDocNo == "" ? "AdaSoft" : ptPmhDocNo + "'";
                tSql += tSql + "\n " + tInsDate;
                tSql += tSql + "\n ,1,";
                tSql += tSql + "\n " + cCNCS.tCS_CNLastValIns + ")";
                tSql += tSql + "\n END";
                tSql += tSql + "\n ELSE";
                tSql += tSql + "\n BEGIN";
                tSql += tSql + "\n UPDATE TSysCountPmt WITH(ROWLOCK) SET FNCptQty=FNCptQty+1";
                tSql += tSql + "\n ," + cCNCS.tCS_CNLastFedUpd;
                tSql += tSql + "\n WHERE FTPosCode='" + ptPosCode == "" ? "ADA" : ptPosCode + "'";
                tSql += tSql + "\n AND FTCptType='" + (pnType + 1) + "'";
                tSql += tSql + "\n AND FTPmhDocNo='" + ptPmhDocNo == "" ? "AdaSoft" : ptPmhDocNo + "'";
                tSql += tSql + "\n " + tUpdDate;
                tSql += tSql + "\n END";
                cCNSP.SP_SQLbExecute(tSql);

                bResult = true;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUpdQtyBillbyType] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbUpdQtyBillbyType] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-04-30 �???���
        private bool C_PRCbUpdQtyBill()
        {
            try
            {
                string tCD = "TSCD" + tPosCode;
                string tPG = "TSPG" + tPosCode;
                bool bResult = false;
                string tSql = "";
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUpdQtyBill] ============ START ============");
                for (int iType = 0; iType <= 2; iType++)
                {
                    C_PRCbUpdQtyBillbyType(iType);
                }
                tSql = "SELECT FTPmhDocNo";
                tSql += "\n FROM " + tPG + " WITH(NOLOCK)";
                tSql += "\n WHERE FTPmhDocNo IN (";
                tSql += "\n SELECT FTDtpPmhBillDocNo FROM " + tCD + " WITH(NOLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "')";
                tSql += "\n FTSdtStaPdt='1'";
                tSql += "\n AND FNSpgType IN (95, 96, 97, 98)";
                using (DataTable oDbTblTmp = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblTmp != null)
                    {
                        if (oDbTblTmp.Rows.Count > 0)
                        {
                            for (int iTmp = 0; iTmp < oDbTblTmp.Rows.Count; iTmp++)
                            {
                                string tPmhDocNo = oDbTblTmp.Rows[iTmp]["FTPmhDocNo"].ToString();
                                if (!string.IsNullOrEmpty(tPmhDocNo))
                                {
                                    for (int iType = 0; iType <= 2; iType++)
                                    {
                                        C_PRCbUpdQtyBillbyType(iType, tPosCode, tPmhDocNo);
                                    }
                                }
                            }
                        }
                    }
                }
                bResult = true;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUpdQtyBill] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbUpdQtyBill] Error : " + ex.Message);
                return false;
            }
        }

