        //*Tao 63-04-23 Clear Temp Sale
        public bool C_PRCbClearSalePmt(bool pbBackBegin = true) //Step 5
        {
            try
            {
                if (cCNSP.C_PRCDeCryptStr(tDllKey, tDllPass, 256) != "AdaNewPmt") return false;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbClearSalePmt] ============ START ============");
                bool bResult = false;
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                string tHD = "TSHD" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tRC = "TSRC" + tPosCode;
                string tCD = "TSCD" + tPosCode;
                string tDP = "TSDP" + tPosCode;
                string tSql = "";
                tSql = "UPDATE " + tHD + " WITH(ROWLOCK)";
                tSql += "\n SET FCShdTotal=0,FCShdNonVat=0,FCShdB4DisChg=0,FTShdDisChgTxt=''";
                tSql += "\n ,FCShdDis=0,FCShdChg=0,FCShdAftDisChg=0,FCShdVat=0";
                tSql += "\n ,FCShdVatable=0,FCShdGrand=0,FCShdRnd=0,FCShdReceive=0";
                tSql += "\n ,FCShdChn=0,FTShdGndText='',FCShdLeft=0,FCShdMnyCsh=0";
                tSql += "\n ,FCShdMnyChq=0,FCShdMnyCrd=0,FCShdMnyCpn=0,FCShdPaid=0";
                tSql += "\n ,FCShdDisPmt=0,FTPmhDocNoBill=''";
                tSql += "\n ,FTShdCpnCodeRef='',FCShdCpnRcv=0";
                tSql += "\n ,FCShdMnyCtf=0,FCShdVatExcise=0";
                tSql += "\n ,FTAloCode=0";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                cCNSP.SP_SQLbExecute(tSql);

                //Clear Promotion Coupon TSDPxxx
                tSql = "UPDATE " + tDP + " WITH(ROWLOCK)";
                tSql += "\n SET FTDtpPmhCpnDocNo=''";
                tSql += "\n ,FTDtpPmhBillDocNo=''";
                tSql += "\n ,FTDtpStaGetPmt=''";
                tSql += "\n ,FCDtpPmhCpnGetQty=0";
                tSql += "\n ,FCDtpPmhCpnValue=0";
                tSql += "\n ,FCDtpPmtQtyGet=0";
                tSql += "\n ,FCDtpDisGP=0";
                tSql += "\n ,FDDtpPmhCpnEffect=NULL";
                tSql += "\n ,FDDtpPmhCpnExpried=NULL";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND ((FNSpmType IN (92,93)) OR (ISNULL(FTDtpPmhCpnDocNo,'')<>''))";
                cCNSP.SP_SQLbExecute(tSql);

                //Clear Promotion Coupon TSDTxxx
                tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                tSql += "\n SET FTSdtPmhCpnDocNo=''";
                tSql += "\n ,FTPmhDocNoBill=''";
                tSql += "\n ,FCSdtPmhCpnGetQty=0";
                tSql += "\n ,FCSdtPmhCpnValue=0";
                tSql += "\n ,FCSdtPmtQtyGet=FCSdtPmtQtyGet - CASE WHEN FCSdtPmhCpnGetQty IS NULL THEN 0 ELSE FCSdtPmhCpnGetQty END";
                tSql += "\n ,FCSdtDisGP=0";
                tSql += "\n ,FCSdtDisAvg=0";
                tSql += "\n ,FCSdtFootAvg=0";
                tSql += "\n ,FCShdDiscGP1=0";
                tSql += "\n ,FCShdDiscGP2=0";
                tSql += "\n ,FCSdtShrDisShp=0";
                if (pbBackBegin) { tSql += "\n ,FTSdtPdtParent=''"; }
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                cCNSP.SP_SQLbExecute(tSql);

                //Clear Promotion Coupon TSDTxxx
                tSql = "DELETE FROM " + tDT + " WITH(ROWLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND ((ISNULL(FTCpnCode,'')<>'') OR (FTSdtStaPdt='5'))";
                cCNSP.SP_SQLbExecute(tSql);

                ////Clear Tender TSRCxxx
                //tSql = "DELETE FROM " + tRC + " WITH(ROWLOCK)";
                //tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                //cCNSP.SP_SQLbExecute(tSql);

                //Clear Promotion TSCDxxx
                tSql = "DELETE FROM " + tCD + " WITH(ROWLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND (FNSpmType IN (" + cCNCS.tCS_PMTGrpType2 + "," + cCNCS.tCS_PMTGrpType3 + "))";
                cCNSP.SP_SQLbExecute(tSql);

                //Clear Promotion TSCDxxx
                tSql = "DELETE FROM " + tCD + " WITH(ROWLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND ISNULL(FNSpmType,0)=0 AND FTDtpStaGetPmt IN ('6','7') AND FCDtpPmtQtyGet=0"; //6=Manual Discount, 7=Staff Discount
                cCNSP.SP_SQLbExecute(tSql);

                C_PRCbCALDiscMember(pbBackBegin);
                bResult = true;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbClearSalePmt] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbClearSalePmt] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-05-11 Void Product
        public bool C_PRCbVoidPdt(int pnPdtSeq, string ptVoidCode)
        {
            try
            {
                if (cCNSP.C_PRCDeCryptStr(tDllKey, tDllPass, 256) != "AdaNewPmt") return false;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbVoidPdt] ============ START ============");
                bool bResult = false;
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbVoidPdt] DocNo : " + tShdDocNo + ", Seq : " + pnPdtSeq.ToString());
                string tHD = "TSHD" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tDP = "TSDP" + tPosCode;
                string tCD = "TSCD" + tPosCode;
                string tVT = "TSVT" + tPosCode;
                string tSql = "";
                tSql = "SELECT *";
                tSql += "\n FROM " + tDT + " WITH(NOLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                tSql += "\n AND FNSdtSeqNo=" + pnPdtSeq;
                using (DataTable oDbTblDT = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblDT != null)
                    {
                        if (oDbTblDT.Rows.Count > 0)
                        {
                            int nVoidPdtSeq = int.Parse(cCNSP.SP_SQLtFunction("MAX", "FNSdtSeqNo", tDT, "WHERE FTShdDocNo='" + tShdDocNo + "'", "0")) + 1;
                            oDbTblDT.Rows[0]["FNSdtSeqNo"] = nVoidPdtSeq;
                            oDbTblDT.Rows[0]["FTPdtName"] = "Void - " + oDbTblDT.Rows[0]["FTPdtName"].ToString();
                            //oDbTblDT.Rows[0]["FTPdtName"] = "Void - " + cCNSP.SP_STRtSingleQuote(oDbTblDT.Rows[0]["FTPdtName"].ToString()); //BulkCopy ����?����? Single Quote �� Double Quote
                            oDbTblDT.Rows[0]["FCSdtQty"] = double.Parse(oDbTblDT.Rows[0]["FCSdtQty"].ToString()) * (-1);
                            oDbTblDT.Rows[0]["FCSdtNet"] = double.Parse(oDbTblDT.Rows[0]["FCSdtNet"].ToString()) * (-1);
                            oDbTblDT.Rows[0]["FTSdtStaPdt"] = "4";
                            oDbTblDT.Rows[0]["FTVodCode"] = ptVoidCode;
                            if (cCNSP.SP_SqlbBulkCopy(oDbTblDT, tDT))
                            {
                                string tSrnCode = oDbTblDT.Rows[0]["FTSrnCode"].ToString();
                                string tPdtCode = oDbTblDT.Rows[0]["FTPdtCode"].ToString();
                                tSql = "UPDATE TCNTPdtSerial WITH(ROWLOCK)";
                                tSql += "\n SET FTSrnStaBook='1'";
                                tSql += "\n WHERE FTPdtCode='" + tPdtCode + "'";
                                tSql += "\n AND FTSrnCode='" + tSrnCode + "'";
                                tSql += "\n ;";

                                tSql += "UPDATE " + tDT + " WITH(ROWLOCK)";
                                tSql += "\n SET FTSdtStaPdt='4'";
                                tSql += "\n ,FTVodCode='" + ptVoidCode + "'";
                                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                tSql += "\n AND FNSdtSeqNo=" + pnPdtSeq;
                                tSql += "\n ;";

                                tSql += "UPDATE " + tDP + " WITH(ROWLOCK)";
                                tSql += "\n SET FTSdtStaPdt='4'";
                                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                tSql += "\n AND FNSdtSeqNo=" + pnPdtSeq;
                                tSql += "\n ;";

                                tSql += "UPDATE " + tCD + " WITH(ROWLOCK)";
                                tSql += "\n SET FTSdtStaPdt='4'";
                                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                tSql += "\n AND FNSdtSeqNo=" + pnPdtSeq;
                                tSql += "\n ;";

                                //Void History
                                string tVoidDocNum = C_PRCtGenVoidNo();
                                string tVoidType = "1"; //1=��?����� ?��?�?���, 2=��?����� ?��?���
                                string tSqlTo = "FTPosCode,FTVidSeq,FTVidType";
                                string tSqlFrm = "'" + tPosCode + "' AS FTPosCode,'" + tVoidDocNum + "' AS FTVidSeq,'" + tVoidType + "' AS FTVidType";
                                for (int iCol = 0; iCol < oDbTblDT.Columns.Count; iCol++)
                                {
                                    tSqlTo += "," + oDbTblDT.Columns[iCol].ColumnName;
                                    tSqlFrm += "," + oDbTblDT.Columns[iCol].ColumnName;
                                }
                                tSql += "INSERT INTO " + tVT + "(" + tSqlTo + ")";
                                tSql += "\n SELECT " + tSqlFrm;
                                tSql += "\n FROM " + tDT + " WITH(NOLOCK)";
                                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                tSql += "\n AND FNSdtSeqNo=" + pnPdtSeq;
                                tSql += "\n ;";
                                bResult = cCNSP.SP_SQLbExecute(tSql);
                                C_PRCbReCalPmt(); //Void �?������� ��?�??��??��������������
                            }
                        }
                    }
                }
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbVoidPdt] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbVoidPdt] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-05-08 �??����������������
        public bool C_PRCbReCalPmt() //Step 6
        {
            try
            {
                if (cCNSP.C_PRCDeCryptStr(tDllKey, tDllPass, 256) != "AdaNewPmt") return false;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbReCalPmt] ============ START ============");
                bool bResult = false;
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbReCalPmt] DocNo : " + tShdDocNo);
                cCNVB.tVB_ShdDocNo = tShdDocNo;
                string tDT = "TSDT" + tPosCode;
                string tDP = "TSDP" + tPosCode;
                string tSql = "";
                tSql = "SELECT TOP 1 FTSdtBarCode, FNSdtSeqNo FROM " + tDT + " WITH(NOLOCK) WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                tSql += "\n AND ISNULL(FTPmhCode,'')<>''";
                tSql += "\n ORDER BY FNSdtSeqNo DESC";
                using (DataTable oDbTblDT = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblDT.Rows.Count > 0)
                    {
                        //Clear DT before ReCal Promotion
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbReCalPmt] Clear " + tDT);
                        tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                        tSql += "\n SET FCSdtNet=(CASE WHEN FTSdtStaPdt='1' THEN FCSdtB4DisChg ELSE FCSdtNet END)";
                        tSql += "\n ,FCSdtVat=0";
                        tSql += "\n ,FCSdtVatable=0";
                        tSql += "\n ,FCSdtDis=0";
                        tSql += "\n ,FCSdtChg=0";
                        tSql += "\n ,FTSdtDisChgTxt=''";
                        tSql += "\n ,FCSdtPmtQtyGet=0";
                        tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                        tSql += "\n ;";
                        //Clear DP before ReCal Promotion
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbReCalPmt] Clear " + tDP);
                        tSql += "UPDATE " + tDP + " WITH(ROWLOCK) ";
                        tSql += "\n SET FTPmhDocNo='', FNSpmType=0, FCDtpDis=0";
                        tSql += "\n , FTDtpStaGetPmt='0', FCDtpPmtQtyGet=0, FNDtpSdtSeqNoRef=0, FNDtpQtyPmtX=0, FNDtpQtyPmtGetX=0"; //Clear TSDPxxx
                        tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                        tSql += "\n ;";
                        cCNSP.SP_SQLbExecute(tSql);
                        //bResult = C_GETbPmtProduct(int.Parse(oDbTblDT.Rows[0]["FNSdtSeqNo"].ToString())); //�??�������  
                        bResult = C_GETbPmtProduct(); //�??������� 
                    }
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbReCalPmt] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbReCalPmt] Error : " + ex.Message);
                return false;
            }
        }

        #endregion

        #region Local Function
        private bool C_PRCbPmtChkActive()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPmtChkActive] ============ START ============");
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);

                cCNSP.SP_TBLbChkTempTable("TSPT" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSPS" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSPX" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSPY" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSPZ" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSHD" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSDT" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSRC" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSDP" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TXML" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSVT" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSCD" + tPosCode, false, true); //*Tao 62-01-03 ���?���� �?�������??

                //Clear TSPM
                cCNSP.SP_TBLbChkTempTable("TSPM" + tPosCode, true, true);
                //Insert TSPM
                string tSql = "";

                //*Thana 65-06-10
                //*KT 67-10-25 Comsheet2024-221 select * �? error ���?�? CD ��� HD �?��� Field ����?�?
                //Column names in each table must be unique. Column name 'FTBchCode' in table '#TMP_TCNTPdtPmtHD' is specified more than once.
                //tSql = "SELECT * INTO #TMP_TCNTPdtPmtHD FROM TCNTPdtPmtHD (NOLOCK) ";
                tSql = "SELECT TCNTPdtPmtHD.* INTO #TMP_TCNTPdtPmtHD FROM TCNTPdtPmtHD (NOLOCK) ";
                tSql += "\n INNER JOIN TCNTPdtPmtCD(NOLOCK) ";
                tSql += "\n ON TCNTPdtPmtHD.FTBchCode = TCNTPdtPmtCD.FTBchCode AND TCNTPdtPmtHD.FTPmhDocNo = TCNTPdtPmtCD.FTPmhDocNo ";
                //*������ where �?���?  *Thana 65-06-10
                tSql += "\n WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN TCNTPdtPmtHD.FDPmhDStart AND TCNTPdtPmtHD.FDPmhDStop)";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhClosed<>'1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhRetOrWhs<>'2') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhStaPrcDoc='1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FNPmhStaAct='1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhBchTo='" & tBchCode & "')" //*Tao 61-12-04 �?���
                tSql += "\n AND ('" + tBchCode + "' BETWEEN TCNTPdtPmtHD.FTPmhBchFrm AND TCNTPdtPmtHD.FTPmhBchTo)"; //*Tao 61-12-04 �??���?�
                tSql += "\n AND (TCNTPdtPmtHD.FNSpmType IN (" + cCNCS.tCS_PMTGrpType1 + "," + cCNCS.tCS_PMTGrpType3 + "))"; //add tCS_PMTGrpType3 ��������� DP �����
                if (cCNVB.bVB_BlockLeafLet) //*Tao 63-01-03 �?��� LeafLet ��?������ �?��� Get
                {
                    //tSql += "\n AND ISNULL(TCNTPdtPmtDT.FTPdtCode,'') NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                    tSql += "\n AND ISNULL(TCNTPdtPmtCD.FTPdtCode,'') NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                    //tSql += "\n AND ISNULL(TCNTPdtPmtCO.FTPdtCode,'') NOT IN (CASE WHEN ISNULL(TCNTPdtPmtHD.FNSpmType,0) IN (5,6) THEN '' ELSE (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ") END)";
                }
                //*������ where �?���?  *Thana 65-06-10

                //Krisana 2026-05-07 Cr. ��?�?��� Load �?��?���� Promotion �??
                //Code �?��� Amorn 2026-05-05 Edit Query PMT
                tSql += "\n AND NOT EXISTS (SELECT 1 FROM TCNTPdtPmtCD CD2";
                tSql += "\n WHERE CD2.FTBchCode = TCNTPdtPmtHD.FTBchCode AND CD2.FTPmhDocNo = TCNTPdtPmtHD.FTPmhDocNo";
                tSql += "\n AND (CD2.FCPmcPriFree < 0 OR CD2.FCPmcPriNew < 0 OR CD2.FCPmcPriDisAmt < 0";
                tSql += "\n OR CD2.FCPmcPriDisPer < 0 ))";
                //Code �?��� Amorn 2026-05-05 Edit Query PMT

                tSql += "\n SELECT * INTO #TMP_TCNTPdtPmtDT FROM TCNTPdtPmtDT (NOLOCK)";
                tSql += "\n WHERE FTPmhDocNo IN (SELECT FTPmhDocNo FROM #TMP_TCNTPdtPmtHD)";
                tSql += "\n SELECT * INTO #TMP_TCNTPdtPmtCD FROM TCNTPdtPmtCD (NOLOCK)";
                tSql += "\n  WHERE FTPmhDocNo IN (SELECT FTPmhDocNo FROM #TMP_TCNTPdtPmtHD)";
                tSql += "\n SELECT * INTO #TMP_TCNTPdtPmtCO FROM TCNTPdtPmtCO (NOLOCK)";
                tSql += "\n  WHERE FTPmhDocNo IN (SELECT FTPmhDocNo FROM #TMP_TCNTPdtPmtHD)";

                //Update DT -- SET FCPmdOrgPri
                tSql += "\n UPDATE #TMP_TCNTPdtPmtDT";
                tSql += "\n Set FCPmdOrgPri = BAR.FCPdtRetPri1";
                tSql += "\n FROM #TMP_TCNTPdtPmtDT DT INNER JOIN tcnmpdtbar BAR ON DT.FTPdtCode = BAR.FTPdtCode AND DT.FTPmdBarCodeBuy = BAR.FTPdtBarCode";

                //Update CD -- SET FCPmcOrgPri
                tSql += "\n UPDATE #TMP_TCNTPdtPmtCD";
                tSql += "\n Set FCPmcOrgPri = BAR.FCPdtRetPri1";
                tSql += "\n FROM #TMP_TCNTPdtPmtCD CD INNER JOIN tcnmpdtbar BAR ON CD.FTPdtCode = BAR.FTPdtCode AND CD.FTPmcBarCodeGet = BAR.FTPdtBarCode";

                //Update CO -- SET FCPmoOrgPri
                tSql += "\n UPDATE #TMP_TCNTPdtPmtCO";
                tSql += "\n Set FCPmoOrgPri = BAR.FCPdtRetPri1";
                tSql += "\n FROM #TMP_TCNTPdtPmtCO CO INNER JOIN tcnmpdtbar BAR ON CO.FTPdtCode = BAR.FTPdtCode AND CO.FTPmoBarCodeCo = BAR.FTPdtBarCode";

                tSql += "\n INSERT INTO TSPM" + tPosCode;
                //tSql = "INSERT INTO TSPM" + tPosCode;
                //*Thana 65-06-10

                tSql += "\n SELECT DISTINCT ";
                tSql += "\n TCNTPdtPmtHD.FTPmhDocNo, TCNTPdtPmtHD.FTPmhName, TCNTPdtPmtHD.FDPmhDStart, TCNTPdtPmtHD.FDPmhDStop";
                tSql += "\n ,TCNTPdtPmtHD.FDPmhTStart, TCNTPdtPmtHD.FDPmhTStop, TCNTPdtPmtHD.FNSpmType, TCNTPdtPmtDT.FTPmdGetType AS FTSpmGetType";
                //tSql += "\n ,TCNTPdtPmtCD.FCPmcPriDisAmt AS FCSpmDisAmt";  
                //tSql += "\n ,TCNTPdtPmtCD.FCPmcPriDisPer AS FCSpmDisPer";

                //Krisana 2025-06-13 Cr. Fix Price Complex Promotion ��?���??����������� Field: FCSpmDisAmt ��� std >> FCPmcPriNew = �?�����, FCPmcPriDisAmt = ��??�?
                tSql += "\n ,Case TCNTPdtPmtCD.FTPmcGetType";
                tSql += "\n         WHEN '1' THEN TCNTPdtPmtCD.FCPmcPriFree";
                tSql += "\n         WHEN '2' THEN TCNTPdtPmtCD.FCPmcPriNew";
                tSql += "\n         WHEN '3' THEN TCNTPdtPmtCD.FCPmcPriDisAmt";
                tSql += "\n         ELSE 0 END AS FCSpmDisAmt";

                tSql += "\n ,TCNTPdtPmtCD.FCPmcPriDisPer AS FCSpmDisPer";

                //BarCdoe X - Type 28 Non-Sale: item-attached discount (same pattern as Type 24)
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FTPdtCode ELSE TCNTPdtPmtDT.FTPdtCode END AS FTPdtCodeX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FTPmcBarCodeGet ELSE TCNTPdtPmtDT.FTPmdBarCodeBuy END AS FTPdtBarX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FTPdtName ELSE TCNTPdtPmtDT.FTPdtName END AS FTPdtNameX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN 1 ELSE TCNTPdtPmtDT.FCPmdBuyQty END AS FCQtyPmtX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN 0 ELSE TCNTPdtPmtDT.FCPmdBuyAmt END AS FCAmtPmtX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FCPmcOrgPri ELSE TCNTPdtPmtDT.FCPmdOrgPri END AS FCSpmPriOrgX, 0 AS FCSpmPriAdjX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FCPmcOrgPri ELSE TCNTPdtPmtDT.FCPmdOrgPri END AS FCSpmPriNewX";
                tSql += "\n ,0 AS FCSpmQtyKeyX, 0 AS FCSpmAmtKeyX,0 AS FCSpmQtyUsedX,0 AS FCSpmAmtUsedX";
                tSql += "\n ,0 AS FCSpmQtyDivX, 0 AS FCSpmQtyModX, 0 AS FCSpmQtyLeftX";
                tSql += "\n ,0 AS FCSpmAmtDivOrgPriX, 0 AS FCSpmAmtDivNewPriX, 0 AS FCSpmAmtModOrgPriX";
                tSql += "\n ,0 AS FCSpmAmtGetPmtX,0 AS FCSpmAmtDiscX";
                //BarCdoe Y
                tSql += "\n ,TCNTPdtPmtCO.FTPdtCode AS FTPdtCodeY, TCNTPdtPmtCO.FTPmoBarCodeCo AS FTPdtBarY,TCNTPdtPmtCO.FTPdtName AS FTPdtNameY";
                tSql += "\n ,TCNTPdtPmtCO.FCPmoBuyQty AS FCQtyPmtY, TCNTPdtPmtDT.FCPmdBuyAmt AS FCAmtPmtY";
                tSql += "\n ,TCNTPdtPmtCO.FCPmoOrgPri AS FCSpmPriOrgY, 0 AS FCSpmPriAdjY, TCNTPdtPmtCO.FCPmoOrgPri AS FCSpmPriNewY";
                tSql += "\n ,0 AS FCSpmQtyKeyY, 0 AS FCSpmAmtKeyY, 0 AS FCSpmQtyUsedY, 0 AS FCSpmAmtUsedY";
                tSql += "\n ,0 AS FCSpmQtyDivY, 0 AS FCSpmQtyModY, 0 AS FCSpmQtyLeftY";
                tSql += "\n ,0 AS FCSpmAmtDivOrgPriY, 0 AS FCSpmAmtDivNewPriY,0 AS FCSpmAmtModOrgPriY";
                tSql += "\n ,0 AS FCSpmAmtGetPmtY, 0 AS FCSpmAmtDiscY";
                //BarCdoe Z
                tSql += "\n ,TCNTPdtPmtCD.FTPdtCode AS FTPdtCodeZ,TCNTPdtPmtCD.FTPmcBarCodeGet AS FTPdtBarZ, TCNTPdtPmtCD.FTPdtName AS FTPdtNameZ";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN 1 ELSE TCNTPdtPmtCD.FCPmcGetQty END AS FCQtyPmtZ,TCNTPdtPmtDT.FCPmdBuyAmt AS FCAmtPmtZ";
                tSql += "\n ,TCNTPdtPmtCD.FCPmcOrgPri AS FCSpmPriOrgZ";
                ////*Tao 63-05-15 �?���
                //tSql += "\n ,TCNTPdtPmtCD.FCPmcOrgPri - TCNTPdtPmtCD.FCPmcPriNew AS FCSpmPriAdjZ";
                //tSql += "\n ,TCNTPdtPmtCD.FCPmcPriNew AS FCSpmPriNewZ";

                //*Thana 65-07-15        �������? OriPri �? Table Promotion �����??�?? Master product
                ////*Tao 63-05-15 �?�?�?�?�??��? �� �?����� �?�����???��
                //tSql += "\n ,(CASE WHEN TCNTPdtPmtCD.FCPmcPriNew > TCNTPdtPmtCD.FCPmcOrgPri THEN 0 ELSE TCNTPdtPmtCD.FCPmcOrgPri - TCNTPdtPmtCD.FCPmcPriNew END) AS FCSpmPriAdjZ";
                //tSql += "\n ,(CASE WHEN TCNTPdtPmtCD.FCPmcPriNew > TCNTPdtPmtCD.FCPmcOrgPri THEN TCNTPdtPmtCD.FCPmcOrgPri ELSE TCNTPdtPmtCD.FCPmcPriNew END) AS FCSpmPriNewZ";

                tSql += "\n ,Case TCNTPdtPmtCD.FTPmcGetType";   //1: Free , 2: new price , 3: disc. baht , 4: disc. percent
                tSql += "\n WHEN '1' THEN TCNTPdtPmtCD.FCPmcOrgPri";
                //tSql += "\n WHEN '2' THEN TCNTPdtPmtCD.FCPmcOrgPri-TCNTPdtPmtCD.FCPmcPriNew";
                tSql += "\n WHEN '2' THEN CASE WHEN TCNTPdtPmtCD.FCPmcOrgPri > TCNTPdtPmtCD.FCPmcPriNew THEN TCNTPdtPmtCD.FCPmcOrgPri-TCNTPdtPmtCD.FCPmcPriNew ELSE 0 END";
                //tSql += "\n WHEN '3' THEN TCNTPdtPmtCD.FCPmcPriDisAmt";
                tSql += "\n WHEN '3' THEN CASE WHEN TCNTPdtPmtCD.FCPmcOrgPri > TCNTPdtPmtCD.FCPmcPriDisAmt THEN TCNTPdtPmtCD.FCPmcPriDisAmt ELSE 0 END";
                tSql += "\n WHEN '4' THEN CAST(TCNTPdtPmtCD.FCPmcOrgPri * TCNTPdtPmtCD.FCPmcPriDisPer * 0.01 AS DECIMAL(15,2))";
                tSql += "\n ELSE 0 END AS FCSpmPriAdjZ";
                tSql += "\n ,Case TCNTPdtPmtCD.FTPmcGetType";
                tSql += "\n WHEN '1' THEN 0";
                //tSql += "\n WHEN '2' THEN TCNTPdtPmtCD.FCPmcPriNew";
                tSql += "\n WHEN '2' THEN CASE WHEN TCNTPdtPmtCD.FCPmcOrgPri > TCNTPdtPmtCD.FCPmcPriNew THEN TCNTPdtPmtCD.FCPmcPriNew ELSE TCNTPdtPmtCD.FCPmcOrgPri END";
                //tSql += "\n WHEN '3' THEN TCNTPdtPmtCD.FCPmcOrgPri - TCNTPdtPmtCD.FCPmcPriDisAmt";
                tSql += "\n WHEN '3' THEN CASE WHEN TCNTPdtPmtCD.FCPmcOrgPri > TCNTPdtPmtCD.FCPmcPriNew THEN TCNTPdtPmtCD.FCPmcOrgPri - TCNTPdtPmtCD.FCPmcPriDisAmt ELSE TCNTPdtPmtCD.FCPmcOrgPri END";
                tSql += "\n WHEN '4' THEN TCNTPdtPmtCD.FCPmcOrgPri - CAST(TCNTPdtPmtCD.FCPmcOrgPri * TCNTPdtPmtCD.FCPmcPriDisPer * 0.01 AS DECIMAL(15,2))";
                tSql += "\n ELSE TCNTPdtPmtCD.FCPmcPriNew END AS FCSpmPriNewZ";
                //*Thana 65-07-15        �������? OriPri �? Table Promotion �����??�?? Master product
                //=====================================================

                tSql += "\n ,0 AS FCSpmQtyKeyZ, 0 AS FCSpmAmtKeyZ, 0 AS FCSpmQtyUsedZ, 0 AS FCSpmAmtUsedZ";
                tSql += "\n ,0 AS FCSpmQtyDivZ, 0 AS FCSpmQtyModZ, 0 AS FCSpmQtyLeftZ";
                tSql += "\n ,0 AS FCSpmAmtDivOrgPriZ, 0 AS FCSpmAmtDivNewPriZ, 0 AS FCSpmAmtModOrgPriZ";
                tSql += "\n ,0 AS FCSpmAmtGetPmtZ, 0 AS FCSpmAmtDiscZ";
                //Plus sale
                tSql += "\n , TCNTPdtPmtCD.FCPmcCpnAmt AS FCSpmWQtyDiv";
                tSql += "\n , CONVERT(VARCHAR,TCNTPdtPmtCD.FDPmcCpnAffect,112) AS FCSpmWQtyOrgPri"; //�?���������� �??
                tSql += "\n , CONVERT(VARCHAR,TCNTPdtPmtCD.FDPmcCpnExpired,112) AS FCSpmWQtyNewPri"; //�?�������?��?�??
                tSql += "\n , 0 AS FCSpmWAmtDivOrgPri";
                tSql += "\n , 0 AS FCSpmWAmtDivNewPri, 0 AS FCSpmWAmtGetPmt";
                tSql += "\n , 0 AS FCSpmWAmtDisc, NULL AS FDSpmTimeIns,'' AS FTSpmStaGet,0 AS FNSpmSeqScan";

                //*Thana 65-06-10    ��?���� Temp Table ��?�?�� update �?� orgPri �? master product >> #TMP_TCNTPdtPmtHD,DT,CD,CO
                //tSql += "\n FROM TCNTPdtPmtHD WITH(NOLOCK) INNER JOIN";
                //tSql += "\n TCNTPdtPmtDT WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtDT.FTPmhDocNo INNER JOIN";
                //tSql += "\n TCNTPdtPmtCD WITH(NOLOCK) ON TCNTPdtPmtDT.FTPmdBarCodeBuy=TCNTPdtPmtCD.FTPmdBarCodeBuy AND";
                //tSql += "\n TCNTPdtPmtDT.FTPmhDocNo=TCNTPdtPmtCD.FTPmhDocNo LEFT OUTER JOIN";
                //tSql += "\n TCNTPdtPmtCO WITH(NOLOCK) ON TCNTPdtPmtDT.FTPmhDocNo=TCNTPdtPmtCO.FTPmhDocNo AND";
                //tSql += "\n TCNTPdtPmtDT.FTPmdBarCodeBuy=TCNTPdtPmtCO.FTPmdBarCodeBuy";

                tSql += "\n FROM #TMP_TCNTPdtPmtHD TCNTPdtPmtHD WITH(NOLOCK) INNER JOIN";
                tSql += "\n #TMP_TCNTPdtPmtCD TCNTPdtPmtCD WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtCD.FTPmhDocNo";
                tSql += "\n LEFT JOIN #TMP_TCNTPdtPmtDT TCNTPdtPmtDT WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtDT.FTPmhDocNo";
                tSql += "\n AND TCNTPdtPmtDT.FTPmdBarCodeBuy=TCNTPdtPmtCD.FTPmcBarCodeGet";
                tSql += "\n LEFT OUTER JOIN #TMP_TCNTPdtPmtCO TCNTPdtPmtCO WITH(NOLOCK) ON TCNTPdtPmtDT.FTPmhDocNo=TCNTPdtPmtCO.FTPmhDocNo AND";
                tSql += "\n TCNTPdtPmtDT.FTPmdBarCodeBuy=TCNTPdtPmtCO.FTPmdBarCodeBuy";
                tSql += "\n WHERE (TCNTPdtPmtHD.FNSpmType=28 OR TCNTPdtPmtDT.FTPmhDocNo IS NOT NULL)";
                //*Thana 65-06-10    ��?���� Temp Table ��?�?�� update �?� orgPri �? master product >> #TMP_TCNTPdtPmtHD,DT,CD,CO

                ////*����?�?���?����� HD //*Thana 65-06-10
                //tSql += "\n WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN TCNTPdtPmtHD.FDPmhDStart AND TCNTPdtPmtHD.FDPmhDStop)";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhClosed<>'1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhRetOrWhs<>'2') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhStaPrcDoc='1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FNPmhStaAct='1') ";
                ////tSql += "\n AND (TCNTPdtPmtHD.FTPmhBchTo='" & tBchCode & "')" //*Tao 61-12-04 �?���
                //tSql += "\n AND ('" + tBchCode + "' BETWEEN TCNTPdtPmtHD.FTPmhBchFrm AND TCNTPdtPmtHD.FTPmhBchTo)"; //*Tao 61-12-04 �??���?�
                //tSql += "\n AND (TCNTPdtPmtHD.FNSpmType IN (" + cCNCS.tCS_PMTGrpType1 + "," + cCNCS.tCS_PMTGrpType3 + "))"; //add tCS_PMTGrpType3 ��������� DP �����
                //if (cCNVB.bVB_BlockLeafLet) //*Tao 63-01-03 �?��� LeafLet ��?������ �?��� Get
                //{
                //    //tSql += "\n AND ISNULL(TCNTPdtPmtDT.FTPdtCode,'') NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                //    tSql += "\n AND ISNULL(TCNTPdtPmtCD.FTPdtCode,'') NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                //    //tSql += "\n AND ISNULL(TCNTPdtPmtCO.FTPdtCode,'') NOT IN (CASE WHEN ISNULL(TCNTPdtPmtHD.FNSpmType,0) IN (5,6) THEN '' ELSE (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ") END)";
                //}
                ////*����?�?���?����� HD //*Thana 65-06-10

                // Non-Sale Clearance (Type 28): item-level Active + date window only for this type
                tSql += "\n AND (TCNTPdtPmtHD.FNSpmType <> 28 OR (TCNTPdtPmtHD.FNSpmType = 28 AND ISNULL(TCNTPdtPmtCD.FCPmcCpnAmt,0)=1";
                tSql += "\n AND '" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN ISNULL(TCNTPdtPmtCD.FDPmcCpnAffect, TCNTPdtPmtHD.FDPmhDStart) AND ISNULL(TCNTPdtPmtCD.FDPmcCpnExpired, TCNTPdtPmtHD.FDPmhDStop)))";
                tSql += "\n ORDER BY TCNTPdtPmtHD.FDPmhDStart";

                //*Thana 65-06-10
                tSql += "\n DROP TABLE #TMP_TCNTPdtPmtHD";
                tSql += "\n DROP TABLE #TMP_TCNTPdtPmtDT";
                tSql += "\n DROP TABLE #TMP_TCNTPdtPmtCD";
                tSql += "\n DROP TABLE #TMP_TCNTPdtPmtCO";
                //*Thana 65-06-10

                cCNSP.SP_SQLoExecute(tSql);
                cCNSP.SP_ADDxLog("LogPmtPrc", VersionDll + ": Initial Promotion := " + tSql);
                //Clear TSPG
                cCNSP.SP_TBLbChkTempTable("TSPG" + tPosCode, true, true);
                //Insert TSPG
                tSql = "INSERT INTO TSPG" + tPosCode;
                tSql += "\n SELECT DISTINCT ";
                tSql += "\n TCNTPdtPmtHD.FTPmhDocNo, TCNTPdtPmtHD.FTPmhName, TCNTPdtPmtHD.FDPmhDStart, TCNTPdtPmtHD.FDPmhDStop";
                tSql += "\n , TCNTPdtPmtHD.FDPmhTStart, TCNTPdtPmtHD.FDPmhTStop, TCNTPdtPmtHD.FNSpmType, TCNTPdtPmtHD.FTPmhGetType";
                tSql += "\n , TCNTPdtPmtHD.FCPmhDisAmt, TCNTPdtPmtHD.FCPmhDisPer, TCNTPdtPmtHD.FCPmhPriAdj, TCNTPdtPmtHD.FTPmhStaBillType";
                tSql += "\n , TCNTPdtPmtHD.FTPmhBillFrm, TCNTPdtPmtHD.FTPmhBillTo, TCNTPdtPmtHD.FTPmhRightChr, TCNTPdtPmtHD.FCPmhSumBillAmt";
                tSql += "\n , TCNTPdtPmtHD.FCPmhCpnQty, TCNTPdtPmtHD.FCPmhCpnAmt, TCNTPdtPmtHD.FDPmhCpnAffect, TCNTPdtPmtHD.FDPmhCpnExpired";
                tSql += "\n ,TCNTPdtPmtDT.FTPmdBarCodeBuy AS FTPdtBarX,TCNTPdtPmtCD.FTPdtCode  AS FTPdtBarZ,'' AS FTSpmNoDis, 0 AS FCSpmNetZ, 0 AS FCSpmNetBill, 0 AS FCSpmAmtDiscZ,0 AS FNSpmSeqScan";
                tSql += "\n ,TCNTPdtPmtHD.FTPmhRmk AS FTPmhRmk";
                tSql += "\n FROM TCNTPdtPmtHD WITH(NOLOCK) LEFT OUTER JOIN";
                tSql += "\n TCNTPdtPmtCD WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtCD.FTPmhDocNo LEFT OUTER JOIN";
                tSql += "\n TCNTPdtPmtDT WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtDT.FTPmhDocNo";
                tSql += "\n WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN TCNTPdtPmtHD.FDPmhDStart AND TCNTPdtPmtHD.FDPmhDStop)";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhClosed<>'1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhRetOrWhs<>'2') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhStaPrcDoc='1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FNPmhStaAct='1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhBchTo='" & tVB_CNBchCode & "')"; //*Tao 61-12-04 �?���
                tSql += "\n AND ('" + tBchCode + "' BETWEEN TCNTPdtPmtHD.FTPmhBchFrm AND TCNTPdtPmtHD.FTPmhBchTo)"; //*Tao 61-12-04 �??���?�
                tSql += "\n AND (TCNTPdtPmtHD.FNSpmType IN (" + cCNCS.tCS_PMTGrpType2 + "))";
                tSql += "\n ORDER BY TCNTPdtPmtHD.FDPmhDStart";
                cCNSP.SP_SQLbExecute(tSql);

                //Clear TSPP
                cCNSP.SP_TBLbChkTempTable("TSPP" + tPosCode, true, true);
                //Insert TSPP
                tSql = "INSERT INTO TSPP" + tPosCode;
                tSql += "\n SELECT DISTINCT ";
                tSql += "\n TCNTPdtPmtHD.FTPmhDocNo AS FTPmhDocNo, TCNTPdtPmtHD.FTPmhName AS FTPmhName ";
                tSql += "\n , TCNTPdtPmtHD.FDPmhDStart AS FDPmhDStart, TCNTPdtPmtHD.FDPmhDStop AS FDPmhDStop ";
                tSql += "\n , TCNTPdtPmtHD.FDPmhTStart AS FDPmhTStart, TCNTPdtPmtHD.FDPmhTStop AS FDPmhTStop ";
                tSql += "\n , TCNTPdtPmtHD.FNSpmType AS FNSppType, TCNTPdtPmtCD.FTPmcGetType AS FTPmhGetType ";
                tSql += "\n , TCNTPdtPmtCD.FCPmcPriDisAmt AS FCPmhDisAmt, TCNTPdtPmtCD.FCPmcPriDisPer AS FCPmhDisPer ";
                tSql += "\n , TCNTPdtPmtCD.FCPmcPriNew AS FCPmhPriAdj, TCNTPdtPmtHD.FTPmhStaBillType AS FTPmhStaBillType";
                tSql += "\n , TCNTPdtPmtHD.FTPmhBillFrm AS FTPmhBillFrm, TCNTPdtPmtHD.FTPmhBillTo AS FTPmhBillTo ";
                tSql += "\n , TCNTPdtPmtHD.FTPmhRightChr AS FTPmhRightChr, TCNTPdtPmtCD.FCPmcGetQty AS FCPmhSumBillAmt";
                tSql += "\n , 1 AS FCPmhCpnQty, TCNTPdtPmtCD.FCPmcCpnAmt AS FCPmhCpnAmt";
                tSql += "\n , TCNTPdtPmtCD.FDPmcCpnAffect AS FDPmhCpnAffect, TCNTPdtPmtCD.FDPmcCpnExpired AS FDPmhCpnExpired";
                tSql += "\n , TCNTPdtPmtCD.FTPmdBarCodeBuy AS FTPdtBarX, TCNTPdtPmtCD.FTPmcBarCodeGet AS FTPdtBarZ";
                tSql += "\n , '' AS FTSpmNoDis, 0 AS FCSpmNetZ";
                tSql += "\n , 0 AS FCSpmNetBill, 0 AS FCSpmAmtDiscZ";
                tSql += "\n , 0 AS FNSpmSeqScan";
                tSql += "\n FROM TCNTPdtPmtHD WITH(NOLOCK) LEFT JOIN";
                tSql += "\n TCNTPdtPmtCD WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo = TCNTPdtPmtCD.FTPmhDocNo";
                tSql += "\n WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN TCNTPdtPmtHD.FDPmhDStart AND TCNTPdtPmtHD.FDPmhDStop)";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhClosed<>'1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhRetOrWhs<>'2') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhStaPrcDoc='1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FNPmhStaAct='1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhBchTo='" & tVB_CNBchCode & "')"; //*Tao 61-12-04 �?���
                tSql += "\n AND ('" + tBchCode + "' BETWEEN TCNTPdtPmtHD.FTPmhBchFrm AND TCNTPdtPmtHD.FTPmhBchTo)"; //*Tao 61-12-04 �??���?�
                tSql += "\n AND (TCNTPdtPmtHD.FNSpmType IN (" + cCNCS.tCS_PMTGrpType3 + "))";
                tSql += "\n ORDER BY TCNTPdtPmtHD.FDPmhDStart";
                cCNSP.SP_SQLbExecute(tSql);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPmtChkActive] ============  END  ============");
                return true;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbPmtChkActive] Error : " + ex.Message);
                return false;
            }
        }

        //Krisana 2025-11-14 Update ��� LF Comsheet/2025-150
        private bool C_PRCbPmtChkActive_LF()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPmtChkActive] ============ START ============");
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);

                cCNSP.SP_TBLbChkTempTable("TSPT" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSPS" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSPX" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSPY" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSPZ" + tPosCode, true, true);
                cCNSP.SP_TBLbChkTempTable("TSHD" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSDT" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSRC" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSDP" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TXML" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSVT" + tPosCode, false, true);
                cCNSP.SP_TBLbChkTempTable("TSCD" + tPosCode, false, true); //*Tao 62-01-03 ���?���� �?�������??

                //Clear TSPM
                cCNSP.SP_TBLbChkTempTable("TSPM" + tPosCode, true, true);
                //Insert TSPM
                string tSql = "";

                //*Thana 65-06-10
                //*KT 67-10-25 Comsheet2024-221 select * �? error ���?�? CD ��� HD �?��� Field ����?�?
                //Column names in each table must be unique. Column name 'FTBchCode' in table '#TMP_TCNTPdtPmtHD' is specified more than once.
                //tSql = "SELECT * INTO #TMP_TCNTPdtPmtHD FROM TCNTPdtPmtHD (NOLOCK) ";

                //************************ 19/06/2025 Tuning Query >> START ******************************
                tSql = "SELECT DISTINCT HD.* INTO #TMP_TCNTPdtPmtHD FROM TCNTPdtPmtHD HD WITH (NOLOCK) ";
                tSql += "\n INNER JOIN TCNTPdtPmtCD CD WITH (NOLOCK) ";
                tSql += "\n ON HD.FTBchCode = CD.FTBchCode AND HD.FTPmhDocNo = CD.FTPmhDocNo ";
                //*������ where �?���?  *Thana 65-06-10
                tSql += "\n WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN HD.FDPmhDStart AND HD.FDPmhDStop)";
                tSql += "\n AND (HD.FTPmhClosed<>'1') ";
                tSql += "\n AND (HD.FTPmhRetOrWhs<>'2') ";
                tSql += "\n AND (HD.FTPmhStaPrcDoc='1') ";
                tSql += "\n AND (HD.FNPmhStaAct='1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhBchTo='" & tBchCode & "')" //*Tao 61-12-04 �?���
                tSql += "\n AND ('" + tBchCode + "' BETWEEN HD.FTPmhBchFrm AND HD.FTPmhBchTo)"; //*Tao 61-12-04 �??���?�
                tSql += "\n AND (HD.FNSpmType IN (" + cCNCS.tCS_PMTGrpType1 + "," + cCNCS.tCS_PMTGrpType3 + "))"; //add tCS_PMTGrpType3 ��������� DP �����
                if (cCNVB.bVB_BlockLeafLet) //*Tao 63-01-03 �?��� LeafLet ��?������ �?��� Get
                {
                    //tSql += "\n AND ISNULL(TCNTPdtPmtDT.FTPdtCode,'') NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                    // tSql += "\n AND ISNULL(TCNTPdtPmtCD.FTPdtCode,'') NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                    // Tuning Query NOT IN >> AND NOT EXISTS
                    tSql += "\n AND NOT EXISTS (SELECT 1 FROM TCNMPdt P WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + " AND P.FTPdtCode = CD.FTPdtCode);";

                    //tSql += "\n AND ISNULL(TCNTPdtPmtCO.FTPdtCode,'') NOT IN (CASE WHEN ISNULL(TCNTPdtPmtHD.FNSpmType,0) IN (5,6) THEN '' ELSE (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ") END)";
                }
                //*������ where �?���?  *Thana 65-06-10

                //Krisana 2026-05-07 Cr. ��?�?��� Load �?��?���� Promotion �??
                //Code �?��� Amorn 2026-05-05 Edit Query PMT
                tSql += "\n AND NOT EXISTS (SELECT 1 FROM TCNTPdtPmtCD CD2";
                tSql += "\n WHERE CD2.FTBchCode = TCNTPdtPmtHD.FTBchCode AND CD2.FTPmhDocNo = TCNTPdtPmtHD.FTPmhDocNo";
                tSql += "\n AND (CD2.FCPmcPriFree < 0 OR CD2.FCPmcPriNew < 0 OR CD2.FCPmcPriDisAmt < 0";
                tSql += "\n OR CD2.FCPmcPriDisPer < 0 ))";
                //Code �?��� Amorn 2026-05-05 Edit Query PMT

                tSql += "\n SELECT * INTO #TMP_TCNTPdtPmtDT FROM TCNTPdtPmtDT (NOLOCK)";
                tSql += "\n WHERE FTPmhDocNo IN (SELECT FTPmhDocNo FROM #TMP_TCNTPdtPmtHD);";

                tSql += "\n SELECT * INTO #TMP_TCNTPdtPmtCD FROM TCNTPdtPmtCD (NOLOCK)";
                tSql += "\n  WHERE FTPmhDocNo IN (SELECT FTPmhDocNo FROM #TMP_TCNTPdtPmtHD);";

                tSql += "\n SELECT * INTO #TMP_TCNTPdtPmtCO FROM TCNTPdtPmtCO (NOLOCK)";
                tSql += "\n  WHERE FTPmhDocNo IN (SELECT FTPmhDocNo FROM #TMP_TCNTPdtPmtHD);";

                // Tuning Query INTO #TMP_PDT_PRICE
                tSql += "\n SELECT FTPdtCode, FTPdtBarCode, FCPdtRetPri1";
                tSql += "\n INTO #TMP_PDT_PRICE";
                tSql += "\n FROM TCNMPDTBAR WITH(NOLOCK);";

                //Update DT -- SET FCPmdOrgPri
                tSql += "\n UPDATE DT";
                tSql += "\n Set FCPmdOrgPri = PR.FCPdtRetPri1";
                tSql += "\n FROM #TMP_TCNTPdtPmtDT DT JOIN #TMP_PDT_PRICE PR ON DT.FTPdtCode = PR.FTPdtCode AND DT.FTPmdBarCodeBuy = PR.FTPdtBarCode;";

                //Update CD -- SET FCPmcOrgPri
                tSql += "\n UPDATE CD";
                tSql += "\n Set FCPmcOrgPri = PR.FCPdtRetPri1";
                tSql += "\n FROM #TMP_TCNTPdtPmtCD CD JOIN #TMP_PDT_PRICE PR ON CD.FTPdtCode = PR.FTPdtCode AND CD.FTPmcBarCodeGet = PR.FTPdtBarCode;";

                //Update CO -- SET FCPmoOrgPri
                tSql += "\n UPDATE CO";
                tSql += "\n Set FCPmoOrgPri = PR.FCPdtRetPri1";
                tSql += "\n FROM #TMP_TCNTPdtPmtCO CO JOIN #TMP_PDT_PRICE PR ON CO.FTPdtCode = PR.FTPdtCode AND CO.FTPmoBarCodeCo = PR.FTPdtBarCode;";

                tSql += "\n INSERT INTO TSPM" + tPosCode;
                //tSql = "INSERT INTO TSPM" + tPosCode;
                //*Thana 65-06-10

                // **************************** Update 30/06/2025 START >> ****************************
                tSql += "\n SELECT DISTINCT ";
                tSql += "\n TCNTPdtPmtHD.FTPmhDocNo, TCNTPdtPmtHD.FTPmhName, TCNTPdtPmtHD.FDPmhDStart, TCNTPdtPmtHD.FDPmhDStop";
                tSql += "\n ,TCNTPdtPmtHD.FDPmhTStart, TCNTPdtPmtHD.FDPmhTStop, TCNTPdtPmtHD.FNSpmType, TCNTPdtPmtDT.FTPmdGetType AS FTSpmGetType";
                //tSql += "\n ,TCNTPdtPmtCD.FCPmcPriDisAmt AS FCSpmDisAmt, TCNTPdtPmtCD.FCPmcPriDisPer AS FCSpmDisPer";

                //Krisana 2025-06-13 Cr. Fix Price Complex Promotion ��?���??����������� Field: FCSpmDisAmt ��� std >> FCPmcPriNew = �?�����, FCPmcPriDisAmt = ��??�?
                tSql += "\n ,Case TCNTPdtPmtCD.FTPmcGetType";
                tSql += "\n         WHEN '1' THEN TCNTPdtPmtCD.FCPmcPriFree";
                tSql += "\n         WHEN '2' THEN TCNTPdtPmtCD.FCPmcPriNew";
                tSql += "\n         WHEN '3' THEN TCNTPdtPmtCD.FCPmcPriDisAmt";
                tSql += "\n         ELSE 0 END AS FCSpmDisAmt";

                tSql += "\n ,TCNTPdtPmtCD.FCPmcPriDisPer AS FCSpmDisPer";
                // **************************** Update 30/06/2025 << END ****************************
                //BarCdoe X - Type 28 Non-Sale: item-attached discount (same pattern as Type 24)
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FTPdtCode ELSE TCNTPdtPmtDT.FTPdtCode END AS FTPdtCodeX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FTPmcBarCodeGet ELSE TCNTPdtPmtDT.FTPmdBarCodeBuy END AS FTPdtBarX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FTPdtName ELSE TCNTPdtPmtDT.FTPdtName END AS FTPdtNameX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN 1 ELSE TCNTPdtPmtDT.FCPmdBuyQty END AS FCQtyPmtX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN 0 ELSE TCNTPdtPmtDT.FCPmdBuyAmt END AS FCAmtPmtX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FCPmcOrgPri ELSE TCNTPdtPmtDT.FCPmdOrgPri END AS FCSpmPriOrgX, 0 AS FCSpmPriAdjX";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN TCNTPdtPmtCD.FCPmcOrgPri ELSE TCNTPdtPmtDT.FCPmdOrgPri END AS FCSpmPriNewX";
                tSql += "\n ,0 AS FCSpmQtyKeyX, 0 AS FCSpmAmtKeyX,0 AS FCSpmQtyUsedX,0 AS FCSpmAmtUsedX";
                tSql += "\n ,0 AS FCSpmQtyDivX, 0 AS FCSpmQtyModX, 0 AS FCSpmQtyLeftX";
                tSql += "\n ,0 AS FCSpmAmtDivOrgPriX, 0 AS FCSpmAmtDivNewPriX, 0 AS FCSpmAmtModOrgPriX";
                tSql += "\n ,0 AS FCSpmAmtGetPmtX,0 AS FCSpmAmtDiscX";
                //BarCdoe Y
                tSql += "\n ,TCNTPdtPmtCO.FTPdtCode AS FTPdtCodeY, TCNTPdtPmtCO.FTPmoBarCodeCo AS FTPdtBarY,TCNTPdtPmtCO.FTPdtName AS FTPdtNameY";
                tSql += "\n ,TCNTPdtPmtCO.FCPmoBuyQty AS FCQtyPmtY, TCNTPdtPmtDT.FCPmdBuyAmt AS FCAmtPmtY";
                tSql += "\n ,TCNTPdtPmtCO.FCPmoOrgPri AS FCSpmPriOrgY, 0 AS FCSpmPriAdjY, TCNTPdtPmtCO.FCPmoOrgPri AS FCSpmPriNewY";
                tSql += "\n ,0 AS FCSpmQtyKeyY, 0 AS FCSpmAmtKeyY, 0 AS FCSpmQtyUsedY, 0 AS FCSpmAmtUsedY";
                tSql += "\n ,0 AS FCSpmQtyDivY, 0 AS FCSpmQtyModY, 0 AS FCSpmQtyLeftY";
                tSql += "\n ,0 AS FCSpmAmtDivOrgPriY, 0 AS FCSpmAmtDivNewPriY,0 AS FCSpmAmtModOrgPriY";
                tSql += "\n ,0 AS FCSpmAmtGetPmtY, 0 AS FCSpmAmtDiscY";
                //BarCdoe Z
                tSql += "\n ,TCNTPdtPmtCD.FTPdtCode AS FTPdtCodeZ,TCNTPdtPmtCD.FTPmcBarCodeGet AS FTPdtBarZ, TCNTPdtPmtCD.FTPdtName AS FTPdtNameZ";
                tSql += "\n ,CASE WHEN TCNTPdtPmtHD.FNSpmType=28 THEN 1 ELSE TCNTPdtPmtCD.FCPmcGetQty END AS FCQtyPmtZ,TCNTPdtPmtDT.FCPmdBuyAmt AS FCAmtPmtZ";
                tSql += "\n ,TCNTPdtPmtCD.FCPmcOrgPri AS FCSpmPriOrgZ";
                ////*Tao 63-05-15 �?���
                //tSql += "\n ,TCNTPdtPmtCD.FCPmcOrgPri - TCNTPdtPmtCD.FCPmcPriNew AS FCSpmPriAdjZ";
                //tSql += "\n ,TCNTPdtPmtCD.FCPmcPriNew AS FCSpmPriNewZ";

                //*Thana 65-07-15        �������? OriPri �? Table Promotion �����??�?? Master product
                ////*Tao 63-05-15 �?�?�?�?�??��? �� �?����� �?�����???��
                //tSql += "\n ,(CASE WHEN TCNTPdtPmtCD.FCPmcPriNew > TCNTPdtPmtCD.FCPmcOrgPri THEN 0 ELSE TCNTPdtPmtCD.FCPmcOrgPri - TCNTPdtPmtCD.FCPmcPriNew END) AS FCSpmPriAdjZ";
                //tSql += "\n ,(CASE WHEN TCNTPdtPmtCD.FCPmcPriNew > TCNTPdtPmtCD.FCPmcOrgPri THEN TCNTPdtPmtCD.FCPmcOrgPri ELSE TCNTPdtPmtCD.FCPmcPriNew END) AS FCSpmPriNewZ";

                tSql += "\n ,Case TCNTPdtPmtCD.FTPmcGetType";   //1: Free , 2: new price , 3: disc. baht , 4: disc. percent
                tSql += "\n WHEN '1' THEN TCNTPdtPmtCD.FCPmcOrgPri";
                //tSql += "\n WHEN '2' THEN TCNTPdtPmtCD.FCPmcOrgPri-TCNTPdtPmtCD.FCPmcPriNew";
                tSql += "\n WHEN '2' THEN CASE WHEN TCNTPdtPmtCD.FCPmcOrgPri > TCNTPdtPmtCD.FCPmcPriNew THEN TCNTPdtPmtCD.FCPmcOrgPri-TCNTPdtPmtCD.FCPmcPriNew ELSE 0 END";
                //tSql += "\n WHEN '3' THEN TCNTPdtPmtCD.FCPmcPriDisAmt";
                tSql += "\n WHEN '3' THEN CASE WHEN TCNTPdtPmtCD.FCPmcOrgPri > TCNTPdtPmtCD.FCPmcPriDisAmt THEN TCNTPdtPmtCD.FCPmcPriDisAmt ELSE 0 END";
                tSql += "\n WHEN '4' THEN CAST(TCNTPdtPmtCD.FCPmcOrgPri * TCNTPdtPmtCD.FCPmcPriDisPer * 0.01 AS DECIMAL(15,2))";
                tSql += "\n ELSE 0 END AS FCSpmPriAdjZ";
                tSql += "\n ,Case TCNTPdtPmtCD.FTPmcGetType";
                tSql += "\n WHEN '1' THEN 0";
                //tSql += "\n WHEN '2' THEN TCNTPdtPmtCD.FCPmcPriNew";
                tSql += "\n WHEN '2' THEN CASE WHEN TCNTPdtPmtCD.FCPmcOrgPri > TCNTPdtPmtCD.FCPmcPriNew THEN TCNTPdtPmtCD.FCPmcPriNew ELSE TCNTPdtPmtCD.FCPmcOrgPri END";
                //tSql += "\n WHEN '3' THEN TCNTPdtPmtCD.FCPmcOrgPri - TCNTPdtPmtCD.FCPmcPriDisAmt";
                tSql += "\n WHEN '3' THEN CASE WHEN TCNTPdtPmtCD.FCPmcOrgPri > TCNTPdtPmtCD.FCPmcPriNew THEN TCNTPdtPmtCD.FCPmcOrgPri - TCNTPdtPmtCD.FCPmcPriDisAmt ELSE TCNTPdtPmtCD.FCPmcOrgPri END";
                tSql += "\n WHEN '4' THEN TCNTPdtPmtCD.FCPmcOrgPri - CAST(TCNTPdtPmtCD.FCPmcOrgPri * TCNTPdtPmtCD.FCPmcPriDisPer * 0.01 AS DECIMAL(15,2))";
                tSql += "\n ELSE TCNTPdtPmtCD.FCPmcPriNew END AS FCSpmPriNewZ";
                //*Thana 65-07-15        �������? OriPri �? Table Promotion �����??�?? Master product
                //=====================================================

                tSql += "\n ,0 AS FCSpmQtyKeyZ, 0 AS FCSpmAmtKeyZ, 0 AS FCSpmQtyUsedZ, 0 AS FCSpmAmtUsedZ";
                tSql += "\n ,0 AS FCSpmQtyDivZ, 0 AS FCSpmQtyModZ, 0 AS FCSpmQtyLeftZ";
                tSql += "\n ,0 AS FCSpmAmtDivOrgPriZ, 0 AS FCSpmAmtDivNewPriZ, 0 AS FCSpmAmtModOrgPriZ";
                tSql += "\n ,0 AS FCSpmAmtGetPmtZ, 0 AS FCSpmAmtDiscZ";
                //Plus sale
                tSql += "\n , TCNTPdtPmtCD.FCPmcCpnAmt AS FCSpmWQtyDiv";
                tSql += "\n , CONVERT(VARCHAR,TCNTPdtPmtCD.FDPmcCpnAffect,112) AS FCSpmWQtyOrgPri"; //�?���������� �??
                tSql += "\n , CONVERT(VARCHAR,TCNTPdtPmtCD.FDPmcCpnExpired,112) AS FCSpmWQtyNewPri"; //�?�������?��?�??
                tSql += "\n , 0 AS FCSpmWAmtDivOrgPri";
                tSql += "\n , 0 AS FCSpmWAmtDivNewPri, 0 AS FCSpmWAmtGetPmt";
                tSql += "\n , 0 AS FCSpmWAmtDisc, NULL AS FDSpmTimeIns,'' AS FTSpmStaGet,0 AS FNSpmSeqScan";
                tSql += "\n , TCNTPdtPmtHD.FTUsrCode AS FTPrintSlip";
                //*Thana 65-06-10    ��?���� Temp Table ��?�?�� update �?� orgPri �? master product >> #TMP_TCNTPdtPmtHD,DT,CD,CO
                //tSql += "\n FROM TCNTPdtPmtHD WITH(NOLOCK) INNER JOIN";
                //tSql += "\n TCNTPdtPmtDT WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtDT.FTPmhDocNo INNER JOIN";
                //tSql += "\n TCNTPdtPmtCD WITH(NOLOCK) ON TCNTPdtPmtDT.FTPmdBarCodeBuy=TCNTPdtPmtCD.FTPmdBarCodeBuy AND";
                //tSql += "\n TCNTPdtPmtDT.FTPmhDocNo=TCNTPdtPmtCD.FTPmhDocNo LEFT OUTER JOIN";
                //tSql += "\n TCNTPdtPmtCO WITH(NOLOCK) ON TCNTPdtPmtDT.FTPmhDocNo=TCNTPdtPmtCO.FTPmhDocNo AND";
                //tSql += "\n TCNTPdtPmtDT.FTPmdBarCodeBuy=TCNTPdtPmtCO.FTPmdBarCodeBuy";

                tSql += "\n FROM #TMP_TCNTPdtPmtHD TCNTPdtPmtHD WITH(NOLOCK) INNER JOIN";
                tSql += "\n #TMP_TCNTPdtPmtCD TCNTPdtPmtCD WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtCD.FTPmhDocNo";
                tSql += "\n LEFT JOIN #TMP_TCNTPdtPmtDT TCNTPdtPmtDT WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtDT.FTPmhDocNo";
                tSql += "\n AND TCNTPdtPmtDT.FTPmdBarCodeBuy=TCNTPdtPmtCD.FTPmcBarCodeGet";
                tSql += "\n LEFT OUTER JOIN #TMP_TCNTPdtPmtCO TCNTPdtPmtCO WITH(NOLOCK) ON TCNTPdtPmtDT.FTPmhDocNo=TCNTPdtPmtCO.FTPmhDocNo AND";
                tSql += "\n TCNTPdtPmtDT.FTPmdBarCodeBuy=TCNTPdtPmtCO.FTPmdBarCodeBuy";
                tSql += "\n WHERE (TCNTPdtPmtHD.FNSpmType=28 OR TCNTPdtPmtDT.FTPmhDocNo IS NOT NULL)";
                //*Thana 65-06-10    ��?���� Temp Table ��?�?�� update �?� orgPri �? master product >> #TMP_TCNTPdtPmtHD,DT,CD,CO

                ////*����?�?���?����� HD //*Thana 65-06-10
                //tSql += "\n WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN TCNTPdtPmtHD.FDPmhDStart AND TCNTPdtPmtHD.FDPmhDStop)";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhClosed<>'1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhRetOrWhs<>'2') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhStaPrcDoc='1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FNPmhStaAct='1') ";
                ////tSql += "\n AND (TCNTPdtPmtHD.FTPmhBchTo='" & tBchCode & "')" //*Tao 61-12-04 �?���
                //tSql += "\n AND ('" + tBchCode + "' BETWEEN TCNTPdtPmtHD.FTPmhBchFrm AND TCNTPdtPmtHD.FTPmhBchTo)"; //*Tao 61-12-04 �??���?�
                //tSql += "\n AND (TCNTPdtPmtHD.FNSpmType IN (" + cCNCS.tCS_PMTGrpType1 + "," + cCNCS.tCS_PMTGrpType3 + "))"; //add tCS_PMTGrpType3 ��������� DP �����
                //if (cCNVB.bVB_BlockLeafLet) //*Tao 63-01-03 �?��� LeafLet ��?������ �?��� Get
                //{
                //    //tSql += "\n AND ISNULL(TCNTPdtPmtDT.FTPdtCode,'') NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                //    tSql += "\n AND ISNULL(TCNTPdtPmtCD.FTPdtCode,'') NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                //    //tSql += "\n AND ISNULL(TCNTPdtPmtCO.FTPdtCode,'') NOT IN (CASE WHEN ISNULL(TCNTPdtPmtHD.FNSpmType,0) IN (5,6) THEN '' ELSE (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ") END)";
                //}
                ////*����?�?���?����� HD //*Thana 65-06-10

                // Non-Sale Clearance (Type 28): item-level Active + date window only for this type
                tSql += "\n AND (TCNTPdtPmtHD.FNSpmType <> 28 OR (TCNTPdtPmtHD.FNSpmType = 28 AND ISNULL(TCNTPdtPmtCD.FCPmcCpnAmt,0)=1";
                tSql += "\n AND '" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN ISNULL(TCNTPdtPmtCD.FDPmcCpnAffect, TCNTPdtPmtHD.FDPmhDStart) AND ISNULL(TCNTPdtPmtCD.FDPmcCpnExpired, TCNTPdtPmtHD.FDPmhDStop)))";
                tSql += "\n ORDER BY TCNTPdtPmtHD.FDPmhDStart;";

                //*Thana 65-06-10
                tSql += "\n DROP TABLE #TMP_TCNTPdtPmtHD;";
                tSql += "\n DROP TABLE #TMP_TCNTPdtPmtDT;";
                tSql += "\n DROP TABLE #TMP_TCNTPdtPmtCD;";
                tSql += "\n DROP TABLE #TMP_TCNTPdtPmtCO;";
                //*Thana 65-06-10
                //************************ 19/06/2025 Tuning Query << END ******************************

                cCNSP.SP_SQLoExecute(tSql);
                cCNSP.SP_ADDxLog("LogPmtPrc", VersionDll + ": Initial Promotion := " + tSql);
                //Clear TSPG
                cCNSP.SP_TBLbChkTempTable("TSPG" + tPosCode, true, true);
                //Insert TSPG
                tSql = "INSERT INTO TSPG" + tPosCode;
                tSql += "\n SELECT DISTINCT ";
                tSql += "\n TCNTPdtPmtHD.FTPmhDocNo, TCNTPdtPmtHD.FTPmhName, TCNTPdtPmtHD.FDPmhDStart, TCNTPdtPmtHD.FDPmhDStop";
                tSql += "\n , TCNTPdtPmtHD.FDPmhTStart, TCNTPdtPmtHD.FDPmhTStop, TCNTPdtPmtHD.FNSpmType, TCNTPdtPmtHD.FTPmhGetType";
                tSql += "\n , TCNTPdtPmtHD.FCPmhDisAmt, TCNTPdtPmtHD.FCPmhDisPer, TCNTPdtPmtHD.FCPmhPriAdj, TCNTPdtPmtHD.FTPmhStaBillType";
                tSql += "\n , TCNTPdtPmtHD.FTPmhBillFrm, TCNTPdtPmtHD.FTPmhBillTo, TCNTPdtPmtHD.FTPmhRightChr, TCNTPdtPmtHD.FCPmhSumBillAmt";
                tSql += "\n , TCNTPdtPmtHD.FCPmhCpnQty, TCNTPdtPmtHD.FCPmhCpnAmt, TCNTPdtPmtHD.FDPmhCpnAffect, TCNTPdtPmtHD.FDPmhCpnExpired";
                tSql += "\n ,TCNTPdtPmtDT.FTPmdBarCodeBuy AS FTPdtBarX,TCNTPdtPmtCD.FTPdtCode  AS FTPdtBarZ,'' AS FTSpmNoDis, 0 AS FCSpmNetZ, 0 AS FCSpmNetBill, 0 AS FCSpmAmtDiscZ,0 AS FNSpmSeqScan";
                tSql += "\n ,TCNTPdtPmtHD.FTPmhRmk AS FTPmhRmk";
                tSql += "\n FROM TCNTPdtPmtHD WITH(NOLOCK) LEFT OUTER JOIN";
                tSql += "\n TCNTPdtPmtCD WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtCD.FTPmhDocNo LEFT OUTER JOIN";
                tSql += "\n TCNTPdtPmtDT WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo=TCNTPdtPmtDT.FTPmhDocNo";
                tSql += "\n WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN TCNTPdtPmtHD.FDPmhDStart AND TCNTPdtPmtHD.FDPmhDStop)";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhClosed<>'1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhRetOrWhs<>'2') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhStaPrcDoc='1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FNPmhStaAct='1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhBchTo='" & tVB_CNBchCode & "')"; //*Tao 61-12-04 �?���
                tSql += "\n AND ('" + tBchCode + "' BETWEEN TCNTPdtPmtHD.FTPmhBchFrm AND TCNTPdtPmtHD.FTPmhBchTo)"; //*Tao 61-12-04 �??���?�
                tSql += "\n AND (TCNTPdtPmtHD.FNSpmType IN (" + cCNCS.tCS_PMTGrpType2 + "))";
                tSql += "\n ORDER BY TCNTPdtPmtHD.FDPmhDStart";
                cCNSP.SP_SQLbExecute(tSql);

                //Clear TSPP
                cCNSP.SP_TBLbChkTempTable("TSPP" + tPosCode, true, true);
                //Insert TSPP
                tSql = "INSERT INTO TSPP" + tPosCode;
                tSql += "\n SELECT DISTINCT ";
                tSql += "\n TCNTPdtPmtHD.FTPmhDocNo AS FTPmhDocNo, TCNTPdtPmtHD.FTPmhName AS FTPmhName ";
                tSql += "\n , TCNTPdtPmtHD.FDPmhDStart AS FDPmhDStart, TCNTPdtPmtHD.FDPmhDStop AS FDPmhDStop ";
                tSql += "\n , TCNTPdtPmtHD.FDPmhTStart AS FDPmhTStart, TCNTPdtPmtHD.FDPmhTStop AS FDPmhTStop ";
                tSql += "\n , TCNTPdtPmtHD.FNSpmType AS FNSppType, TCNTPdtPmtCD.FTPmcGetType AS FTPmhGetType ";
                tSql += "\n , TCNTPdtPmtCD.FCPmcPriDisAmt AS FCPmhDisAmt, TCNTPdtPmtCD.FCPmcPriDisPer AS FCPmhDisPer ";
                tSql += "\n , TCNTPdtPmtCD.FCPmcPriNew AS FCPmhPriAdj, TCNTPdtPmtHD.FTPmhStaBillType AS FTPmhStaBillType";
                tSql += "\n , TCNTPdtPmtHD.FTPmhBillFrm AS FTPmhBillFrm, TCNTPdtPmtHD.FTPmhBillTo AS FTPmhBillTo ";
                tSql += "\n , TCNTPdtPmtHD.FTPmhRightChr AS FTPmhRightChr, TCNTPdtPmtCD.FCPmcGetQty AS FCPmhSumBillAmt";
                tSql += "\n , 1 AS FCPmhCpnQty, TCNTPdtPmtCD.FCPmcCpnAmt AS FCPmhCpnAmt";
                tSql += "\n , TCNTPdtPmtCD.FDPmcCpnAffect AS FDPmhCpnAffect, TCNTPdtPmtCD.FDPmcCpnExpired AS FDPmhCpnExpired";
                tSql += "\n , TCNTPdtPmtCD.FTPmdBarCodeBuy AS FTPdtBarX, TCNTPdtPmtCD.FTPmcBarCodeGet AS FTPdtBarZ";
                tSql += "\n , '' AS FTSpmNoDis, 0 AS FCSpmNetZ";
                tSql += "\n , 0 AS FCSpmNetBill, 0 AS FCSpmAmtDiscZ";
                tSql += "\n , 0 AS FNSpmSeqScan";
                tSql += "\n FROM TCNTPdtPmtHD WITH(NOLOCK) LEFT JOIN";
                tSql += "\n TCNTPdtPmtCD WITH(NOLOCK) ON TCNTPdtPmtHD.FTPmhDocNo = TCNTPdtPmtCD.FTPmhDocNo";
                tSql += "\n WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN TCNTPdtPmtHD.FDPmhDStart AND TCNTPdtPmtHD.FDPmhDStop)";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhClosed<>'1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhRetOrWhs<>'2') ";
                tSql += "\n AND (TCNTPdtPmtHD.FTPmhStaPrcDoc='1') ";
                tSql += "\n AND (TCNTPdtPmtHD.FNPmhStaAct='1') ";
                //tSql += "\n AND (TCNTPdtPmtHD.FTPmhBchTo='" & tVB_CNBchCode & "')"; //*Tao 61-12-04 �?���
                tSql += "\n AND ('" + tBchCode + "' BETWEEN TCNTPdtPmtHD.FTPmhBchFrm AND TCNTPdtPmtHD.FTPmhBchTo)"; //*Tao 61-12-04 �??���?�
                tSql += "\n AND (TCNTPdtPmtHD.FNSpmType IN (" + cCNCS.tCS_PMTGrpType3 + "))";
                tSql += "\n ORDER BY TCNTPdtPmtHD.FDPmhDStart";
                cCNSP.SP_SQLbExecute(tSql);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbPmtChkActive] ============  END  ============");
                return true;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbPmtChkActive] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 62-11-19 ��?�?�?����?��� ��������� ���� ���
        private DataTable C_GEToPdtFindPmtExist(string ptPdtBarCode)
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFindPmtExist] ============ START ============");
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFindPmtExist] Barcode : " + ptPdtBarCode);
                string tSql = "";
                tSql = "SELECT ISNULL(FTPmhDocNo,'') AS FTPmhDocNo,ISNULL(FTPmhName,'') AS FTPmhName,FDPmhDStart,FDPmhDStop,FDPmhTStart";
                tSql += "\n ,FDPmhTStop,ISNULL(FNSpmType,'') AS FNSpmType,ISNULL(FTSpmGetType,'') AS FTSpmGetType,ISNULL(FCSpmDisAmt,'') AS FCSpmDisAmt,ISNULL(FCSpmDisPer,'') AS FCSpmDisPer";
                tSql += "\n ,ISNULL(FTPdtCodeX,'') AS FTPdtCodeX,ISNULL(FTPdtBarX,'') AS FTPdtBarX,ISNULL(FTPdtNameX,'') AS FTPdtNameX,ISNULL(FCQtyPmtX,0) AS FCQtyPmtX,ISNULL(FCAmtPmtX,0) AS FCAmtPmtX";
                tSql += "\n ,ISNULL(FCSpmPriOrgX,0) AS FCSpmPriOrgX,ISNULL(FCSpmPriAdjX,0) AS FCSpmPriAdjX,ISNULL(FCSpmPriNewX,0) AS FCSpmPriNewX,ISNULL(FCSpmQtyKeyX,0) AS FCSpmQtyKeyX,ISNULL(FCSpmAmtKeyX,0) AS FCSpmAmtKeyX";
                tSql += "\n ,ISNULL(FCSpmQtyUsedX,0) AS FCSpmQtyUsedX,ISNULL(FCSpmAmtUsedX,0) AS FCSpmAmtUsedX,ISNULL(FCSpmQtyDivX,0) AS FCSpmQtyDivX,ISNULL(FCSpmQtyModX,0) AS FCSpmQtyModX,ISNULL(FCSpmQtyLeftX,0) AS FCSpmQtyLeftX";
                tSql += "\n ,ISNULL(FCSpmAmtDivOrgPriX,0) AS FCSpmAmtDivOrgPriX,ISNULL(FCSpmAmtDivNewPriX,0) AS FCSpmAmtDivNewPriX,ISNULL(FCSpmAmtModOrgPriX,0) AS FCSpmAmtModOrgPriX,ISNULL(FCSpmAmtGetPmtX,0) AS FCSpmAmtGetPmtX,ISNULL(FCSpmAmtDiscX,0) AS FCSpmAmtDiscX";
                tSql += "\n ,ISNULL(FTPdtCodeY,'') AS FTPdtCodeY,ISNULL(FTPdtBarY,'') AS FTPdtBarY,ISNULL(FTPdtNameY,'') AS FTPdtNameY,ISNULL(FCQtyPmtY,0) AS FCQtyPmtY,ISNULL(FCAmtPmtY,0) AS FCAmtPmtY";
                tSql += "\n ,ISNULL(FCSpmPriOrgY,0) AS FCSpmPriOrgY,ISNULL(FCSpmPriAdjY,0) AS FCSpmPriAdjY,ISNULL(FCSpmPriNewY,0) AS FCSpmPriNewY,ISNULL(FCSpmQtyKeyY,0) AS FCSpmQtyKeyY,ISNULL(FCSpmAmtKeyY,0) AS FCSpmAmtKeyY";
                tSql += "\n ,ISNULL(FCSpmQtyUsedY,0) AS FCSpmQtyUsedY,ISNULL(FCSpmAmtUsedY,0) AS FCSpmAmtUsedY,ISNULL(FCSpmQtyDivY,0) AS FCSpmQtyDivY,ISNULL(FCSpmQtyModY,0) AS FCSpmQtyModY,ISNULL(FCSpmQtyLeftY,0) AS FCSpmQtyLeftY";
                tSql += "\n ,ISNULL(FCSpmAmtDivOrgPriY,0) AS FCSpmAmtDivOrgPriY,ISNULL(FCSpmAmtDivNewPriY,0) AS FCSpmAmtDivNewPriY,ISNULL(FCSpmAmtModOrgPriY,0) AS FCSpmAmtModOrgPriY,ISNULL(FCSpmAmtGetPmtY,0) AS FCSpmAmtGetPmtY,ISNULL(FCSpmAmtDiscY,0) AS FCSpmAmtDiscY";
                tSql += "\n ,ISNULL(FTPdtCodeZ,'') AS FTPdtCodeZ,ISNULL(FTPdtBarZ,'') AS FTPdtBarZ,ISNULL(FTPdtNameZ,'') AS FTPdtNameZ,ISNULL(FCQtyPmtZ,0) AS FCQtyPmtZ,ISNULL(FCAmtPmtZ,0) AS FCAmtPmtZ";
                tSql += "\n ,ISNULL(FCSpmPriOrgZ,0) AS FCSpmPriOrgZ,ISNULL(FCSpmPriAdjZ,0) AS FCSpmPriAdjZ,ISNULL(FCSpmPriNewZ,0) AS FCSpmPriNewZ,ISNULL(FCSpmQtyKeyZ,0) AS FCSpmQtyKeyZ,ISNULL(FCSpmAmtKeyZ,0) AS FCSpmAmtKeyZ";
                tSql += "\n ,ISNULL(FCSpmQtyUsedZ,0) AS FCSpmQtyUsedZ,ISNULL(FCSpmAmtUsedZ,0) AS FCSpmAmtUsedZ,ISNULL(FCSpmQtyDivZ,0) AS FCSpmQtyDivZ,ISNULL(FCSpmQtyModZ,0) AS FCSpmQtyModZ,ISNULL(FCSpmQtyLeftZ,0) AS FCSpmQtyLeftZ";
                tSql += "\n ,ISNULL(FCSpmAmtDivOrgPriZ,0) AS FCSpmAmtDivOrgPriZ,ISNULL(FCSpmAmtDivNewPriZ,0) AS FCSpmAmtDivNewPriZ,ISNULL(FCSpmAmtModOrgPriZ,0) AS FCSpmAmtModOrgPriZ,ISNULL(FCSpmAmtGetPmtZ,0) AS FCSpmAmtGetPmtZ,ISNULL(FCSpmAmtDiscZ,0) AS FCSpmAmtDiscZ";
                tSql += "\n ,ISNULL(FCSpmWQtyDiv,0) AS FCSpmWQtyDiv,ISNULL(FCSpmWQtyOrgPri,0) AS FCSpmWQtyOrgPri,ISNULL(FCSpmWQtyNewPri,0) AS FCSpmWQtyNewPri,ISNULL(FCSpmWAmtDivOrgPri,0) AS FCSpmWAmtDivOrgPri,ISNULL(FCSpmWAmtDivNewPri,0) AS FCSpmWAmtDivNewPri";
                tSql += "\n ,ISNULL(FCSpmWAmtGetPmt,0) AS FCSpmWAmtGetPmt,ISNULL(FCSpmWAmtDisc,0) AS FCSpmWAmtDisc,FDSpmTimeIns,ISNULL(FTSpmStaGet,'') AS FTSpmStaGet,ISNULL(FNSpmSeqScan,0) AS FNSpmSeqScan";
                tSql += "\n FROM TSPM" + tPosCode + " WITH(NOLOCK)";
                tSql += "\n WHERE (FTPdtBarX='" + ptPdtBarCode + "'";
                tSql += "\n OR FTPdtBarY='" + ptPdtBarCode + "'";
                tSql += "\n OR FTPdtBarZ='" + ptPdtBarCode + "')";
                tSql += "\n AND ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN FDPmhDStart AND FDPmhDStop)";       //Krisana 2025-08-08 ����?�� Field : FDPmhDStart, FDPmhDStop Comsheet 2025/098 
                tSql += "\n AND FNSpmType IN (" + cCNCS.tCS_PMTGrpType1 + ")";
                if (cCNVB.bVB_BlockLeafLet) //*Tao 63-01-03 �?��� LeafLet ��?������ �?��� Get
                {
                    //tSql += "\n AND FTPdtCodeX NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                    tSql += "\n AND FTPdtCodeZ NOT IN (SELECT FTPdtCode FROM TCNMPdt WITH(NOLOCK) WHERE " + cCNCS.tCS_CNLeafLetCond + ")";
                }

                tSql += "\n       AND ( ";
                tSql += "\n       CASE ";
                tSql += "\n           WHEN FTSpmGetType IN (1, 2, 3) AND FCSpmDisAmt > 0 THEN 1 ";
                tSql += "\n           WHEN FTSpmGetType = 4          AND FCSpmDisPer > 0 THEN 1 ";
                tSql += "\n           ELSE 0 ";
                tSql += "\n       END ";
                tSql += "\n       ) = 1 ";

                tSql += "\n ORDER BY FCSpmDisAmt DESC";
                using (DataTable oDbTblChk = cCNSP.SP_SQLoExecute(tSql, "TSPT" + tPosCode)) //*Tao 19-11-19 ��?� Table Name ?���
                {
                    if (oDbTblChk != null)
                    {
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFindPmtExist] Promotion Count : " + oDbTblChk.Rows.Count.ToString());
                        return oDbTblChk;
                    }
                    else
                    {
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFindPmtExist] Promotion Count : Error");
                        return new DataTable();
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_GEToPdtFindPmtExist] Error : " + ex.Message);
                return new DataTable();
            }
        }

        //*Tao 62-11-25 Insert �?��� ���� TSDTxxx (������?�?����?�� !!��?���?�!!)
        private bool C_PRCbSavePdt2DT(int pnPdtSeq, string ptPdtBarCode, int pnPdtQty)
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2DT] ============ START ============");
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2DT] Barcode : " + ptPdtBarCode + ", PdtQty : " + pnPdtQty.ToString());
                string tSql = "";
                tSql = "SELECT TOP 1 "; // TCNMPdt.*,TCNMPdtBar.*";
                tSql += "\n TCNMPdt.FTPdtCode,TCNMPdt.FTPdtNameShort,TCNMPdt.FTPgpChain,TCNMPdt.FTPdtSTKCode,TCNMPdt.FTPmhCode";
                tSql += "\n ,TCNMPdt.FTPmhType,TCNMPdt.FCPdtSTKFac,TCNMPdt.FTPdtVatType,TCNMPdt.FTPdtPoint,TCNMPdt.FTPdtSaleType";
                tSql += "\n ,TCNMPdt.FTPdtPmtType,TCNMPdt.FCPdtCostAvg,TCNMPdt.FTPdtArticle,TCNMPdt.FTDcsCode,TCNMPdt.FTPszCode";
                tSql += "\n ,TCNMPdt.FTClrCode,TCNMPdt.FTPdtNoDis,TCNMPdt.FTPunCode ,TCNMPdt.FCPdtUnitFact,TCNMPdtBar.FTPdtBarCode,TCNMPdtBar.FCPdtRetPri1";
                tSql += "\n FROM TCNMPdt WITH(NOLOCK),TCNMPdtBar WITH(NOLOCK)";
                tSql += "\n WHERE (TCNMPdt.FTPdtCode=TCNMPdtBar.FTPdtCode) AND ISNULL(TCNMPdt.FTPdtOthPurSplN2,'')=''";
                //tSql += "\n AND (TCNMPdt.FTPdtCode='" + ptPdtBarCode + "'";
                //tSql += "\n OR FTPdtBarCode='" + ptPdtBarCode + "')";
                tSql += "\n AND TCNMPdtBar.FTPdtBarCode = '" + ptPdtBarCode + "'";
                tSql += "\n AND FTPdtStaActive ='1'"; //��?����
                tSql += "\n AND FTPdtStaAlwSale ='1'"; //�����
                tSql += "\n AND '" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN FDPdtSaleStart AND FDPdtSaleStop";
                tSql += "\n AND FTPdtType NOT IN ('70','71','80','81','99')";
                tSql += "\n AND FDPdtPriAffect <= GETDATE()";
                tSql += "\n ORDER BY TCNMPdtBar.FDPdtPriAffect DESC, TCNMPdtBar.FTPdtCode";
                //"FTPdtCode,FTPdtNameShort,FTPgpChain,FTPdtSTKCode,FTSrnCode,FTPmhCode,FTPmhType,FCPdtSTKFac,FCPdtRetPri1,FTPdtVatType,FTPdtPoint,FTPdtSaleType,FTPdtPmtType,FCPdtCostAvg,FTPdtArticle,FTDcsCode,FTPszCode,FTClrCode,FTPdtNoDis,FTPunCode,FCPdtUnitFact,FCSdtSetPrice,FCSdtSalePrice"
                using (DataTable oDbTblPdt = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblPdt.Rows.Count > 0)
                    {
                        //string tUT_PdtBarCode = oDbTblPdt.Rows[0]["FTPdtBarCode"].ToString();
                        string tPdtCode = oDbTblPdt.Rows[0]["FTPdtCode"].ToString();
                        string tPdtName = oDbTblPdt.Rows[0]["FTPdtNameShort"].ToString();
                        string tPdtGrp = oDbTblPdt.Rows[0]["FTPgpChain"].ToString();
                        string tStkCode = oDbTblPdt.Rows[0]["FTPdtSTKCode"].ToString();
                        string tSrnCode = ""; //oDbTblPdt.Rows[0]["FTSrnCode"].ToString();
                        string tPmtCode = oDbTblPdt.Rows[0]["FTPmhCode"].ToString();
                        string tPmtType = oDbTblPdt.Rows[0]["FTPmhType"].ToString();
                        int cStkFac = int.Parse(oDbTblPdt.Rows[0]["FCPdtSTKFac"].ToString());
                        double cSalePrice = double.Parse(oDbTblPdt.Rows[0]["FCPdtRetPri1"].ToString());
                        double cSetPrice = double.Parse(oDbTblPdt.Rows[0]["FCPdtRetPri1"].ToString());
                        string tVatType = oDbTblPdt.Rows[0]["FTPdtVatType"].ToString();
                        string tPdtPoint = oDbTblPdt.Rows[0]["FTPdtPoint"].ToString();
                        string tSaleType = oDbTblPdt.Rows[0]["FTPdtSaleType"].ToString();
                        string tAccCode = oDbTblPdt.Rows[0]["FTPdtPmtType"].ToString();
                        double cPdtCost = double.Parse(oDbTblPdt.Rows[0]["FCPdtCostAvg"].ToString());
                        string tPdtArticle = oDbTblPdt.Rows[0]["FTPdtArticle"].ToString();
                        string tDcsCode = oDbTblPdt.Rows[0]["FTDcsCode"].ToString();
                        string tPszCode = oDbTblPdt.Rows[0]["FTPszCode"].ToString();
                        string tClrCode = oDbTblPdt.Rows[0]["FTClrCode"].ToString();
                        string tPszName = cCNSP.SP_SQLtFunction("", "FTPszName", "TCNMPdtSize", "WHERE FTPszCode='" + tPszCode + "'");
                        string tClrName = cCNSP.SP_SQLtFunction("", "FTClrName", "TCNMColor", "WHERE FTClrCode='" + tClrCode + "'");
                        bool bPdtNoDis = (oDbTblPdt.Rows[0]["FTPdtNoDis"].ToString() == "1") ? true : false;
                        string tPdtUnitC = oDbTblPdt.Rows[0]["FTPunCode"].ToString();
                        double cPdtUnitF = double.Parse(oDbTblPdt.Rows[0]["FCPdtUnitFact"].ToString());
                        string tPdtUnitN = cCNSP.SP_SQLtFunction("", "FTPunName", "TCNMPdtUnit", "WHERE FTPunCode='" + tPdtUnitC + "'");

                        double cChgAmt = 0; //double.Parse(oDbTblPdt.Rows[0]["FCSdtSetPrice"].ToString());
                        double cDisAmt = 0; //double.Parse(oDbTblPdt.Rows[0]["FCSdtSalePrice"].ToString());
                        //double cUT_B4DisChg = double.Parse(oDbTblPdt.Rows[0]["FCSdtSetPrice"].ToString());
                        //double tVB_CNStaPmt16 = double.Parse(oDbTblPdt.Rows[0]["FCSdtSalePrice"].ToString());
                        string tPdtStatus = "1"; //??��?��� 1:�?���, 2:�?�?, 3:�?���, 4: ?��? (Void) ,5 �?��
                        if (tRetVATInOrEx == "")
                        {
                            tRetVATInOrEx = cCNSP.SP_SQLtFunction("TOP 1", "FTCmpRetInOrEx", "TCNMComp", "WHERE FTCmpCode='001'", "1");
                            cCNVB.tVB_CNRetVATInOrEx = tRetVATInOrEx;
                        }
                        if (cVatRate == 0)
                        {
                            cVatRate = cCNPM.PM_GETcVatRate();
                            cCNVB.cVB_VatRate = cVatRate;
                        }
                        double cNet = (pnPdtQty * cSalePrice);
                        double cB4DisChg = (pnPdtQty * cSalePrice);
                        double cVat = (tVatType == "1" ? cCNSP.SP_CALcVatValue((tRetVATInOrEx == "1" ? false : true), cNet, cVatRate) : 0);
                        double cVatable = ((tVatType == "1") ? cNet - cVat : 0);  //1:vat, 2:novat (0)
                        double cCostIn = (tVatType == "1" ? cCNSP.SP_CALcVatAmt(true, cPdtCost, cVatRate) : cPdtCost); //'1:vat=+N%, 2:nonvat=CostEx

                        using (DataTable oDbTblCheckPmt = C_GEToPdtFindPmtExist(ptPdtBarCode))
                        {
                            if (oDbTblCheckPmt.Rows.Count > 0)
                            {
                                for (int i = 0; i < oDbTblCheckPmt.Rows.Count; i++)
                                {
                                    tPmtCode = oDbTblCheckPmt.Rows[0]["FTPmhDocNo"].ToString();
                                    tPmtType = oDbTblCheckPmt.Rows[0]["FNSpmType"].ToString();
                                    tPdtName = "*" + tPdtName;
                                    i = oDbTblCheckPmt.Rows.Count; //�����������? ��?���?�?
                                }
                            }
                        }

                        tSql = "DECLARE @tUserIns VARCHAR(50)";
                        tSql += "\n SET @tUserIns = '" + tUserName + "'";
                        tSql += "\n INSERT INTO TSDT" + tPosCode;
                        tSql += "\n (FTBchCode,FTShdDocNo,FNSdtSeqNo,FTPdtCode,FTPdtName,"; //1
                        tSql += "\n FTShdDocType,FDShdDocDate,FTShdVATInOrEx,FTSdtBarCode,FTSdtStkCode,"; //2
                        tSql += "\n FCSdtStkFac,FTSdtVatType,FTSdtSaleType,FTPgpChain,FTSrnCode,"; //3
                        tSql += "\n FTPmhCode,FTPmhType,FTPunCode,FTSdtUnitName,FCSdtFactor,"; //4
                        tSql += "\n FCSdtSalePrice,FCSdtQty,FCSdtSetPrice,FCSdtB4DisChg,FCSdtNet,"; //5
                        tSql += "\n FCSdtVat,FCSdtVatable,FCSdtQtyAll,FCSdtCostIn,FCSdtCostEx,"; //6
                        tSql += "\n FTSdtStaPdt,FNShdSign,FNSdtPdtLevel,FTWahCode,FTSdtLotNo,"; //7
                        tSql += "\n FTSdtDisChgTxt,FCSdtDis,FCSdtChg,FNSdtStaRef,FDSdtExpired,"; //8
                        tSql += "\n FTShdStaVatSend,FTSdtApOrAr,FTPdtArticle,FTDcsCode,FTPszCode,"; //9
                        tSql += "\n FTClrCode,FTPszName,FTClrName,FTPdtNoDis,FCSdtPmtQtyGet,"; //10
                        tSql += "\n FTAccCode,FTCpnCode,"; //11
                        tSql += "\n " + cCNCS.tCS_CNLastFedIns; //12
                        tSql += "\n ) VALUES (";
                        tSql += "\n '" + tBchCode + "','" + tShdDocNo + "'," + pnPdtSeq + ",'" + tPdtCode + "','" + cCNSP.SP_STRtSingleQuote(tPdtName) + "',"; //1
                        tSql += "\n '" + tShdDocType + "','" + cCNSP.SP_DTEtByFormat(dSaleDate) + "','" + cCNVB.tVB_CNRetVATInOrEx + "','" + ptPdtBarCode + "','" + tStkCode + "',"; //2
                        tSql += "\n " + String.Format("{0:F2}", cStkFac) + ",'" + tVatType + "','" + tSaleType + "','" + tPdtGrp + "','" + tSrnCode + "',"; //3
                        tSql += "\n '" + tPmtCode + "'" + ",'" + tPmtType + "','" + tPdtUnitC + "','" + tPdtUnitN + "'," + String.Format("{0:F2}", cPdtUnitF) + ","; //4
                        tSql += "\n " + String.Format("{0:F2}", cSalePrice) + "," + pnPdtQty + "," + String.Format("{0:F2}", cSetPrice) + "," + String.Format("{0:F2}", cB4DisChg) + "," + String.Format("{0:F2}", cNet) + ","; //5
                        tSql += "\n " + String.Format("{0:F2}", cVat) + "," + String.Format("{0:F2}", cVatable) + "," + String.Format("{0:F2}", (pnPdtQty * cPdtUnitF * cStkFac)) + "," + String.Format("{0:F2}", cCostIn) + "," + String.Format("{0:F2}", cPdtCost) + ","; //6
                        tSql += "\n '" + tPdtStatus + "',1,0,'" + cCNVB.tVB_CNWahCode + "','" + tPdtPoint + "',"; //7
                        tSql += "\n ''," + String.Format("{0:F2}", cDisAmt) + "," + String.Format("{0:F2}", cChgAmt) + ",1," + "'" + cCNSP.SP_DTEtByFormat(dSaleDate) + "',"; //8
                        tSql += "\n '" + (cCNVB.bVB_CNBillVatSend ? "2" : "1") + "','" + cCNVB.tVB_CNCstCode + "','" + tPdtArticle + "','" + tDcsCode + "','" + tPszCode + "',"; //9
                        tSql += "\n '" + tClrCode + "','" + tPszName + "','" + tClrName + "','" + ((bPdtNoDis) ? "1" : "2") + "'," + 0 + ","; //10
                        tSql += "\n '" + tAccCode + "','',"; //11
                        tSql += "\n " + cCNCS.tCS_CNLastValIns + ")"; //12
                        return cCNSP.SP_SQLbExecute(tSql);
                    }
                    else
                    {
                        return false;
                    }
                }
                //return true;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbSavePdt2DT] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 62-11-19 Insert �?��� ������������ ���� TSPTxxx
        private bool C_PRCbSavePdt2PT(int pnPdtSeq, string ptPdtBarCode, int pnPdtQty = 1)
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2PT] ============ START ============");
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2PT] Barcode : " + ptPdtBarCode);
                using (DataTable oDbTblPmt = C_GEToPdtFindPmtExist(ptPdtBarCode))
                {
                    if (oDbTblPmt.Rows.Count > 0)
                    {
                        for (int i = 0; i < oDbTblPmt.Rows.Count; i++)
                        {
                            oDbTblPmt.Rows[i]["FNSpmSeqScan"] = pnPdtSeq;
                            oDbTblPmt.Rows[i]["FCSpmQtyKeyX"] = (ptPdtBarCode == oDbTblPmt.Rows[i]["FTPdtBarX"].ToString()) ? pnPdtQty : 0;
                            oDbTblPmt.Rows[i]["FCSpmQtyKeyY"] = (ptPdtBarCode == oDbTblPmt.Rows[i]["FTPdtBarY"].ToString()) ? pnPdtQty : 0;
                            oDbTblPmt.Rows[i]["FCSpmQtyKeyZ"] = (ptPdtBarCode == oDbTblPmt.Rows[i]["FTPdtBarZ"].ToString()) ? pnPdtQty : 0;
                            oDbTblPmt.Rows[i]["FDSpmTimeIns"] = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                        }
                        return cCNSP.SP_SqlbBulkCopy(oDbTblPmt, "TSPT" + tPosCode);
                    }
                    else
                    {
                        return true;
                    }
                }
                //return true;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbSavePdt2PT] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 62-11-20 �?������?��??���? TSDTxxx
        private DataTable C_GEToPdtFromDT(string ptShdDocNo, int pnSeqNo)
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFromDT] ============ START ============");
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFromDT] FTShdDocNo : " + ptShdDocNo + " , ");
                string tSql = "";
                tSql = "SELECT * FROM TSDT" + tPosCode + " WITH(NOLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND FNSdtSeqNo=" + pnSeqNo;
                using (DataTable oDbTblChk = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblChk != null)
                    {
                        if (oDbTblChk.Rows.Count > 0)
                        {
                            cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFromDT] Found : " + oDbTblChk.Rows[0]["FTPdtName"].ToString());
                        }
                        else
                        {
                            cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFromDT] Not Found !");
                        }
                        return oDbTblChk;
                    }
                    else
                    {
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GEToPdtFromDT] Error");
                        return new DataTable();
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_GEToPdtFromDT] Error : " + ex.Message);
                return new DataTable();
            }
        }

        //*Tao 62-11-20 Insert �?��� ������������ ���� TSDPxxx
        private bool C_PRCbSavePdt2DP(int pnPdtSeq, string ptPdtBarCode, int pnPdtQty = 1)
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2DP] ============ START ============");
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2DP] SeqNo : " + pnPdtSeq.ToString() + ", Barcode : " + ptPdtBarCode + ", Qty: " + pnPdtQty.ToString());
                using (DataTable oDbTblDT = C_GEToPdtFromDT(tShdDocNo, pnPdtSeq))
                {
                    if (oDbTblDT.Rows.Count > 0)
                    {
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2DP] Save Pdt to TSDP" + tPosCode + " : Start");
                        string tFTPdtCode = oDbTblDT.Rows[0]["FTPdtCode"].ToString();

                            string tFTPmhDocNo = "";                          
                            string tFTPdtName = oDbTblDT.Rows[0]["FTPdtName"].ToString();
                            string tFTShdDocType = oDbTblDT.Rows[0]["FTShdDocType"].ToString();
                            string tFTDtpPmhBillDocNo = "";
                            string tFTDtpPmhCpnDocNo = "";
                            string tFTDtpStaGetPmt = "0";
                            string tFTSdtStaPdt = oDbTblDT.Rows[0]["FTSdtStaPdt"].ToString();
                            string tFTPdtNoDis = oDbTblDT.Rows[0]["FTPdtNoDis"].ToString();
                            string tFTUserName = oDbTblDT.Rows[0]["FTWhoIns"].ToString();
                            //int nFNSdtQty = int.Parse(oDbTblDT.Rows[0]["FCSdtQty"].ToString());
                            int nFNSpmType = 0;
                            int nFNDtpSdtSeqNoRef = 0;
                            int nFNDtpQtyPmtX = 0;
                            int nFNDtpQtyPmtGetX = 0;
                            int nFNDtpQtyPmtLeftX = 0;
                            int nFNDtpQtyPmtY = 0;
                            int nFNDtpQtyPmtGetY = 0;
                            int nFNDtpQtyPmtLeftY = 0;
                            double cFCDtpQtyAll = 1;
                            double cFCDtpNet = double.Parse(oDbTblDT.Rows[0]["FCSdtSetPrice"].ToString());
                            double cFCDtpDis = 0;
                            double cFCDtpPmhCpnGetQty = 0;
                            double cFCDtpPmhCpnValue = 0;
                            double cFCDtpDisGP = 0;
                            double cFCDtpPmtQtyGet = 0;

                            StringBuilder oStr = new StringBuilder();
                            oStr.AppendLine("DECLARE @tUserIns VARCHAR(50)");
                            oStr.AppendLine("SET @tUserIns = '" + tFTUserName + "'");
                            oStr.AppendLine("DECLARE @nLastSeqNo int");
                            oStr.AppendLine("SET @nLastSeqNo = (SELECT ISNULL(Max(FNDtpSeqNo),0) FROM TSDP" + tPosCode + " WITH(NOLOCK) WHERE FTShdDocNo='" + tShdDocNo + "')");
                            for (int nQty = 1; nQty <= pnPdtQty; nQty++)
                            {
                                oStr.AppendLine("INSERT INTO TSDP" + tPosCode);
                                oStr.AppendLine("(FTBchCode,FTShdDocNo,FNDtpSeqNo,FNSdtSeqNo,FTPmhDocNo");
                                oStr.AppendLine(",FNSpmType,FTDtpBarCode,FTPdtCode,FTPdtName,FTShdDocType");
                                oStr.AppendLine(",FDShdDocDate,FCDtpQtyAll,FCDtpNet,FCDtpDis,FTDtpPmhBillDocNo");
                                oStr.AppendLine(",FTDtpPmhCpnDocNo,FCDtpPmhCpnGetQty,FCDtpPmhCpnValue,FDDtpPmhCpnEffect,FDDtpPmhCpnExpried");
                                oStr.AppendLine(",FCDtpDisGP,FTDtpStaGetPmt,FCDtpPmtQtyGet,FNDtpSdtSeqNoRef,FNDtpQtyPmtX");
                                oStr.AppendLine(",FNDtpQtyPmtGetX,FNDtpQtyPmtLeftX,FNDtpQtyPmtY,FNDtpQtyPmtGetY,FNDtpQtyPmtLeftY");
                                oStr.AppendLine(",FTSdtStaPdt,FTPdtNoDis");
                                oStr.AppendLine("," + cCNCS.tCS_CNLastFedIns);
                                oStr.AppendLine(") VALUES('" + tBchCode + "','" + tShdDocNo + "'," + (nQty + "+@nLastSeqNo") + "," + pnPdtSeq + ",'" + tFTPmhDocNo + "'");
                                oStr.AppendLine("," + nFNSpmType + ",'" + ptPdtBarCode + "','" + tFTPdtCode + "','" + tFTPdtName + "','" + tFTShdDocType + "'");
                                oStr.AppendLine(",'" + cCNSP.SP_DTEtByFormat(dSaleDate) + "'," + String.Format("{0:F2}", cFCDtpQtyAll) + "," + String.Format("{0:F2}", cFCDtpNet) + "," + String.Format("{0:F2}", cFCDtpDis) + ",'" + tFTDtpPmhBillDocNo + "'");
                                oStr.AppendLine(",'" + tFTDtpPmhCpnDocNo + "'," + String.Format("{0:F2}", cFCDtpPmhCpnGetQty) + "," + String.Format("{0:F2}", cFCDtpPmhCpnValue) + ", NULL ,NULL");
                                oStr.AppendLine("," + String.Format("{0:F2}", cFCDtpDisGP) + ",'" + tFTDtpStaGetPmt + "'," + String.Format("{0:F2}", cFCDtpPmtQtyGet) + "," + nFNDtpSdtSeqNoRef + "," + nFNDtpQtyPmtX);
                                oStr.AppendLine("," + nFNDtpQtyPmtGetX + "," + nFNDtpQtyPmtLeftX + "," + nFNDtpQtyPmtY + "," + nFNDtpQtyPmtGetY + "," + nFNDtpQtyPmtLeftY);
                                oStr.AppendLine(",'" + tFTSdtStaPdt + "','" + tFTPdtNoDis + "'");
                                oStr.AppendLine("," + cCNCS.tCS_CNLastValIns + ")");
                            }
                            bool bResult = cCNSP.SP_SQLbExecute(oStr.ToString());
                            if (bResult)
                            {
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2DP] Save Pdt to TSDP" + tPosCode + " : Success");
                            }
                            else
                            {
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2DP] Save Pdt to TSDP" + tPosCode + " : Fail !");
                            }
                            return bResult;
                           
                    }
                    else
                    {
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbSavePdt2DP] Not Found !");
                        return false;
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbSavePdt2DP] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-01-06 Insert �?��� ������������ �?���? TSDPxxx ���� TSCDxxx
        private static void C_PRCbSavePmtDP2CD(int pnCDseqNo, int pnDPseqNo = 0, bool pbNewSeqCD = true)
        {
            try
            {
                //Re Seq FNDtpSeqNo
                int nCDSeqNo = 0;
                if (pbNewSeqCD)
                {
                    //�������� pnCDseqNo �?��� ��� Gen ����
                    if (pnCDseqNo == 0)
                    {
                        nCDSeqNo = int.Parse(cCNSP.SP_SQLtFunction("MAX", "FNDtpSeqNo", "TSCD" + cCNVB.tVB_PosCode, "WHERE (FTShdDocNo='" + cCNVB.tVB_ShdDocNo + "') AND (FTSdtStaPdt='1')", "0")) + 1;
                    }
                    else
                    {
                        nCDSeqNo = pnCDseqNo;
                    }
                }
                else
                {
                    //�� pnDPseqNo
                    nCDSeqNo = pnDPseqNo;
                }
                string tSqlInsCD = "INSERT INTO TSCD" + cCNVB.tVB_PosCode;
                tSqlInsCD += "\n SELECT FTBchCode,FTShdDocNo," + nCDSeqNo + ",FNSdtSeqNo,FTPmhDocNo";
                tSqlInsCD += "\n ,FNSpmType,FTDtpBarCode,FTPdtCode,FTPdtName,FTShdDocType";
                tSqlInsCD += "\n ,FDShdDocDate,FCDtpQtyAll,FCDtpNet,FCDtpDis,FTDtpPmhBillDocNo";
                tSqlInsCD += "\n ,FTDtpPmhCpnDocNo,FCDtpPmhCpnGetQty,FCDtpPmhCpnValue,FDDtpPmhCpnEffect,FDDtpPmhCpnExpried";
                tSqlInsCD += "\n ,FCDtpDisGP,FTDtpStaGetPmt,FCDtpPmtQtyGet,FNDtpSdtSeqNoRef,FNDtpQtyPmtX";
                tSqlInsCD += "\n ,FNDtpQtyPmtGetX,FNDtpQtyPmtLeftX,FNDtpQtyPmtY,FNDtpQtyPmtGetY,FNDtpQtyPmtLeftY";
                tSqlInsCD += "\n ,FTSdtStaPdt,FTPdtNoDis";
                tSqlInsCD += "\n ," + cCNCS.tCS_CNLastFedIns;
                tSqlInsCD += "\n FROM TSDP" + cCNVB.tVB_PosCode + " WITH(NOLOCK)";
                tSqlInsCD += "\n WHERE FNDtpSeqNo=" + pnDPseqNo;
                tSqlInsCD += "\n AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                oW_SqlCDPmtGroup1.AppendLine(tSqlInsCD);
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbSavePmtDP2CD] Error : " + ex.Message);
            }
        }

        //*Thana 2026-05-22 Prevent same type repeat
        private static void W_PRCxUpdateUsedSeq(int pnPmtType, int pnDPSeqNo, bool pbStaInc)
        {
            try
            {
                if (pnPmtType >= 0 && pnPmtType < tW_SeqUsedByType.Length)
                {
                    tW_SeqUsedByType[pnPmtType] += ",'" + pnDPSeqNo + "'";
                }
                if (!pbStaInc) tW_SeqUpdDP += ",'" + pnDPSeqNo + "'";
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_PRCxUpdateUsedSeq] Error : " + ex.Message);
            }
        }

        //*Tao 63-04-15 �??��??��??���?�� (Type9)
        private bool C_PRCbCALDiscMember(bool pbBackBegin = false) //true = �??��?� ��?����??���?��
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALDiscMember] ============ START ============");
                bool bResult = (!bIsMember);
                //Default Value
                cCNVB.oVB_Type9Member = new List<cCNVB.cVB_Type9Member>();
                cCNVB.cVB_MemType9 = 0;
                if ((tShdDocType == "1") && (bIsMember)) //�???�?�?�� ��� ����?? ��?��
                {
                    string tDT = "TSDT" + tPosCode;
                    string tDP = "TSDP" + tPosCode;
                    string tCD = "TSCD" + tPosCode;
                    string tSql = "";
                    //tSql = "SELECT DISTINCT " + tDT + ".FNSdtSeqNo," + tDT + ".FTPdtCode," + tDT + ".FTSdtBarCode";
                    //tSql += "\n ," + tDT + ".FCSdtQty," + tDT + ".FCSdtSalePrice," + tDT + ".FCSdtSetPrice";
                    //tSql += "\n ," + tDT + ".FCSdtB4DisChg," + tDT + ".FCSdtNet," + tDT + ".FCSdtVat";
                    //tSql += "\n ," + tDT + ".FCSdtVatable," + tDT + ".FTSdtDisChgTxt," + tDT + ".FCSdtDis";
                    //tSql += "\n ," + tDT + ".FTSdtVatType";
                    //tSql += "\n ,TCNTPdtPmtCD.FCPmcOrgPri,TCNTPdtPmtCD.FCPmcCpnAmt";
                    //tSql += "\n ,TCNTPdtPmtCD.FTPmcGetType";
                    //tSql += "\n FROM " + tDT + " WITH(NOLOCK)";
                    //tSql += "\n INNER JOIN TCNTPdtPmtCD";
                    //tSql += "\n ON " + tDT + ".FTPmhCode=TCNTPdtPmtCD.FTPmhDocNo";
                    //tSql += "\n AND " + tDT + ".FTSdtBarCode=TCNTPdtPmtCD.FTPmcBarCodeGet";
                    //tSql += "\n INNER JOIN TCNTPdtPmtHD";
                    //tSql += "\n ON TCNTPdtPmtCD.FTPmhDocNo=TCNTPdtPmtHD.FTPmhDocNo";
                    //tSql += "\n WHERE " + tDT + ".FTShdDocNo='" + tShdDocNo + "'";
                    //tSql += "\n AND TCNTPdtPmtHD.FNSpmType=9";
                    //tSql += "\n AND TCNTPdtPmtHD.FTPmhGetType='1'"; //0=�?��?���� , 1=��??
                    //tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                    //tSql += "\n ORDER BY FNSdtSeqNo";
                    //��?����??������ ��?��?�?������
                    tSql = "SELECT DISTINCT " + tDT + ".FNSdtSeqNo," + tDT + ".FTPdtCode," + tDT + ".FTSdtBarCode";
                    tSql += "\n ," + tDT + ".FCSdtQty," + tDT + ".FCSdtSalePrice," + tDT + ".FCSdtSetPrice";
                    tSql += "\n ," + tDT + ".FCSdtB4DisChg," + tDT + ".FCSdtNet," + tDT + ".FCSdtVat";
                    tSql += "\n ," + tDT + ".FCSdtVatable," + tDT + ".FTSdtDisChgTxt," + tDT + ".FCSdtDis";
                    tSql += "\n ," + tDT + ".FTSdtVatType";
                    tSql += "\n ,TCNTPdtPmtCD.FCPmcOrgPri,TCNTPdtPmtCD.FCPmcCpnAmt";
                    tSql += "\n ,TCNTPdtPmtCD.FTPmcGetType";
                    tSql += "\n FROM " + tDT + " WITH(NOLOCK)";
                    tSql += "\n INNER JOIN TCNTPdtPmtCD";
                    tSql += "\n ON " + tDT + ".FTPmhCode=TCNTPdtPmtCD.FTPmhDocNo";
                    tSql += "\n AND " + tDT + ".FTSdtBarCode=TCNTPdtPmtCD.FTPmcBarCodeGet";
                    tSql += "\n INNER JOIN TCNTPdtPmtHD ON TCNTPdtPmtCD.FTPmhDocNo = TCNTPdtPmtHD.FTPmhDocNo";
                    tSql += "\n INNER JOIN " + tCD + "";
                    tSql += "\n ON " + tDT + ".FTPmhCode= " + tCD + ".FTPmhDocNo";
                    tSql += "\n AND " + tDT + ".FNSdtSeqNo= " + tCD + ".FNSdtSeqNo";
                    tSql += "\n WHERE " + tDT + ".FTShdDocNo='" + tShdDocNo + "'";
                    tSql += "\n AND " + tCD + ".FNSpmType=9";
                    tSql += "\n AND TCNTPdtPmtHD.FTPmhGetType='1'"; //0=�?��?���� , 1=��??
                    tSql += "\n AND " + tCD + ".FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                    tSql += "\n ORDER BY FNSdtSeqNo";
                    using (DataTable oDbTblChk = cCNSP.SP_SQLoExecute(tSql))
                    {
                        if (oDbTblChk != null)
                        {
                            if (oDbTblChk.Rows.Count > 0)
                            {
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALDiscMember] Found : " + oDbTblChk.Rows.Count.ToString());
                                //double cCmpVatRate = cCNPM.PM_GETcVatRate();
                                for (int i = 0; i < oDbTblChk.Rows.Count; i++)
                                {
                                    string tGetType = oDbTblChk.Rows[i]["FTPmcGetType"].ToString(); //3=?�? ,4=?%
                                    string tVatType = oDbTblChk.Rows[i]["FTSdtVatType"].ToString(); //1=Vat ,����=non vat
                                    string tDisChgTxtOld = oDbTblChk.Rows[i]["FTSdtDisChgTxt"].ToString();
                                    string tDisChgTxt = "";
                                    double cNet = double.Parse(oDbTblChk.Rows[i]["FCSdtNet"].ToString());
                                    double cDis = double.Parse(oDbTblChk.Rows[i]["FCPmcCpnAmt"].ToString()); //��??�?,%
                                    double cB4DisChg = double.Parse(oDbTblChk.Rows[i]["FCSdtSalePrice"].ToString());
                                    double cDisAmtOld = double.Parse(oDbTblChk.Rows[i]["FCSdtDis"].ToString());
                                    double cVatOld = double.Parse(oDbTblChk.Rows[i]["FCSdtVat"].ToString());
                                    double cVatableOld = double.Parse(oDbTblChk.Rows[i]["FCSdtVatable"].ToString());
                                    double cQty = double.Parse(oDbTblChk.Rows[i]["FCSdtQty"].ToString());
                                    double cAFDis = 0;
                                    double cDisPercent = 0;
                                    double cDisAmt = 0;
                                    double cVat = 0;
                                    double cVatable = 0;
                                    int nSeq = int.Parse(oDbTblChk.Rows[i]["FNSdtSeqNo"].ToString());
                                    if (tGetType == "3")
                                    {
                                        //?�?
                                        cDis = cQty * cDis; //�??��?�� * �??���
                                        if (cDis > cNet) { cDis = cNet; }
                                        if (pbBackBegin)
                                        { cAFDis = (cNet + cDis); }
                                        else
                                        { cAFDis = (cNet - cDis); }
                                    }
                                    else
                                    {
                                        //?%
                                        cDisPercent = cDis;
                                        cDis = (cB4DisChg * cDisPercent) / 100;
                                        cDis = (cQty * cDis);
                                        if (pbBackBegin)
                                        { cAFDis = (cNet + cDis); }
                                        else
                                        { cAFDis = (cNet - cDis); }
                                    }
                                    if (pbBackBegin)
                                    {
                                        tDisChgTxt = "-" + String.Format("{0:F2}", (cDisAmtOld - cDis));
                                    }
                                    else
                                    {
                                        if (tDisChgTxtOld == "") //pbBackBegin
                                        {
                                            tDisChgTxt = "-" + String.Format("{0:F2}", cDis);
                                        }
                                        else
                                        {
                                            tDisChgTxt = tDisChgTxtOld + ",-" + String.Format("{0:F2}", cDis);
                                        }
                                    }
                                    cDisAmt = pbBackBegin ? (cDisAmtOld - cDis) : (cDisAmtOld + cDis);
                                    cVat = (tVatType == "1") ? cCNSP.SP_CALcVatValue(false, cAFDis, cVatRate) : 0; //Include Vat ����? ��?�����
                                    cVatable = (tVatType == "1") ? (cAFDis - cVat) : 0;
                                    //Update DT New Value
                                    tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                                    tSql += "\n SET FCSdtNet=" + String.Format("{0:F2}", cAFDis);
                                    tSql += "\n ,FCSdtVat=" + String.Format("{0:F2}", cVat);
                                    tSql += "\n ,FCSdtVatable=" + String.Format("{0:F2}", cVatable);
                                    tSql += "\n ,FCSdtDis=" + String.Format("{0:F2}", cDisAmt);
                                    tSql += "\n ,FTSdtDisChgTxt='" + tDisChgTxt + "'";
                                    if (pbBackBegin) //��� �??��?� ��?����??���?�� ��� Clear Promotion Coupon
                                    {
                                        tSql += "\n ,FTSdtPmhCpnDocNo=''";
                                        tSql += "\n ,FCSdtPmhCpnGetQty=0";
                                        tSql += "\n ,FCSdtPmhCpnValue=0";
                                        tSql += "\n ,FCSdtPmtQtyGet=0";
                                        tSql += "\n ,FCSdtDisGP=0"; //Type 18
                                    }
                                    tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                    tSql += "\n AND FNSdtSeqNo=" + nSeq;
                                    cCNSP.SP_SQLbExecute(tSql);

                                    //Update DP New Value
                                    tSql = "UPDATE " + tDP + " WITH(ROWLOCK)";
                                    tSql += "\n SET FCDtpDis=" + String.Format("{0:F2}", (pbBackBegin ? (cDisAmtOld - cDis) : (cDisAmtOld + cDis)) / cQty);
                                    tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                    tSql += "\n AND FNSpmType=9";
                                    tSql += "\n AND FNSdtSeqNo=" + nSeq;
                                    cCNSP.SP_SQLbExecute(tSql);

                                    //Update CD New Value
                                    double cDiscManual = double.Parse(cCNSP.SP_SQLtFunction("SUM", "FCDtpDis", tCD, "WHERE FTShdDocNo='" + tShdDocNo + "' AND FNSdtSeqNo=" + nSeq + " AND FTDtpStaGetPmt=5 AND FCDtpPmtQtyGet=0", "0"));
                                    tSql = "UPDATE " + tCD + " WITH(ROWLOCK)";
                                    tSql += "\n SET FCDtpDis=" + String.Format("{0:F2}", (pbBackBegin ? ((cDisAmtOld - cDiscManual) - cDis) : ((cDisAmtOld - cDiscManual) + cDis)) / cQty);
                                    tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                    tSql += "\n AND FNSpmType=9";
                                    tSql += "\n AND FNSdtSeqNo=" + nSeq;
                                    cCNSP.SP_SQLbExecute(tSql);

                                    //�?�?��??������? ���?�?���???���?��?��
                                    cCNVB.oVB_Type9Member.Add(new cCNVB.cVB_Type9Member
                                    {
                                        FNSdtSeqNo = nSeq,
                                        FCSdtNet = double.Parse(String.Format("{0:F2}", cAFDis)),
                                        FCSdtVat = double.Parse(String.Format("{0:F2}", cVat)),
                                        FCSdtVatable = double.Parse(String.Format("{0:F2}", cVatable)),
                                        FCSdtDis = double.Parse(String.Format("{0:F2}", cDisAmt)),
                                        FTSdtDisChgTxt = tDisChgTxt,
                                        FCSdtQty = cQty,
                                    });
                                    cCNVB.cVB_MemType9 += double.Parse(String.Format("{0:F2}", pbBackBegin ? 0 : cDis));
                                }
                            }
                            else
                            {
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALDiscMember] Not Found !");
                            }
                            bResult = true;
                        }
                        else
                        {
                            cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALDiscMember] Error");
                            bResult = false;
                        }
                    }
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALDiscMember] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbCALDiscMember] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-04-17 �??����??������?�������
        private double C_CalcDiscByType(string ptGetType, double pcSumDisc, double pcAdjust, double pcDiscAmt, double pcDiscPer)
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_CalcDiscByType] ============ START ============");
                double cResult = 0;
                switch (ptGetType)
                {
                    case "1": //���
                        cResult = pcSumDisc;
                        break;
                    case "2": //��?�?�
                        cResult = pcSumDisc - pcAdjust;
                        break;
                    case "3": //?�??
                        cResult = pcDiscAmt;
                        break;
                    case "4": //?������?�
                        cResult = (pcDiscPer * pcSumDisc) / 100;
                        break;
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_CalcDiscByType] Result : " + cResult.ToString());
                return cResult < 0 ? 0 : cResult;

            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_CalcDiscByType] Error : " + ex.Message);
                return 0;
            }
        }

        //*Tao 63-04-27 �??�??���?�� (Type 20)
        private bool C_PRCbCALPmtType20()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtType20] ============ START ============");
                string tHD = "TSHD" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tPM = "TSPM" + tPosCode;
                string tPP = "TSPP" + tPosCode;
                string tSql = "";
                //���?���?�?�� �?���������
                tSql = "SELECT FTSdtBarCode,MIN(FNSdtSeqNo) AS FNSdtSeqNo";
                tSql += "\n FROM " + tDT + " WITH(NOLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                tSql += "\n AND ISNULL(FTCpnCode,'')=''"; //��?������?���������?��?�� Type 16
                tSql += "\n GROUP BY FTSdtBarCode";
                tSql += "\n ORDER BY FNSdtSeqNo";
                using (DataTable oDbTblDT = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblDT != null)
                    {
                        if (oDbTblDT.Rows.Count > 0)
                        {
                            string tPmhDocNo = "";
                            for (int iDT = 0; iDT < oDbTblDT.Rows.Count; iDT++)
                            {
                                string tBarCode = oDbTblDT.Rows[iDT]["FTSdtBarCode"].ToString();
                                //���?���?�?�?�����??�������
                                tSql = "SELECT DISTINCT FTPmhDocNo";
                                tSql += "\n FROM " + tPM + " WITH(NOLOCK)";
                                tSql += "\n WHERE FTPdtBarX='" + tBarCode + "'";
                                tSql += "\n AND FNSpmType='91'";
                                tSql += "\n ORDER BY FTPmhDocNo";
                                using (DataTable oDbTblPM = cCNSP.SP_SQLoExecute(tSql))
                                {
                                    if (oDbTblPM != null)
                                    {
                                        if (oDbTblPM.Rows.Count > 0)
                                        {
                                            for (int iPM = 0; iPM < oDbTblPM.Rows.Count; iPM++)
                                            {
                                                tPmhDocNo += tPmhDocNo == "" ? "'" + oDbTblPM.Rows[iPM]["FTPmhDocNo"].ToString() + "'" : ",'" + oDbTblPM.Rows[iPM]["FTPmhDocNo"].ToString() + "'";
                                            }
                                        }
                                    }
                                }
                            }
                            //�??�??������??�������
                            if (!string.IsNullOrEmpty(tPmhDocNo)) //��?��� Promotion Type-20 ���
                            {
                                tSql = "SELECT DISTINCT " + tPM + ".FTPmhDocNo," + tPM + ".FTSpmGetType,TCNTPdtPmtHD.FTPmhRmk";
                                tSql += "\n ,TCNTPdtPmtHD.FDPmhCpnAffect,TCNTPdtPmtHD.FDPmhCpnExpired,TCNTPdtPmtHD.FCPmhCpnAmt,TCNTPdtPmtHD.FTPmhStatus,TCNTPdtPmtHD.FCPmhCpnQty";
                                tSql += "\n FROM " + tPM + " WITH(NOLOCK)";
                                tSql += "\n INNER JOIN TCNTPdtPmtHD WITH(NOLOCK) ON " + tPM + ".FTPmhDocNo=TCNTPdtPmtHD.FTPmhDocNo";
                                tSql += "\n WHERE " + tPM + ".FTPmhDocNo IN (" + tPmhDocNo + ")";
                                tSql += "\n AND " + tPM + ".FNSpmType='91'";
                                tSql += "\n AND ISNULL(TCNTPdtPmtHD.FTPmhClosed,'')<>'1'";
                                tSql += "\n AND ISNULL(TCNTPdtPmtHD.FTPmhStaPrcDoc,'')='1'";
                                tSql += "\n ORDER BY FTPmhDocNo";
                                using (DataTable oDbTblPM = cCNSP.SP_SQLoExecute(tSql))
                                {
                                    if (oDbTblPM != null)
                                    {
                                        if (oDbTblPM.Rows.Count > 0)
                                        {
                                            for (int iPM = 0; iPM < oDbTblPM.Rows.Count; iPM++)
                                            {
                                                string tPmtDocNo = oDbTblPM.Rows[iPM]["FTPmhDocNo"].ToString();
                                                //string tPmhRmkPrint += tPmhRmkPrint == "" ? oDbTblPM.Rows[iPM]["FTPmhRmk"].ToString() : ";" + oDbTblPM.Rows[iPM]["FTPmhRmk"].ToString();
                                                string tPmhRmk = oDbTblPM.Rows[iPM]["FTPmhRmk"].ToString();
                                                DateTime dPmhCpnAffect = DateTime.Parse(oDbTblPM.Rows[iPM]["FDPmhCpnAffect"].ToString());
                                                DateTime dPmhCpnExpired = DateTime.Parse(oDbTblPM.Rows[iPM]["FDPmhCpnExpired"].ToString());
                                                double cPmhCpnAmt = double.Parse(oDbTblPM.Rows[iPM]["FCPmhCpnAmt"].ToString());
                                                bool bPrintSta = oDbTblPM.Rows[iPM]["FCPmhCpnQty"].ToString() == "1" ? true : false;
                                                string tGetType = oDbTblPM.Rows[iPM]["FTSpmGetType"].ToString();
                                                string tBarCode = "";
                                                double cSumALL = 0;
                                                double cSumAmt = 0;
                                                int nCount = 0;
                                                //��?�?�?��?����������???���?��
                                                tSql = "SELECT MAX(FTPdtCode) AS FTPdtCode,MAX(FTPdtName) AS FTPdtName,FTSdtBarCode,SUM(FCSdtQty) AS FCSdtQty,SUM(FCSdtQtyAll) AS FCSdtQtyAll,SUM(FCSdtNet) AS FCSdtNet,MIN(FNSdtSeqNo) AS FNSdtSeqNo";
                                                tSql += "\n FROM " + tDT + " WITH(NOLOCK)";
                                                tSql += "\n WHERE FTSdtBarCode IN (SELECT DISTINCT FTPdtBarX FROM " + tPP + " WITH(NOLOCK) WHERE FTPmhDocNo='" + tPmtDocNo + "')";
                                                tSql += "\n AND FTShdDocNo='" + tShdDocNo + "'";
                                                tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                                                tSql += "\n AND ISNULL(FTCpnCode,'')=''"; //��?������?���������?��?�� Type 16
                                                tSql += "\n GROUP BY FTSdtBarCode";
                                                tSql += "\n ORDER BY FNSdtSeqNo";
                                                using (DataTable oDbTblTmp = cCNSP.SP_SQLoExecute(tSql))
                                                {
                                                    if (oDbTblTmp != null)
                                                    {
                                                        if (oDbTblTmp.Rows.Count > 0)
                                                        {
                                                            for (int iTmp = 0; iTmp < oDbTblTmp.Rows.Count; iTmp++)
                                                            {
                                                                tBarCode += tBarCode == "" ? "'" + oDbTblTmp.Rows[iTmp]["FTSdtBarCode"].ToString() + "'" : ",'" + oDbTblTmp.Rows[iTmp]["FTSdtBarCode"].ToString() + "'";
                                                                if (tGetType == "1") //���/�?
                                                                {
                                                                    cSumALL += double.Parse(oDbTblTmp.Rows[iTmp]["FCSdtQty"].ToString());
                                                                }
                                                                else
                                                                {
                                                                    cSumALL += double.Parse(oDbTblTmp.Rows[iTmp]["FCSdtNet"].ToString());
                                                                }
                                                                cSumAmt += double.Parse(oDbTblTmp.Rows[iTmp]["FCSdtNet"].ToString());
                                                            }
                                                        }
                                                    }
                                                }
                                                //�??�?��?����������???���?��
                                                if (cSumALL > 0)
                                                {
                                                    double cDisAmt = 0;
                                                    string tPmcGetType = "";
                                                    string tSppType = "";
                                                    tSql = "SELECT DISTINCT FTPmhGetType,CONVERT(FLOAT,FCPmhSumBillAmt) AS FCPmhSumBillAmt,FCPmhDisAmt,FCPmhDisPer,FNSppType";
                                                    tSql += "\n FROM " + tPP + " WITH(NOLOCK)";
                                                    tSql += "\n WHERE FTPmhDocNo='" + tPmtDocNo + "'";
                                                    tSql += "\n ORDER BY FCPmhSumBillAmt";
                                                    using (DataTable oDbTblTmp = cCNSP.SP_SQLoExecute(tSql))
                                                    {
                                                        if (oDbTblTmp != null)
                                                        {
                                                            if (oDbTblTmp.Rows.Count > 0)
                                                            {
                                                                for (int iTmp = 0; iTmp < oDbTblTmp.Rows.Count; iTmp++)
                                                                {
                                                                    if (double.Parse(oDbTblTmp.Rows[iTmp]["FCPmhSumBillAmt"].ToString()) <= cSumALL)
                                                                    {
                                                                        tPmcGetType = oDbTblTmp.Rows[iTmp]["FTPmhGetType"].ToString();
                                                                        tSppType = oDbTblTmp.Rows[iTmp]["FNSppType"].ToString();
                                                                        switch (tPmcGetType)
                                                                        {
                                                                            case "1": //�����
                                                                            case "2": //?�?
                                                                            case "4": //���
                                                                                cDisAmt = double.Parse(oDbTblTmp.Rows[iTmp]["FCPmhDisAmt"].ToString());
                                                                                break;
                                                                            case "3": //? %
                                                                                cDisAmt = double.Parse(oDbTblTmp.Rows[iTmp]["FCPmhDisPer"].ToString());
                                                                                break;
                                                                        }
                                                                    }
                                                                }
                                                            }
                                                            if (cDisAmt > 0)
                                                            {
                                                                nCount += 1;
                                                                if (tPmcGetType == "3") { cDisAmt = (cDisAmt * cSumAmt) / 100; }
                                                                string tPmhDetail = "";
                                                                string[] aPmhDetail = tPmhRmk.Split(';');
                                                                string[] aDetail;
                                                                if (aPmhDetail.Length == 1)
                                                                {
                                                                    aDetail = aPmhDetail[0].Split(',');
                                                                    if (aDetail.Length == 1)
                                                                    {
                                                                        tPmhDetail = aDetail[0] + " " + String.Format("{0:F2}", cDisAmt);
                                                                    }
                                                                    else
                                                                    {
                                                                        tPmhDetail = aDetail[0] + " " + String.Format("{0:F2}", cDisAmt) + " " + aDetail[1];
                                                                    }
                                                                }
                                                                else
                                                                {
                                                                    tPmhDetail = aPmhDetail[0] + " " + String.Format("{0:F2}", cDisAmt) + " " + aPmhDetail[1];
                                                                }
                                                                C_PRCxUpdBillPmtType20(tBarCode, tPmtDocNo, tPmcGetType, cDisAmt, nCount, tSppType, cPmhCpnAmt, tPmhDetail, cCNSP.SP_DTEtByFormat(dPmhCpnAffect), cCNSP.SP_DTEtByFormat(dPmhCpnExpired), bPrintSta);
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                return true;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbCALPmtType20] Error : " + ex.Message);
                return false;
            }

        }

        //*Tao 63-04-28 �??������???���?�?��??�� (Type 20)
        private void C_PRCxUpdBillPmtType20(string ptBarcode, string ptPmhDocNo, string ptPmtGetType, double pcPoint, int pnCount, string ptSppType, double pcCpnAmt = 0, string ptPmhDetail = "", string ptPmhCpnAffect = "", string ptPmhCpnExpired = "", bool pbPrintCpnSta = false)
        {
            try
            {
                string tHD = "TSHD" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tDP = "TSDP" + tPosCode;
                string tCD = "TSCD" + tPosCode;
                string tPM = "TSPM" + tPosCode;
                string tSql = "";
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCxUpdBillPmtType20] ============ START ============");
                tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                tSql += "\n SET FCShdDiscGP1=FCShdDiscGP1+" + pcPoint + "";
                tSql += "\n WHERE FTSdtBarCode IN (" + ptBarcode + ")"; //��?�� Single Quote ��?�?��?�
                //tSql += "\n WHERE FTSdtBarCode IN (SELECT DISTINCT FTPdtBarX FROM " + tPM + " WHERE FTPmhDocNo='" + ptPmhDocNo + "')";
                tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                tSql += "\n AND ISNULL(FTCpnCode,'')=''"; //��?������?���������?��?�� Type 16
                tSql += "\n ;";
                //cCNSP.SP_SQLbExecute(tSql);
                oW_SqlDTPmtGroup2.AppendLine(tSql);
                switch (ptPmtGetType)
                {
                    case "1":
                        tSql = "UPDATE " + tHD + " WITH(ROWLOCK)";
                        tSql += "\n SET FTAloCode=ISNULL(FTAloCode,0)+" + pcPoint;
                        tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                        tSql += "\n ;";
                        //cCNSP.SP_SQLbExecute(tSql);
                        oW_SqlHDPmtGroup2.AppendLine(tSql);
                        nW_CDSeqNo += 1;
                        tSql = "INSERT INTO " + tCD + " WITH(ROWLOCK)";
                        tSql += "\n SELECT FTBchCode,FTShdDocNo," + nW_CDSeqNo + ",0,'" + ptPmhDocNo + "'";
                        tSql += "\n ," + ptSppType + ",'','','" + ptPmhDetail + "',FTShdDocType";
                        tSql += "\n ,FDShdDocDate,0,0,0,''";
                        tSql += "\n ,''," + pcPoint + "," + pcCpnAmt + ",'" + ptPmhCpnAffect + "','" + ptPmhCpnExpired + "'";
                        tSql += "\n ,0,'4',1,0,0";
                        tSql += "\n ,0,0,0,0,0";
                        tSql += "\n ,'" + (pbPrintCpnSta ? "1" : "") + "',''";
                        tSql += "\n ,FDDateUpd,FTTimeUpd,FTWhoUpd,FDDateIns,FTTimeIns,FTWhoIns";
                        tSql += "\n FROM " + tDP + " WITH(NOLOCK)";
                        tSql += "\n WHERE FNDtpSeqNo=1";
                        tSql += "\n AND FTShdDocNo='" + tShdDocNo + "'";
                        tSql += "\n ;";
                        //cCNSP.SP_SQLbExecute(tSql);
                        oW_SqlCDPmtGroup2.AppendLine(tSql);
                        break;
                    case "2":
                    case "3":

                        break;

                    case "4":

                        break;
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCxUpdBillPmtType20] ============  END  ============");
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCxUpdBillPmtType20] Error : " + ex.Message);
            }
        }

        //*Tao 63-04-16 �??��??���?�� (Type 12-17)
        private bool C_PRCbCALDiscPmt()
        {
            //Table PG:����?���?���?��� ��� Promotion ���?�?�����
            //Table DP:����?���?��� ����� Promotion ��?��(Pmt 1-11) �����
            //Table DT:����?���?��?�� ���?�����
            //����?���?��?��?�??? Promotion ���?�� ���?������?? DT ����������� PG ���� DP
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALDiscPmt] ============ START ============");
                string tVPM = "VPMTforBILL" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tDP = "TSDP" + tPosCode;
                string tCD = "TSCD" + tPosCode;
                string tPG = "TSPG" + tPosCode;
                string tSql = "";
                tSql = "IF EXISTS (SELECT * FROM SYSOBJECTS WHERE ID=OBJECT_ID(N'[" + tVPM + "]'))";
                tSql += "\n BEGIN";
                tSql += "\n DROP VIEW [" + tVPM + "]";
                tSql += "\n END";
                cCNSP.SP_SQLbExecute(tSql);
                tSql = "CREATE VIEW " + tVPM + " AS ";
                if (cCNVB.bVB_CNAlwDisPmt)
                {
                    tSql += "\n SELECT DISTINCT " + tPG + ".FTPmhDocNo," + tDT + ".FTSdtBarCode FROM " + tPG + " WITH(NOLOCK)," + tDT + " WITH(NOLOCK)";
                    tSql += "\n WHERE " + tDT + ".FTShdDocNo='" + tShdDocNo + "'";
                    tSql += "\n AND " + tDT + ".FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                    tSql += "\n EXCEPT";
                    tSql += "\n SELECT DISTINCT " + tPG + ".FTPmhDocNo," + tPG + ".FTPdtBarX FROM " + tPG + " WITH(NOLOCK)";
                }
                else
                {
                    tSql += "\n SELECT DISTINCT " + tPG + ".FTPmhDocNo," + tDT + ".FTSdtBarCode FROM " + tPG + " WITH(NOLOCK)," + tDT + " WITH(NOLOCK)";
                    tSql += "\n WHERE " + tDT + ".FTShdDocNo='" + tShdDocNo + "'";
                    tSql += "\n AND " + tDT + ".FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                    tSql += "\n EXCEPT";
                    tSql += "\n SELECT DISTINCT " + tPG + ".FTPmhDocNo," + tDP + ".FTDtpBarcode FROM " + tPG + " WITH(NOLOCK)," + tDP + " WITH(NOLOCK)";
                    tSql += "\n EXCEPT";
                    tSql += "\n SELECT DISTINCT " + tPG + ".FTPmhDocNo," + tPG + ".FTPdtBarX FROM " + tPG + " WITH(NOLOCK)";
                    tSql += "\n EXCEPT";
                    tSql += "\n SELECT DISTINCT " + tDP + ".FTPmhDocNo," + tDP + ".FTDtpBarcode FROM " + tDP + " WITH(NOLOCK)";
                }
                if (cCNSP.SP_SQLbExecute(tSql))
                {
                    tSql = "SELECT DISTINCT " + tPG + ".FTPmhDocNo";
                    tSql += "\n ," + tPG + ".FTPmhName";
                    tSql += "\n ," + tPG + ".FDPmhDStart";
                    tSql += "\n ," + tPG + ".FDPmhDStop";
                    tSql += "\n ," + tPG + ".FDPmhTStart";
                    tSql += "\n ," + tPG + ".FDPmhTStop";
                    tSql += "\n ," + tPG + ".FNSpgType";
                    tSql += "\n ," + tPG + ".FTPmhGetType";
                    tSql += "\n ,0 AS FCSpgNetBill";
                    tSql += "\n ,0 AS FCSpgAmtDiscZ";
                    tSql += "\n ," + tPG + ".FCPmhDisAmt";
                    tSql += "\n ," + tPG + ".FCPmhDisPer";
                    tSql += "\n ," + tPG + ".FCPmhPriAdj";
                    tSql += "\n ," + tPG + ".FTPmhStaBillType";
                    tSql += "\n ," + tPG + ".FTPmhBillFrm";
                    tSql += "\n ," + tPG + ".FTPmhBillTo";
                    tSql += "\n ," + tPG + ".FTPmhRightChr";
                    tSql += "\n ," + tPG + ".FCPmhSumBillAmt";
                    tSql += "\n ," + tPG + ".FCPmhCpnQty";
                    tSql += "\n ," + tPG + ".FCPmhCpnAmt";
                    tSql += "\n ," + tPG + ".FDPmhCpnAffect";
                    tSql += "\n ," + tPG + ".FDPmhCpnExpired";
                    tSql += "\n ,ISNULL(" + tPG + ".FTPmhRmk,'') AS FTPmhRmk";
                    tSql += "\n ,ISNULL(" + tPG + ".FTPdtBarZ,'') AS FTPdtCodeZ";
                    tSql += "\n ," + tPG + ".FTPdtBarZ";
                    tSql += "\n ,ISNULL(" + tVPM + ".FTSdtBarCode,'') AS FTPdtBarX";
                    tSql += "\n ,(" + tDP + ".FCDtpNet - " + tDP + ".FCDtpDis) AS FCSpgNetZ";
                    tSql += "\n ," + tDP + ".FNSdtSeqNo";
                    tSql += "\n ," + tDP + ".FNSdtSeqNo AS FNDtpSeqNo";
                    tSql += "\n FROM " + tVPM;
                    tSql += "\n INNER JOIN " + tPG + " WITH(NOLOCK) ON " + tPG + ".FTPmhDocNo=" + tVPM + ".FTPmhDocNo";
                    tSql += "\n INNER JOIN " + tDP + " WITH(NOLOCK) ON " + tDP + ".FTDtpBarCode=" + tVPM + ".FTSdtBarCode";
                    tSql += "\n AND " + tDP + ".FTShdDocNo = '" + tShdDocNo + "'";
                    tSql += "\n AND " + tDP + ".FTPdtNoDis='2'";
                    tSql += "\n AND " + tDP + ".FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                    tSql += "\n ORDER BY FTPmhDocNo";
                    using (DataTable oDbVPmt = cCNSP.SP_SQLoExecute(tSql))
                    {
                        if (oDbVPmt != null)
                        {
                            if (oDbVPmt.Rows.Count > 0)
                            {
                                double cSumBill = 0;
                                //string tPmhCode = "";
                                string tStaBillType = "";
                                string tPmhDocNo = "";
                                int nSpgType = 0;
                                string tGetType = "";
                                double cDiscAmt = 0;
                                double cDiscPer = 0;
                                double cAdjust = 0;
                                string tBillFrm = "";
                                string tBillTo = "";
                                string tRightChr = "";
                                double cSumBillAmt = 0;
                                double cCpnQty = 0;
                                double cCpnAmt = 0;
                                double cSpgNetZ = 0;
                                int nSdtSeq = 0;
                                int nDtpSeq = 0;
                                string tPmtRmk = "";
                                string tPdtBarX = "";
                                string tPdtCodeZ = "";
                                DateTime dCpnAffect = default(DateTime);
                                DateTime dCpnExpired = default(DateTime);
                                //�??���??�?���������??���?��
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALDiscPmt] Promotion DisLast Count : " + oDbVPmt.Rows.Count);
                                cCNVB.oVB_PmtDisLast = new List<cCNVB.cVB_PmtDisLast>();
                                cCNVB.oVB_PmtSumDisLast = new List<cCNVB.cVB_PmtSumDisLast>();
                                for (int iVP = 0; iVP <= oDbVPmt.Rows.Count; iVP++)
                                {
                                    if (iVP == 0)
                                    {
                                        //�?��������?�? ���?����??�������������??
                                        cSumBill = 0;
                                        tStaBillType = oDbVPmt.Rows[iVP]["FTPmhStaBillType"].ToString();
                                        tPmhDocNo = oDbVPmt.Rows[iVP]["FTPmhDocNo"].ToString();
                                        nSpgType = int.Parse(oDbVPmt.Rows[iVP]["FNSpgType"].ToString());
                                        tGetType = oDbVPmt.Rows[iVP]["FTPmhGetType"].ToString(); //Type of Discount 1:Free, 2:Adjust Price, 3:Discount Baht, 4:Discount Percent
                                        cDiscAmt = double.Parse(oDbVPmt.Rows[iVP]["FCPmhDisAmt"].ToString()); //Discount Baht
                                        cDiscPer = double.Parse(oDbVPmt.Rows[iVP]["FCPmhDisPer"].ToString()); //Discount Percent
                                        cAdjust = double.Parse(oDbVPmt.Rows[iVP]["FCPmhPriAdj"].ToString()); //Adjust Price
                                        tBillFrm = oDbVPmt.Rows[iVP]["FTPmhBillFrm"].ToString();
                                        tBillTo = oDbVPmt.Rows[iVP]["FTPmhBillTo"].ToString();
                                        tRightChr = oDbVPmt.Rows[iVP]["FTPmhRightChr"].ToString();
                                        cSumBillAmt = double.Parse(oDbVPmt.Rows[iVP]["FCPmhSumBillAmt"].ToString()); //Sum Bill to get coupon Promotion
                                        cCpnQty = double.Parse(oDbVPmt.Rows[iVP]["FCPmhCpnQty"].ToString()); //Coupon's Qty of Promotion
                                        cCpnAmt = double.Parse(oDbVPmt.Rows[iVP]["FCPmhCpnAmt"].ToString()); //Coupon's Value of Promotion
                                        cSpgNetZ = double.Parse(oDbVPmt.Rows[iVP]["FCSpgNetZ"].ToString());
                                        nSdtSeq = int.Parse(oDbVPmt.Rows[iVP]["FNSdtSeqNo"].ToString());
                                        nDtpSeq = int.Parse(oDbVPmt.Rows[iVP]["FNDtpSeqNo"].ToString());
                                        tPmtRmk = oDbVPmt.Rows[iVP]["FTPmhRmk"].ToString();
                                        tPdtBarX = oDbVPmt.Rows[iVP]["FTPdtBarX"].ToString();
                                        tPdtCodeZ = oDbVPmt.Rows[iVP]["FTPdtCodeZ"].ToString();
                                        if (!string.IsNullOrEmpty(oDbVPmt.Rows[iVP]["FDPmhCpnAffect"].ToString())) { dCpnAffect = DateTime.Parse(oDbVPmt.Rows[iVP]["FDPmhCpnAffect"].ToString()); }
                                        if (!string.IsNullOrEmpty(oDbVPmt.Rows[iVP]["FDPmhCpnExpired"].ToString())) { dCpnExpired = DateTime.Parse(oDbVPmt.Rows[iVP]["FDPmhCpnExpired"].ToString()); }
                                        cSumBill += cSpgNetZ;
                                        //�?�?��??������? ���?�?���???���?��?��
                                        cCNVB.oVB_PmtDisLast.Add(new cCNVB.cVB_PmtDisLast
                                        {
                                            FTPmhStaBillType = tStaBillType,
                                            FTPmhDocNo = tPmhDocNo,
                                            FNSpgType = nSpgType,
                                            FTPmhGetType = tGetType,
                                            FCPmhDiscAmt = cDiscAmt,
                                            FCPmhDiscPer = cDiscPer,
                                            FCPmhPriAdj = cAdjust,
                                            FTPmhBillFrm = tBillFrm,
                                            FTPmhBillTo = tBillTo,
                                            FTPmhRightChr = tRightChr,
                                            FCPmhSumBillAmt = cSumBillAmt,
                                            FCPmhCpnQty = cCpnQty,
                                            FCPmhCpnAmt = cCpnAmt,
                                            FCSpgNetZ = cSpgNetZ,
                                            FNSdtSeqNo = nSdtSeq,
                                            FNDtpSeqNo = nDtpSeq,
                                            FTPmhRmk = tPmtRmk,
                                            FTPdtBarX = tPdtBarX,
                                            FTPdtCodeZ = tPdtCodeZ,
                                            FDPmhCpnAffect = dCpnAffect,
                                            FDPmhCpnExpired = dCpnExpired
                                        });
                                    }
                                    else
                                    {
                                        if ((iVP == oDbVPmt.Rows.Count) || (tPmhDocNo != oDbVPmt.Rows[iVP]["FTPmhDocNo"].ToString()))
                                        {
                                            int nQtySalBillYear = 0; //Sum no of bill in to Year
                                            int nQtySalBillMonth = 0; //Sum no of bill in to Month
                                            int nQtySalBillDay = 0; //Sum no of bill in to day
                                            string tLastBillPmt = "";
                                            string tLastBillMat = "";
                                            int nDivBill = 0;
                                            double cSumDiscBill = 0;
                                            switch (nSpgType)
                                            {
                                                case 95: //Type 12 �������?�?�������?��� N ���?�? �?/��?/��
                                                    switch (tStaBillType)
                                                    {
                                                        case "2": //Year
                                                            nQtySalBillYear = int.Parse(cCNSP.SP_SQLtFunction("SUM", "FNCptQty", "TSysCountPmt", "WHERE YEAR(FDCptStartDate)=" + dSaleDate.Year + " AND FTPmhDocNo='" + tPmhDocNo + "' AND FTCptType=3", "0"));
                                                            if (((nQtySalBillYear + 1) >= int.Parse(tBillFrm)) && ((nQtySalBillYear + 1) <= int.Parse(tBillTo)))
                                                            {
                                                                cSumDiscBill = C_CalcDiscByType(tGetType, cSumBill, cAdjust, cDiscAmt, cDiscPer);
                                                            }
                                                            break;
                                                        case "3": //Month
                                                            nQtySalBillMonth = int.Parse(cCNSP.SP_SQLtFunction("SUM", "FNCptQty", "TSysCountPmt", "WHERE MONTH(FDCptStartDate)=" + dSaleDate.Month + " AND YEAR(FDCptStartDate)=" + dSaleDate.Year + " AND FTPmhDocNo='" + tPmhDocNo + "' AND FTCptType=2", "0"));
                                                            if (((nQtySalBillMonth + 1) >= int.Parse(tBillFrm)) && ((nQtySalBillMonth + 1) <= int.Parse(tBillTo)))
                                                            {
                                                                cSumDiscBill = C_CalcDiscByType(tGetType, cSumBill, cAdjust, cDiscAmt, cDiscPer);
                                                            }
                                                            break;
                                                        case "4": //Day
                                                            nQtySalBillDay = int.Parse(cCNSP.SP_SQLtFunction("SUM", "FNCptQty", "TSysCountPmt", "WHERE FDCptStartDate='" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' AND FTPmhDocNo='" + tPmhDocNo + "' AND FTCptType=1", "0"));
                                                            if (((nQtySalBillDay + 1) >= int.Parse(tBillFrm)) && ((nQtySalBillDay + 1) <= int.Parse(tBillTo)))
                                                            {
                                                                cSumDiscBill = C_CalcDiscByType(tGetType, cSumBill, cAdjust, cDiscAmt, cDiscPer);
                                                            }
                                                            break;
                                                    }
                                                    break;
                                                case 96: //Type 13 �������?�?�������?����??��� N �? �?/��?/��
                                                    switch (tStaBillType)
                                                    {
                                                        case "2": //Year
                                                            nQtySalBillYear = int.Parse(cCNSP.SP_SQLtFunction("SUM", "FNCptQty", "TSysCountPmt", "WHERE YEAR(FDCptStartDate)=" + dSaleDate.Year + " AND FTPmhDocNo='AdaSoft' AND FTCptType=3", "0"));
                                                            if ((nQtySalBillYear + 1) == int.Parse(tBillFrm))
                                                            {
                                                                cSumDiscBill = C_CalcDiscByType(tGetType, cSumBill, cAdjust, cDiscAmt, cDiscPer);
                                                            }
                                                            break;
                                                        case "3": //Month
                                                            nQtySalBillMonth = int.Parse(cCNSP.SP_SQLtFunction("SUM", "FNCptQty", "TSysCountPmt", "WHERE MONTH(FDCptStartDate)=" + dSaleDate.Month + " AND YEAR(FDCptStartDate)=" + dSaleDate.Year + " AND FTPmhDocNo='AdaSoft' AND FTCptType=2", "0"));
                                                            if ((nQtySalBillMonth + 1) == int.Parse(tBillFrm))
                                                            {
                                                                cSumDiscBill = C_CalcDiscByType(tGetType, cSumBill, cAdjust, cDiscAmt, cDiscPer);
                                                            }
                                                            break;
                                                        case "4": //Day
                                                            nQtySalBillDay = int.Parse(cCNSP.SP_SQLtFunction("SUM", "FNCptQty", "TSysCountPmt", "WHERE FDCptStartDate='" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' AND FTPmhDocNo='AdaSoft' AND FTCptType=1", "0"));
                                                            if ((nQtySalBillDay + 1) == int.Parse(tBillFrm))
                                                            {
                                                                cSumDiscBill = C_CalcDiscByType(tGetType, cSumBill, cAdjust, cDiscAmt, cDiscPer);
                                                            }
                                                            break;
                                                    }
                                                    break;
                                                case 97: //Type 14 �������?�?�������?�������?�?���???�������?��?���?�
                                                    if (!string.IsNullOrEmpty(tRightChr.Trim()))
                                                    {
                                                        tLastBillPmt = String.Format("{0:D7}", int.Parse(tRightChr.Trim()));
                                                        tLastBillMat = tShdDocNo.Substring(tShdDocNo.Length - tLastBillPmt.Length);
                                                        if ((tLastBillPmt == tLastBillMat) && (tLastBillPmt.Length > 0)) //7 ����?���� �?�?��������?�?
                                                        {
                                                            cSumDiscBill = C_CalcDiscByType(tGetType, cSumBill, cAdjust, cDiscAmt, cDiscPer);
                                                        }
                                                    }
                                                    break;
                                                case 98: //Type 15 �������?�?�������?�������?�?���???�������?��?��?���?����?����?�
                                                    if (!string.IsNullOrEmpty(tRightChr.Trim()))
                                                    {
                                                        tLastBillPmt = tRightChr.Trim();
                                                        tLastBillMat = tShdDocNo.Substring(tShdDocNo.Length - tLastBillPmt.Length);
                                                        if ((tLastBillPmt == tLastBillMat) && (tLastBillPmt.Length > 0)) //7 ����?���� �?�?��������?�?
                                                        {
                                                            cSumDiscBill = C_CalcDiscByType(tGetType, cSumBill, cAdjust, cDiscAmt, cDiscPer);
                                                        }
                                                    }
                                                    break;
                                                case 99: //Type 16 ���?�??����?���� (�??�?�?�������??��)
                                                case 100: //type 17 ���?�??����?���� (�??�?�?�������??��)
                                                    nDivBill = (int)((cSumBill + cCNSP.SP_GETcRoundDiff(cSumBill)) / cSumBillAmt);
                                                    if (tGetType == "5")
                                                    {
                                                        if (nDivBill > 1) { nDivBill = 1; }
                                                    }
                                                    else
                                                    {
                                                        if (nDivBill > cCNVB.nVB_CNCpnMaxQty) { nDivBill = cCNVB.nVB_CNCpnMaxQty; }
                                                    }
                                                    cSumDiscBill = (nDivBill * cCpnAmt);
                                                    break;
                                            }
                                            if (cSumDiscBill > cSumBill) { cSumDiscBill = 0; }
                                            //�?�?��??������? ���?�?���???���?��?��
                                            cCNVB.oVB_PmtSumDisLast.Add(new cCNVB.cVB_PmtSumDisLast
                                            {
                                                FTPmhStaBillType = tStaBillType,
                                                FTPmhDocNo = tPmhDocNo,
                                                FCPmhNet = cSumBill,
                                                FCPmhDis = cSumDiscBill,
                                                FNPmhType = nSpgType,
                                                FCPmhSumBillAmt = cSumBillAmt,
                                                FCPmhCpnAmt = cCpnAmt,
                                                FCPmhCpnLeft = (cSumBillAmt - cSumBill)
                                            });
                                            if ((iVP <= oDbVPmt.Rows.Count - 1))
                                            {
                                                cSumBill = 0;
                                                tStaBillType = oDbVPmt.Rows[iVP]["FTPmhStaBillType"].ToString(); //������������
                                                tPmhDocNo = oDbVPmt.Rows[iVP]["FTPmhDocNo"].ToString();
                                                nSpgType = int.Parse(oDbVPmt.Rows[iVP]["FNSpgType"].ToString());
                                                tGetType = oDbVPmt.Rows[iVP]["FTPmhGetType"].ToString(); //Type of Discount 1:Free, 2:Adjust Price, 3:Discount Baht, 4:Discount Percent
                                                cDiscAmt = double.Parse(oDbVPmt.Rows[iVP]["FCPmhDisAmt"].ToString()); //Discount Baht
                                                cDiscPer = double.Parse(oDbVPmt.Rows[iVP]["FCPmhDisPer"].ToString()); //Discount Percent
                                                cAdjust = double.Parse(oDbVPmt.Rows[iVP]["FCPmhPriAdj"].ToString()); //Adjust Price
                                                tBillFrm = oDbVPmt.Rows[iVP]["FTPmhBillFrm"].ToString();
                                                tBillTo = oDbVPmt.Rows[iVP]["FTPmhBillTo"].ToString();
                                                tRightChr = oDbVPmt.Rows[iVP]["FTPmhRightChr"].ToString();
                                                cSumBillAmt = double.Parse(oDbVPmt.Rows[iVP]["FCPmhSumBillAmt"].ToString()); //Sum Bill to get coupon Promotion
                                                cCpnQty = double.Parse(oDbVPmt.Rows[iVP]["FCPmhCpnQty"].ToString()); //Coupon's Qty of Promotion
                                                cCpnAmt = double.Parse(oDbVPmt.Rows[iVP]["FCPmhCpnAmt"].ToString()); //Coupon's Value of Promotion
                                                cSpgNetZ = double.Parse(oDbVPmt.Rows[iVP]["FCSpgNetZ"].ToString()); ;
                                                nSdtSeq = int.Parse(oDbVPmt.Rows[iVP]["FNSdtSeqNo"].ToString());
                                                nDtpSeq = int.Parse(oDbVPmt.Rows[iVP]["FNDtpSeqNo"].ToString());
                                                tPmtRmk = oDbVPmt.Rows[iVP]["FTPmhRmk"].ToString();
                                                tPdtBarX = oDbVPmt.Rows[iVP]["FTPdtBarX"].ToString();
                                                tPdtCodeZ = oDbVPmt.Rows[iVP]["FTPdtCodeZ"].ToString();
                                                if (!string.IsNullOrEmpty(oDbVPmt.Rows[iVP]["FDPmhCpnAffect"].ToString())) { dCpnAffect = DateTime.Parse(oDbVPmt.Rows[iVP]["FDPmhCpnAffect"].ToString()); }
                                                if (!string.IsNullOrEmpty(oDbVPmt.Rows[iVP]["FDPmhCpnExpired"].ToString())) { dCpnExpired = DateTime.Parse(oDbVPmt.Rows[iVP]["FDPmhCpnExpired"].ToString()); }
                                                cSumBill += cSpgNetZ;
                                                //�?�?��??������? ���?�?���???���?��?��
                                                cCNVB.oVB_PmtDisLast.Add(new cCNVB.cVB_PmtDisLast
                                                {
                                                    FTPmhStaBillType = tStaBillType,
                                                    FTPmhDocNo = tPmhDocNo,
                                                    FNSpgType = nSpgType,
                                                    FTPmhGetType = tGetType,
                                                    FCPmhDiscAmt = cDiscAmt,
                                                    FCPmhDiscPer = cDiscPer,
                                                    FCPmhPriAdj = cAdjust,
                                                    FTPmhBillFrm = tBillFrm,
                                                    FTPmhBillTo = tBillTo,
                                                    FTPmhRightChr = tRightChr,
                                                    FCPmhSumBillAmt = cSumBillAmt,
                                                    FCPmhCpnQty = cCpnQty,
                                                    FCPmhCpnAmt = cCpnAmt,
                                                    FCSpgNetZ = cSpgNetZ,
                                                    FNSdtSeqNo = nSdtSeq,
                                                    FNDtpSeqNo = nDtpSeq,
                                                    FTPmhRmk = tPmtRmk,
                                                    FTPdtBarX = tPdtBarX,
                                                    FTPdtCodeZ = tPdtCodeZ,
                                                    FDPmhCpnAffect = dCpnAffect,
                                                    FDPmhCpnExpired = dCpnExpired
                                                });
                                            }
                                        }
                                        else
                                        {
                                            //��������?? ���?����?�?
                                            cSumBill += double.Parse(oDbVPmt.Rows[iVP]["FCSpgNetZ"].ToString());
                                        }
                                    }
                                }
                                //�??������?��?�� Type 12-17
                                if (cCNVB.oVB_PmtSumDisLast.Count > 0)
                                {
                                    ////���?��� Type ��� ���?��?�?������??�?�?��?                        
                                    //cCNVB.oVB_PmtSumDisLast.Sort(delegate (cCNVB.cVB_PmtSumDisLast Para1, cCNVB.cVB_PmtSumDisLast Para2) {
                                    //int nSort = Para1.FNPmhType.CompareTo(Para2.FNPmhType); //���?��� Type 95, 96, 97, 98, 99, 100
                                    //if (nSort == 0) { nSort = Para2.FCPmhDis.CompareTo(Para1.FCPmhDis); } //���?����?�����??������?�?��?
                                    //return nSort;
                                    //});

                                    //���?��?�?������??�?�?��?
                                    cCNVB.oVB_PmtSumDisLast.Sort(delegate (cCNVB.cVB_PmtSumDisLast Para1, cCNVB.cVB_PmtSumDisLast Para2)
                                    {
                                        //return Para1.FCPmhDis.CompareTo(Para2.FCPmhDis); //Ascending
                                        return Para2.FCPmhDis.CompareTo(Para1.FCPmhDis); //Descending
                                    });
                                    //�??������?��?�� Type 12-15 (FTH ��������??�?�? Type ����)
                                    double cRatio = 0;
                                    double cDisAvg = 0;
                                    double cPmhDisCur = 0;
                                    string tPmtDiscLastCode = "";
                                    foreach (cCNVB.cVB_PmtSumDisLast oSumDisLast in cCNVB.oVB_PmtSumDisLast) //���?�������?�?
                                    {
                                        if ((oSumDisLast.FNPmhType >= 95) && (oSumDisLast.FNPmhType <= 98))
                                        {
                                            tPmtDiscLastCode = oSumDisLast.FTPmhDocNo;
                                            if (oSumDisLast.FCPmhDis > 0)
                                            {
                                                int nIndexDisLast = 0;
                                                foreach (cCNVB.cVB_PmtDisLast oPmtDisLast in cCNVB.oVB_PmtDisLast) //���?�?������������?�?
                                                {
                                                    nIndexDisLast++;
                                                    if (oPmtDisLast.FTPmhDocNo == oSumDisLast.FTPmhDocNo)
                                                    {
                                                        if (oSumDisLast.FCPmhNet > 0)
                                                        {
                                                            cRatio = (oSumDisLast.FCPmhDis / oSumDisLast.FCPmhNet);
                                                        }
                                                        else
                                                        {
                                                            cRatio = 0;
                                                        }
                                                        cPmhDisCur = oSumDisLast.FCPmhDis;
                                                        if (nIndexDisLast == cCNVB.oVB_PmtDisLast.Count)
                                                        {
                                                            cDisAvg = cPmhDisCur;
                                                        }
                                                        else
                                                        {
                                                            cDisAvg = (oPmtDisLast.FCSpgNetZ * cRatio);
                                                            cPmhDisCur = ((cPmhDisCur - oPmtDisLast.FCSpgNetZ) * cRatio);
                                                        }
                                                        oPmtDisLast.FCSpgAmtDiscZ = cDisAvg;
                                                        C_PRCxUpdBillDPPmt(oPmtDisLast.FNSdtSeqNo, oPmtDisLast.FNDtpSeqNo, cDisAvg, oSumDisLast.FNPmhType, oSumDisLast.FTPmhDocNo, "", "", 0, 0, oPmtDisLast.FTPmhRmk);
                                                        cCNVB.cVB_CNSumDiscPmt += oSumDisLast.FCPmhDis;
                                                        break; //(FTH ��������??�?�? Type ����)
                                                    }
                                                }
                                                break; //(FTH ��������??�?�? Type ����)
                                            }
                                        }
                                    }

                                    //�??������?��?�� Type 16-17 (FTH �����?? Type �����)
                                    cCNVB.nVB_CNPmtCpnQty = 0; //�??�??
                                    cCNVB.cVB_CNPmtCpnAmt = 0; //��?�???
                                    foreach (cCNVB.cVB_PmtSumDisLast oSumDisLast in cCNVB.oVB_PmtSumDisLast)
                                    {
                                        if ((oSumDisLast.FNPmhType >= 99) && (oSumDisLast.FNPmhType <= 100))
                                        {
                                            if ((oSumDisLast.FCPmhDis > 0) && (!string.IsNullOrEmpty(oSumDisLast.FTPmhDocNo)))
                                            {
                                                int nIndexDisLast = 0;
                                                foreach (cCNVB.cVB_PmtDisLast oPmtDisLast in cCNVB.oVB_PmtDisLast) //���?�?������������?�?
                                                {
                                                    nIndexDisLast++;
                                                    if (oPmtDisLast.FTPmhDocNo == oSumDisLast.FTPmhDocNo)
                                                    {
                                                        string tPmtDetail = "";
                                                        string tPmtRemark = "";
                                                        string tPmtCpnMsg1 = "";
                                                        string tPmtCpnMsg2 = "";
                                                        bool bPmtCpnIsNoMsg2 = false;
                                                        double cPmtCpnAmt = oPmtDisLast.FCPmhCpnAmt;
                                                        int nPmtCpnQty = (int)((oSumDisLast.FCPmhDis + cCNSP.SP_GETcRoundDiff(oSumDisLast.FCPmhDis)) / oPmtDisLast.FCPmhCpnAmt);
                                                        if (nPmtCpnQty > 0)
                                                        {
                                                            cCNVB.nVB_CNPmtCpnQty += nPmtCpnQty; //�??�??
                                                            cCNVB.cVB_CNPmtCpnAmt += cPmtCpnAmt; //��?�???
                                                            cCNVB.tVB_CNPmtCpnCode = C_PRCtGenCpnNo(oPmtDisLast.FDPmhCpnAffect, oPmtDisLast.FDPmhCpnExpired, oSumDisLast.FNPmhType);
                                                            tPmtRemark = oPmtDisLast.FTPmhRmk;
                                                            if (!string.IsNullOrEmpty(tPmtRemark))
                                                            {
                                                                string[] aPmtRemark = tPmtRemark.Split(';');
                                                                tPmtCpnMsg1 = aPmtRemark[0];
                                                                if (aPmtRemark.Length > 1) { tPmtCpnMsg2 = aPmtRemark[1]; }
                                                                if (aPmtRemark.Length > 2) { bPmtCpnIsNoMsg2 = aPmtRemark[2] == "0" ? true : false; }
                                                                if (!string.IsNullOrEmpty(tPmtCpnMsg1))
                                                                {
                                                                    if (bPmtCpnIsNoMsg2)
                                                                    {
                                                                        tPmtDetail = tPmtCpnMsg1.Trim();
                                                                    }
                                                                    else
                                                                    {
                                                                        tPmtDetail = (tPmtCpnMsg1 + " " + nPmtCpnQty.ToString() + " " + tPmtCpnMsg2).Trim();
                                                                    }
                                                                }
                                                            }
                                                            if ((oSumDisLast.FNPmhType == 99) && (!string.IsNullOrEmpty(oPmtDisLast.FTPdtCodeZ))) //Type 16 ��?���?��?������� DT ��������
                                                            {
                                                                C_PRCxInsBillDTPmt(oPmtDisLast.FTPdtCodeZ, nPmtCpnQty, "016", oSumDisLast.FNPmhType, oSumDisLast.FTPmhDocNo);
                                                            }
                                                            cRatio = 0; //oSumDisLast.FCPmhDis / oSumDisLast.FCPmhNet;
                                                            cPmhDisCur = 0; //oSumDisLast.FCPmhDis;   
                                                            cDisAvg = 0;
                                                            oPmtDisLast.FCSpgAmtDiscZ = cDisAvg;
                                                            C_PRCxUpdBillDPPmt(oPmtDisLast.FNSdtSeqNo, oPmtDisLast.FNDtpSeqNo, cDisAvg, oSumDisLast.FNPmhType, oSumDisLast.FTPmhDocNo, cCNSP.SP_DTEtByFormat(oPmtDisLast.FDPmhCpnAffect), cCNSP.SP_DTEtByFormat(oPmtDisLast.FDPmhCpnExpired), cPmtCpnAmt, nPmtCpnQty, tPmtDetail);
                                                            break;
                                                        }
                                                    }
                                                }
                                            }
                                            else
                                            {
                                                if ((tPmtDiscLastCode == "") || (tPmtDiscLastCode != oSumDisLast.FTPmhDocNo))
                                                {
                                                    oSumDisLast.FBItemUnUse = true;
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                return true;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbCALDiscPmt] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-04-29 Gen Void No.
        private string C_PRCtGenVoidNo()
        {
            //Format        : YYXXX-DDDDDDDDD
            //YY            : Year SaleDate 2 Digits
            //XXX           : PosCode 3 Digits
            //DDDDDDDDD     : No. 9 Digits
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCtGenVoidNo] ============ START ============");
                string tVT = "TSVT" + tPosCode;
                string tVDT = "TPSTVoidDT";
                int nMaxVoidTrans = int.Parse(cCNSP.SP_SQLtFunction("MAX", "RIGHT(FTVidSeq,9)", tVT, "WHERE FTPosCode='" + tPosCode + "' AND Year(FDShdDocDate)=" + dSaleDate.Year, "0").Trim());
                int nMaxVoidMaster = int.Parse(cCNSP.SP_SQLtFunction("MAX", "RIGHT(FTVidSeq,9)", tVDT, "WHERE FTPosCode='" + tPosCode + "' AND Year(FDShdDocDate)=" + dSaleDate.Year, "0").Trim());
                int nMaxVoidDoc = nMaxVoidMaster > nMaxVoidTrans ? nMaxVoidMaster : nMaxVoidTrans;
                string tVoidNo = String.Format("{0:D9}", (nMaxVoidDoc + 1));
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCtGenVoidNo] ============  END  ============");
                return dSaleDate.ToString("yy") + tPosCode + "-" + tVoidNo;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCtGenVoidNo] Error : " + ex.Message);
                return string.Empty;
            }
        }

        //*Tao 63-04-24 Gen Coupon No.
        private string C_PRCtGenCpnNo(DateTime pdPmtCpnStart, DateTime pdPmtCpnStop, int pnPmhType)
        {
            //Format        : MMCDDDSSSSS
            //MM            : Promotion Type. 2 Digits
            //C             : Checking digit. 1 digit
            //DDD           : Duration (No of day since promotion start effect date to promotion expired date). 3 digits.  Ex. start 3/02/2007      expire 8/02/2007  then Duration = 006 , Means 6 days effct
            //SSSSS         : Start date in Julian date format except first digit.  5 digits.
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCtGenCpnNo] ============ START ============");
                string tType = pnPmhType.ToString("00");
                string tStart = pdPmtCpnStart.ToString("yy") + (pdPmtCpnStart.Subtract(new DateTime(pdPmtCpnStart.Year, 1, 1)).TotalDays + 1).ToString("000");
                string tDuration = (pdPmtCpnStop.Subtract(pdPmtCpnStart).TotalDays + 1).ToString("000");
                string tCombine = tType + tDuration + tStart;
                int nDivision = int.Parse(tCombine.Substring(0, 1));
                int nTotal = 0;
                string tChkDigit = "";
                for (int nId = 1; nId < tCombine.Length; nId++)
                {
                    nTotal += int.Parse(tCombine.Substring(nId, 1)) + 1;
                }
                tChkDigit = (nTotal % nDivision).ToString("0");
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCtGenCpnNo] ============  END  ============");
                return tCombine.Substring(0, 2) + tChkDigit + tCombine.Substring(2, (tCombine.Length - 2));
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCtGenCpnNo] Error : " + ex.Message);
                return string.Empty;
            }
        }

        //*Tao 63-04-22 �??������������?��??��
        private void C_PRCxUpdBillDPPmt(int pnSeqNo, int pnDtpSeqNo, double pcDisAvg, int pnPmhType, string ptPmhCode, string ptCpnStart, string ptCpnStop, double pcCpnAmt, int pnCpnQty, string ptPmhDetail)
        {
            try
            {
                string tDT = "TSDT" + tPosCode;
                string tDP = "TSDP" + tPosCode;
                string tCD = "TSCD" + tPosCode;
                string tSql = "";
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCxUpdBillCDPmt] ============ START ============");
                tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                tSql += "\n SET FTPmhDocNoBill='" + ptPmhCode + "'";
                tSql += "\n ,FCSdtDisAvg=FCSdtDisAvg + " + pcDisAvg;
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND FNSdtSeqNo=" + pnSeqNo;
                tSql += "\n ;";
                //cCNSP.SP_SQLbExecute(tSql);
                oW_SqlDTPmtGroup2.AppendLine(tSql);

                tSql = "UPDATE " + tDP + " WITH(ROWLOCK)";
                tSql += "\n SET FTDtpPmhBillDocNo='" + ptPmhCode + "'";
                tSql += "\n ,FCDtpPmhCpnGetQty=FCDtpPmhCpnGetQty + " + pnCpnQty;
                tSql += "\n ,FCDtpPmhCpnValue=FCDtpPmhCpnValue + " + pcCpnAmt;
                if (string.IsNullOrEmpty(ptCpnStart))
                {
                    tSql += "\n ,FDDtpPmhCpnEffect=NULL";
                    tSql += "\n ,FDDtpPmhCpnExpried=NULL";
                }
                else
                {
                    tSql += "\n ,FDDtpPmhCpnEffect='" + ptCpnStart + "'";
                    tSql += "\n ,FDDtpPmhCpnExpried='" + ptCpnStop + "'";
                }
                tSql += "\n ,FTDtpStaGetPmt=4";
                tSql += "\n ,FCDtpPmtQtyGet=1";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                tSql += "\n AND FNDtpSeqNo=" + pnDtpSeqNo;
                tSql += "\n ;";
                //cCNSP.SP_SQLbExecute(tSql);
                oW_SqlDPPmtGroup2.AppendLine(tSql);
                if (tShdDocType == "1") //��?����?��
                {
                    nW_CDSeqNo += 1;
                    if ((pnPmhType == 99) || (pnPmhType == 100))
                    {
                        tSql = "INSERT INTO " + tCD + " WITH(ROWLOCK)";
                        tSql += "\n SELECT FTBchCode,FTShdDocNo," + nW_CDSeqNo + ",0,'" + ptPmhCode + "'";
                        tSql += "\n ," + pnPmhType + ",'','','" + ptPmhDetail + "',FTShdDocType";
                        tSql += "\n ,FDShdDocDate,0,0,0,''";
                        tSql += "\n ,'" + cCNVB.tVB_CNPmtCpnCode + "'," + pnCpnQty + "," + pcCpnAmt + ",'" + ptCpnStart + "','" + ptCpnStop + "'";
                        tSql += "\n ,0,'4',1,0,0";
                        tSql += "\n ,0,0,0,0,0";
                        tSql += "\n ,'',''";
                        tSql += "\n ,FDDateUpd,FTTimeUpd,FTWhoUpd,FDDateIns,FTTimeIns,FTWhoIns";
                        tSql += "\n FROM " + tDP + " WITH(NOLOCK)";
                        tSql += "\n WHERE FNDtpSeqNo=" + pnDtpSeqNo;
                        tSql += "\n AND FTShdDocNo='" + tShdDocNo + "'";
                        tSql += "\n ;";
                        //cCNSP.SP_SQLbExecute(tSql);
                        oW_SqlCDPmtGroup2.AppendLine(tSql);
                    }
                    else if ((pnPmhType >= 95) && (pnPmhType <= 98))
                    {
                        tSql = "INSERT INTO " + tCD + " WITH(ROWLOCK)";
                        tSql += "\n SELECT FTBchCode,FTShdDocNo," + nW_CDSeqNo + ",0,'" + ptPmhCode + "'";
                        tSql += "\n ," + pnPmhType + ",'','','" + ptPmhDetail + "',FTShdDocType";
                        tSql += "\n ,FDShdDocDate,0,0," + pcDisAvg + ",''";
                        tSql += "\n ,'',0,0,NULL,NULL";
                        tSql += "\n ,0,'4',1,0,0";
                        tSql += "\n ,0,0,0,0,0";
                        tSql += "\n ,'',''";
                        tSql += "\n ,FDDateUpd,FTTimeUpd,FTWhoUpd,FDDateIns,FTTimeIns,FTWhoIns";
                        tSql += "\n FROM " + tDP + " WITH(NOLOCK)";
                        tSql += "\n WHERE FNDtpSeqNo=" + pnDtpSeqNo;
                        tSql += "\n AND FTShdDocNo='" + tShdDocNo + "'";
                        tSql += "\n ;";
                        //cCNSP.SP_SQLbExecute(tSql);
                        oW_SqlCDPmtGroup2.AppendLine(tSql);
                    }
                    else
                    {
                        tSql = "INSERT INTO " + tCD + " WITH(ROWLOCK)";
                        tSql += "\n SELECT FTBchCode,FTShdDocNo," + nW_CDSeqNo + ",0,'" + ptPmhCode + "'";
                        tSql += "\n ," + pnPmhType + ",'','','" + ptPmhDetail + "',FTShdDocType";
                        tSql += "\n ,FDShdDocDate,0,0,0,''";
                        tSql += "\n ,''," + pnCpnQty + "," + pcCpnAmt + ",NULL,NULL";
                        tSql += "\n ,0,'4',1,0,0";
                        tSql += "\n ,0,0,0,0,0";
                        tSql += "\n ,'',''";
                        tSql += "\n ,FDDateUpd,FTTimeUpd,FTWhoUpd,FDDateIns,FTTimeIns,FTWhoIns";
                        tSql += "\n FROM " + tDP + " WITH(NOLOCK)";
                        tSql += "\n WHERE FNDtpSeqNo=" + pnDtpSeqNo;
                        tSql += "\n AND FTShdDocNo='" + tShdDocNo + "'";
                        tSql += "\n ;";
                        //cCNSP.SP_SQLbExecute(tSql);
                        oW_SqlCDPmtGroup2.AppendLine(tSql);
                    }
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCxUpdBillCDPmt] ============  END  ============");
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCxUpdBillCDPmt] Error : " + ex.Message);
            }
        }

        //*Tao 63-04-24 �����������?��?����������?��?�� ?�� Type 16
        private void C_PRCxInsBillDTPmt(string ptPdtCode, int pnPdtQty, string ptSpmCode, int pnPmhType, string ptPmhCode)
        {
            try
            {
                string tDT = "TSDT" + tPosCode;
                string tSql = "";
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCxInsBillDTPmt] ============ START ============");
                tSql = "SELECT TOP 1 ";
                tSql += "\n TCNMPdt.FTPdtCode,TCNMPdt.FTPdtNameShort,TCNMPdt.FTPgpChain,TCNMPdt.FTPdtSTKCode,TCNMPdt.FTPmhCode";
                tSql += "\n ,TCNMPdt.FTPmhType,TCNMPdt.FCPdtSTKFac,TCNMPdt.FTPdtVatType,TCNMPdt.FTPdtPoint,TCNMPdt.FTPdtSaleType";
                tSql += "\n ,TCNMPdt.FTPdtPmtType,TCNMPdt.FCPdtCostAvg,TCNMPdt.FTPdtArticle,TCNMPdt.FTDcsCode,TCNMPdt.FTPszCode";
                tSql += "\n ,TCNMPdt.FTClrCode,TCNMPdt.FTPdtNoDis,TCNMPdt.FTPunCode ,TCNMPdt.FCPdtUnitFact,TCNMPdtBar.FTPdtBarCode,TCNMPdtBar.FCPdtRetPri1";
                tSql += "\n ,CASE WHEN ISNULL(TCNTPdtPmtCD.FTPdtName,'')='' THEN TCNMPdt.FTPdtName ELSE ISNULL(TCNTPdtPmtCD.FTPdtName,'') END AS FTPdtName2";
                tSql += "\n FROM TCNMPdt WITH(NOLOCK),TCNMPdtBar WITH(NOLOCK),TCNTPdtPmtCD WITH(NOLOCK)";
                tSql += "\n WHERE (TCNMPdt.FTPdtCode=TCNMPdtBar.FTPdtCode)";
                //tSql += "\n AND ISNULL(TCNMPdt.FTPdtOthPurSplN2,'')=''";
                tSql += "\n AND TCNMPdt.FTPdtCode=TCNTPdtPmtCD.FTPdtCode";
                //tSql += "\n AND TCNMPdt.FTPdtCode='" + ptPdtCode + "'";
                tSql += "\n AND TCNTPdtPmtCD.FTPdtCode='" + ptPdtCode + "'";
                tSql += "\n AND TCNTPdtPmtCD.FTPmhDocNo='" + ptPmhCode + "'";
                //tSql += "\n AND FTPdtStaActive ='1'"; //��?����
                //tSql += "\n AND FTPdtStaAlwSale ='1'"; //�����
                //tSql += "\n AND '" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN FDPdtSaleStart AND FDPdtSaleStop";
                ////tSql += "\n AND FTPdtType NOT IN ('70','71','80','81','99')";
                tSql += "\n AND FDPdtPriAffect <= GETDATE()";
                tSql += "\n ORDER BY TCNMPdtBar.FDPdtPriAffect DESC, TCNMPdtBar.FTPdtCode";
                //"FTPdtCode,FTPdtNameShort,FTPgpChain,FTPdtSTKCode,FTSrnCode,FTPmhCode,FTPmhType,FCPdtSTKFac,FCPdtRetPri1,FTPdtVatType,FTPdtPoint,FTPdtSaleType,FTPdtPmtType,FCPdtCostAvg,FTPdtArticle,FTDcsCode,FTPszCode,FTClrCode,FTPdtNoDis,FTPunCode,FCPdtUnitFact,FCSdtSetPrice,FCSdtSalePrice"
                using (DataTable oDbTblPdt = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblPdt.Rows.Count > 0)
                    {
                        nW_DTSeqNO += 1; //Seq ����?� DT
                        string tPdtBarCode = oDbTblPdt.Rows[0]["FTPdtBarCode"].ToString();
                        string tPdtCode = oDbTblPdt.Rows[0]["FTPdtCode"].ToString();
                        //string tPdtName = oDbTblPdt.Rows[0]["FTPdtNameShort"].ToString();
                        string tPdtName = oDbTblPdt.Rows[0]["FTPdtName2"].ToString();
                        string tPdtGrp = oDbTblPdt.Rows[0]["FTPgpChain"].ToString();
                        string tStkCode = oDbTblPdt.Rows[0]["FTPdtSTKCode"].ToString();
                        string tSrnCode = ""; //oDbTblPdt.Rows[0]["FTSrnCode"].ToString();
                        string tPmtCode = oDbTblPdt.Rows[0]["FTPmhCode"].ToString();
                        string tPmtType = oDbTblPdt.Rows[0]["FTPmhType"].ToString();
                        int cStkFac = int.Parse(oDbTblPdt.Rows[0]["FCPdtSTKFac"].ToString());
                        double cSalePrice = double.Parse(oDbTblPdt.Rows[0]["FCPdtRetPri1"].ToString());
                        double cSetPrice = double.Parse(oDbTblPdt.Rows[0]["FCPdtRetPri1"].ToString());
                        string tVatType = oDbTblPdt.Rows[0]["FTPdtVatType"].ToString();
                        string tPdtPoint = oDbTblPdt.Rows[0]["FTPdtPoint"].ToString();
                        string tSaleType = oDbTblPdt.Rows[0]["FTPdtSaleType"].ToString();
                        string tAccCode = oDbTblPdt.Rows[0]["FTPdtPmtType"].ToString();
                        double cPdtCost = double.Parse(oDbTblPdt.Rows[0]["FCPdtCostAvg"].ToString());
                        string tPdtArticle = oDbTblPdt.Rows[0]["FTPdtArticle"].ToString();
                        string tDcsCode = oDbTblPdt.Rows[0]["FTDcsCode"].ToString();
                        string tPszCode = oDbTblPdt.Rows[0]["FTPszCode"].ToString();
                        string tClrCode = oDbTblPdt.Rows[0]["FTClrCode"].ToString();
                        string tPszName = cCNSP.SP_SQLtFunction("", "FTPszName", "TCNMPdtSize", "WHERE FTPszCode='" + tPszCode + "'");
                        string tClrName = cCNSP.SP_SQLtFunction("", "FTClrName", "TCNMColor", "WHERE FTClrCode='" + tClrCode + "'");
                        bool bPdtNoDis = (oDbTblPdt.Rows[0]["FTPdtNoDis"].ToString() == "1") ? true : false;
                        string tPdtUnitC = oDbTblPdt.Rows[0]["FTPunCode"].ToString();
                        double cPdtUnitF = double.Parse(oDbTblPdt.Rows[0]["FCPdtUnitFact"].ToString());
                        string tPdtUnitN = cCNSP.SP_SQLtFunction("", "FTPunName", "TCNMPdtUnit", "WHERE FTPunCode='" + tPdtUnitC + "'");

                        double cChgAmt = 0; //double.Parse(oDbTblPdt.Rows[0]["FCSdtSetPrice"].ToString());
                        double cDisAmt = 0; //double.Parse(oDbTblPdt.Rows[0]["FCSdtSalePrice"].ToString());
                        //double cUT_B4DisChg = double.Parse(oDbTblPdt.Rows[0]["FCSdtSetPrice"].ToString());
                        //double tVB_CNStaPmt16 = double.Parse(oDbTblPdt.Rows[0]["FCSdtSalePrice"].ToString());
                        string tPdtStatus = "1"; //??��?��� 1:�?���, 2:�?�?, 3:�?���, 4: ?��? (Void) ,5 �?��
                        if (tRetVATInOrEx == "")
                        {
                            tRetVATInOrEx = cCNSP.SP_SQLtFunction("TOP 1", "FTCmpRetInOrEx", "TCNMComp", "WHERE FTCmpCode='001'", "1");
                            cCNVB.tVB_CNRetVATInOrEx = tRetVATInOrEx;
                        }
                        if (cVatRate == 0)
                        {
                            cVatRate = cCNPM.PM_GETcVatRate();
                            cCNVB.cVB_VatRate = cVatRate;
                        }
                        cSetPrice = 0; //���?���?���
                        double cNet = (pnPdtQty * cSetPrice);
                        double cB4DisChg = (pnPdtQty * cSetPrice);
                        double cVat = (tVatType == "1" ? cCNSP.SP_CALcVatValue((tRetVATInOrEx == "1" ? false : true), cNet, cVatRate) : 0);
                        double cVatable = ((tVatType == "1") ? cNet - cVat : 0);  //1:vat, 2:novat (0)
                        double cCostIn = (tVatType == "1" ? cCNSP.SP_CALcVatAmt(true, cPdtCost, cVatRate) : cPdtCost); //'1:vat=+N%, 2:nonvat=CostEx

                        tSql = "INSERT INTO " + tDT;
                        tSql += "\n (FTBchCode,FTShdDocNo,FNSdtSeqNo,FTPdtCode,FTPdtName,"; //1
                        tSql += "\n FTShdDocType,FDShdDocDate,FTShdVATInOrEx,FTSdtBarCode,FTSdtStkCode,"; //2
                        tSql += "\n FCSdtStkFac,FTSdtVatType,FTSdtSaleType,FTPgpChain,FTSrnCode,"; //3
                        tSql += "\n FTPmhCode,FTPmhType,FTPunCode,FTSdtUnitName,FCSdtFactor,"; //4
                        tSql += "\n FCSdtSalePrice,FCSdtQty,FCSdtSetPrice,FCSdtB4DisChg,FCSdtNet,"; //5
                        tSql += "\n FCSdtVat,FCSdtVatable,FCSdtQtyAll,FCSdtCostIn,FCSdtCostEx,"; //6
                        tSql += "\n FTSdtStaPdt,FNShdSign,FNSdtPdtLevel,FTWahCode,FTSdtLotNo,"; //7
                        tSql += "\n FTSdtDisChgTxt,FCSdtDis,FCSdtChg,FNSdtStaRef,FDSdtExpired,"; //8
                        tSql += "\n FTShdStaVatSend,FTSdtApOrAr,FTPdtArticle,FTDcsCode,FTPszCode,"; //9
                        tSql += "\n FTClrCode,FTPszName,FTClrName,FTPdtNoDis,FCSdtPmtQtyGet,"; //10
                        tSql += "\n FTAccCode,FTCpnCode,"; //11
                        tSql += "\n " + cCNCS.tCS_CNLastFedIns; //12
                        tSql += "\n ) VALUES (";
                        tSql += "\n '" + tBchCode + "','" + tShdDocNo + "'," + nW_DTSeqNO + ",'" + tPdtCode + "','" + cCNSP.SP_STRtSingleQuote(tPdtName) + "',"; //1
                        tSql += "\n '" + tShdDocType + "','" + cCNSP.SP_DTEtByFormat(dSaleDate) + "','" + cCNVB.tVB_CNRetVATInOrEx + "','" + tPdtBarCode + "','" + tStkCode + "',"; //2
                        tSql += "\n " + String.Format("{0:F2}", cStkFac) + ",'" + tVatType + "','" + tSaleType + "','" + tPdtGrp + "','" + tSrnCode + "',"; //3
                        tSql += "\n '" + tPmtCode + "'" + ",'" + tPmtType + "','" + tPdtUnitC + "','" + tPdtUnitN + "'," + String.Format("{0:F2}", cPdtUnitF) + ","; //4
                        tSql += "\n " + String.Format("{0:F2}", cSalePrice) + "," + pnPdtQty + "," + String.Format("{0:F2}", cSetPrice) + "," + String.Format("{0:F2}", cB4DisChg) + "," + String.Format("{0:F2}", cNet) + ","; //5
                        tSql += "\n " + String.Format("{0:F2}", cVat) + "," + String.Format("{0:F2}", cVatable) + "," + String.Format("{0:F2}", (pnPdtQty * cPdtUnitF * cStkFac)) + "," + String.Format("{0:F2}", cCostIn) + "," + String.Format("{0:F2}", cPdtCost) + ","; //6
                        tSql += "\n '" + tPdtStatus + "',1,0,'" + cCNVB.tVB_CNWahCode + "','" + tPdtPoint + "',"; //7
                        tSql += "\n ''," + String.Format("{0:F2}", cDisAmt) + "," + String.Format("{0:F2}", cChgAmt) + ",1," + "'" + cCNSP.SP_DTEtByFormat(dSaleDate) + "',"; //8
                        tSql += "\n '" + (cCNVB.bVB_CNBillVatSend ? "2" : "1") + "','" + cCNVB.tVB_CNCstCode + "','" + tPdtArticle + "','" + tDcsCode + "','" + tPszCode + "',"; //9
                        tSql += "\n '" + tClrCode + "','" + tPszName + "','" + tClrName + "','" + ((bPdtNoDis) ? "1" : "2") + "'," + 0 + ","; //10
                        tSql += "\n '" + tAccCode + "','" + ptSpmCode + "',"; //11
                        tSql += "\n " + cCNCS.tCS_CNLastValIns + ")"; //12
                        tSql += "\n ;";
                        //cCNSP.SP_SQLbExecute(tSql);
                        oW_SqlDTPmtGroup2.AppendLine(tSql);
                    }
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCxInsBillDTPmt] ============  END  ============");
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCxInsBillDTPmt] Error : " + ex.Message);
            }
        }

        //*Tao 62-12-12 �??�??���
        private bool C_PRCbCALPmtBill()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtBill] ============ START ============");
                bool bResult = true;
                //Bill Count
                string tTmpHD = "TSHD" + tPosCode;
                string tSalHD = "TPSTSalHD";
                cCNVB.nVB_CNQtySalBillYear = int.Parse(cCNSP.SP_SQLtFunction("COUNT", "FTShdDocNo", tSalHD, "WHERE YEAR(FDShdDocDate)=" + int.Parse(cCNSP.SP_DTEtByFormat(dSaleDate, "YYYY")), "0"));
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtBill] Year Bill Count : " + cCNVB.nVB_CNQtySalBillYear);
                cCNVB.nVB_CNQtySalBillMonth = int.Parse(cCNSP.SP_SQLtFunction("COUNT", "FTShdDocNo", tSalHD, "WHERE MONTH(FDShdDocDate)=" + int.Parse(cCNSP.SP_DTEtByFormat(dSaleDate, "MM")), "0"));
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtBill] Month Bill Count : " + cCNVB.nVB_CNQtySalBillMonth);
                cCNVB.nVB_CNQtySalBillDay = int.Parse(cCNSP.SP_SQLtFunction("COUNT", "FTShdDocNo", tSalHD, "WHERE DAY(FDShdDocDate)=" + int.Parse(cCNSP.SP_DTEtByFormat(dSaleDate, "DD")), "0"));
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtBill] Day Bill Count : " + cCNVB.nVB_CNQtySalBillDay);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtBill] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbCALPmtBill] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 62-11-21 �??��??���?�� (Type 18, N=93)
        private bool C_PRCbCALPmtGP()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtGP] ============ START ============");
                string tHD = "TSHD" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tRC = "TSRC" + tPosCode;
                string tDP = "TSDP" + tPosCode;
                string tCD = "TSCD" + tPosCode;
                string tPP = "TSPP" + tPosCode;
                string tSql = "";
                int nPmtType93Count = int.Parse(cCNSP.SP_SQLtFunction("COUNT", "FTPmhDocNo", tPP, "WHERE ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN FDPmhDStart AND FDPmhDStop) AND FNSppType=93", "0"));
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtGP] Get Promotion Group2 Type93 : Count=" + nPmtType93Count);
                if (nPmtType93Count > 0) //������������� ����?��?�? TSDPxxx (�������?����)
                {
                    //��?�?�?��?���?��������������?�� ���?�?�?�?��������?��?��
                    tSql = "SELECT FNDtpSeqNo, FTDtpBarCode, FTPdtCode, FTPdtName, FCDtpQtyAll, FCDtpNet, FNSdtSeqNo FROM " + tDP + " WITH(NOLOCK)";
                    tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                    tSql += "\n AND FTShdDocType='1'"; //?�?�?��
                    if (!cCNVB.bVB_CalPmtMultiple) { tSql += "\n AND ISNULL(FCDtpPmtQtyGet,0)=0"; } //�?�������??��?��
                    tSql += "\n AND FTSdtStaPdt='1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                    using (DataTable oDbTblDP = cCNSP.SP_SQLoExecute(tSql))
                    {
                        if (oDbTblDP != null)
                        {
                            if (oDbTblDP.Rows.Count > 0)
                            {
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtGP] Get " + tDP + " Promotion Count : " + oDbTblDP.Rows.Count);
                                cCNVB.oVB_PmtType93 = new List<cCNVB.cVB_PmtType93>();
                                for (int iDP = 0; iDP < oDbTblDP.Rows.Count; iDP++)
                                {
                                    //���?������?��?�� (93)
                                    string tPdtCode = oDbTblDP.Rows[iDP]["FTPdtCode"].ToString();
                                    string tPdtBarCode = oDbTblDP.Rows[iDP]["FTDtpBarCode"].ToString();
                                    string tPdtName = oDbTblDP.Rows[iDP]["FTPdtName"].ToString();
                                    double cPdtNet = double.Parse(oDbTblDP.Rows[iDP]["FCDtpNet"].ToString());
                                    double cPdtQty = double.Parse(oDbTblDP.Rows[iDP]["FCDtpQtyAll"].ToString());
                                    int nDtpSeq = int.Parse(oDbTblDP.Rows[iDP]["FNDtpSeqNo"].ToString());
                                    int nSdtSeq = int.Parse(oDbTblDP.Rows[iDP]["FNSdtSeqNo"].ToString());
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtGP] Get " + tDP + " Promotion FNDtpSeqNo : " + nDtpSeq.ToString());
                                    tSql = "SELECT FTPmhGetType,FCPmhDisAmt,FCPmhDisPer,FNSppType,FTPmhDocNo FROM " + tPP + " WITH(NOLOCK)";
                                    tSql += "\n WHERE FNSppType=" + 93;
                                    tSql += "\n AND FTPdtBarZ='" + tPdtBarCode + "'";
                                    tSql += "\n AND ('" + cCNSP.SP_DTEtByFormat(dSaleDate) + "' BETWEEN FDPmhDStart AND FDPmhDStop)";
                                    using (DataTable oDbTblPP = cCNSP.SP_SQLoExecute(tSql))
                                    {
                                        if (oDbTblPP != null)
                                        {
                                            if (oDbTblPP.Rows.Count > 0)
                                            {
                                                bool bMaxIsDisAmt = false;
                                                double cMaxPmtDis = 0;
                                                double cMaxPmtDisAll = 0;
                                                string tMaxPmtType = "";
                                                string tMaxPmtCode = "";
                                                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtGP] Promotion 93 Count : " + oDbTblPP.Rows.Count);
                                                for (int iPP = 0; iPP < oDbTblPP.Rows.Count; iPP++)
                                                {
                                                    bool bIsDisAmt = oDbTblPP.Rows[iPP]["FTPmhGetType"].ToString() == "3" ? true : false;
                                                    double cPmtDis = bIsDisAmt ? double.Parse(oDbTblPP.Rows[iPP]["FCPmhDisAmt"].ToString()) : double.Parse(oDbTblPP.Rows[iPP]["FCPmhDisPer"].ToString());
                                                    double cPmtDisAll = bIsDisAmt ? (cPmtDis * cPdtQty) : (cPmtDis * cPdtNet / 100);
                                                    string tPmtType = oDbTblPP.Rows[iPP]["FNSppType"].ToString();
                                                    string tPmtCode = oDbTblPP.Rows[iPP]["FTPmhDocNo"].ToString();
                                                    if (cMaxPmtDisAll < cPmtDisAll)
                                                    {
                                                        cMaxPmtDisAll = cPmtDisAll;
                                                        cMaxPmtDis = cPmtDis;
                                                        bMaxIsDisAmt = bIsDisAmt;
                                                        tMaxPmtType = tPmtType;
                                                        tMaxPmtCode = tPmtCode;
                                                    }
                                                    if (cMaxPmtDisAll > cPdtNet)
                                                    {
                                                        cMaxPmtDis = cPdtNet;
                                                    }
                                                    //�?�?��??������? ���?�?���???���?��?��
                                                    cCNVB.oVB_PmtType93.Add(new cCNVB.cVB_PmtType93
                                                    {
                                                        PdtCode = tPdtCode,
                                                        PdtBarCode = tPdtBarCode,
                                                        SdtSeqNo = nSdtSeq,
                                                        DtpSeqNo = nDtpSeq,
                                                        PdtName = tPdtName,
                                                        PmtCode = tMaxPmtCode,
                                                        PmtType = tMaxPmtType,
                                                        DisType = bMaxIsDisAmt,
                                                        DiscQty = cMaxPmtDis,
                                                        DiscAmt = cMaxPmtDisAll,
                                                    });
                                                }
                                            }
                                        }
                                    }
                                }
                                //Update TSDPxxx �?��?����������?��?��(Type93)
                                if (cCNVB.oVB_PmtType93.Count > 0)
                                {
                                    double cBalTotal = (cCNVB.cVB_SubTotal - cCNVB.cVB_CNSumDiscPmt); //�?�?����?���� = �?�����?���?��� - ��??���?�� Type 12-15
                                    foreach (cCNVB.cVB_PmtType93 oItem in cCNVB.oVB_PmtType93)
                                    {
                                        if (oItem.DiscAmt <= cBalTotal) //��??��?����?�����?�������
                                        {
                                            tSql = "UPDATE " + tDP + " WITH(ROWLOCK)";
                                            tSql += "\n SET FCDtpDisGP=FCDtpDisGP+" + oItem.DiscAmt;
                                            tSql += "\n ,FCDtpPmtQtyGet=FCDtpPmtQtyGet+1";
                                            tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                            tSql += "\n AND FNDtpSeqNo=" + oItem.DtpSeqNo;
                                            tSql += "\n ;";
                                            //cCNSP.SP_SQLbExecute(tSql);
                                            oW_SqlDPPmtGroup2.AppendLine(tSql);
                                            tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                                            tSql += "\n SET FTSdtPmhCpnDocNo='" + oItem.PmtCode + "'";
                                            tSql += "\n ,FCSdtPmhCpnGetQty=FCSdtPmhCpnGetQty+" + oItem.DiscQty;
                                            tSql += "\n ,FCSdtDisGP=FCSdtDisGP+" + oItem.DiscAmt;
                                            tSql += "\n ,FCSdtPmtQtyGet=FCSdtPmtQtyGet+" + oItem.DiscQty;
                                            tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                            tSql += "\n AND FNSdtSeqNo=" + oItem.SdtSeqNo;
                                            tSql += "\n ;";
                                            //cCNSP.SP_SQLbExecute(tSql);
                                            oW_SqlDTPmtGroup2.AppendLine(tSql);
                                            //*Tao 63-02-24 �?�������??���?�� (Type 18, N=93)
                                            nW_CDSeqNo += 1;
                                            tSql = "INSERT INTO " + tCD + " WITH(ROWLOCK)";
                                            tSql += "\n SELECT FTBchCode,FTShdDocNo," + nW_CDSeqNo + ",FNSdtSeqNo,'" + oItem.PmtCode + "'";
                                            tSql += "\n ," + oItem.PmtType + ",FTDtpBarCode,FTPdtCode,FTPdtName,FTShdDocType";
                                            tSql += "\n ,FDShdDocDate,FCDtpQtyAll,FCDtpNet,FCDtpDis,'" + oItem.PmtCode + "'";
                                            tSql += "\n ,'',0,0,NULL,NULL";
                                            tSql += "\n ," + oItem.DiscAmt + ",'4',1,0,0";
                                            tSql += "\n ,0,0,0,0,0";
                                            tSql += "\n ,FTSdtStaPdt,FTPdtNoDis";
                                            tSql += "\n ,FDDateUpd,FTTimeUpd,FTWhoUpd,FDDateIns,FTTimeIns,FTWhoIns";
                                            tSql += "\n FROM " + tDP + " WITH(NOLOCK)";
                                            tSql += "\n WHERE FNDtpSeqNo=" + oItem.SdtSeqNo;
                                            tSql += "\n AND FTShdDocNo='" + tShdDocNo + "'";
                                            tSql += "\n ;";
                                            //cCNSP.SP_SQLbExecute(tSql);
                                            oW_SqlCDPmtGroup2.AppendLine(tSql);
                                            //*Tao 63-04-29 �?�������??���?�� ����?���?�?�� Voucher
                                            string tRcvCode = "008";
                                            string tRcvName = "�???�� (�??�??)";
                                            nW_RCSeqNO += 1;
                                            tSql = "INSERT INTO " + tRC;
                                            tSql += "\n (FTShdDocNo,FNSrcSeqNo,FTShdDocType,"; //1
                                            tSql += "\n FDShdDocDate,FTRcvCode,FTRcvName,"; //2
                                            tSql += "\n FCSrcFAmt,FCSrcAmt,FCSrcNet, FCSrcChg,"; //3
                                            tSql += "\n FTSrcRef,FTBnkCode,FTBnkName,FDSrcRefDate,"; //4
                                            tSql += "\n " + cCNCS.tCS_CNLastFedIns; //5
                                            tSql += "\n ) VALUES (";
                                            tSql += "\n '" + tShdDocNo + "'," + nW_RCSeqNO + ",'" + tShdDocType + "',"; //1
                                            tSql += "\n '" + cCNSP.SP_DTEtByFormat(dSaleDate) + "','" + tRcvCode + "','" + tRcvName + "',"; //2
                                            tSql += "\n " + String.Format("{0:F2}", cBalTotal) + "," + String.Format("{0:F2}", oItem.DiscAmt) + "," + String.Format("{0:F2}", oItem.DiscAmt) + ",0,"; //3
                                            tSql += "\n '0000'" + ",'000','��?? GP','" + cCNSP.SP_DTEtByFormat(DateTime.Now.Date) + "',"; //4
                                            tSql += "\n " + cCNCS.tCS_CNLastValIns + ")"; //5
                                            tSql += "\n ;";
                                            //cCNSP.SP_SQLbExecute(tSql);
                                            oW_SqlRCPmtGroup2.AppendLine(tSql);

                                            tSql = "UPDATE " + tHD + " WITH(ROWLOCK)";
                                            tSql += "\n SET FCShdMnyCtf=FCShdMnyCtf+" + String.Format("{0:F2}", oItem.DiscAmt);
                                            tSql += "\n ,FCShdChn=0";
                                            //tSql += "\n ,FCShdRnd=" + String.Format("{0:F2}", cRound);
                                            tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                                            tSql += "\n ;";
                                            //cCNSP.SP_SQLbExecute(tSql);
                                            oW_SqlHDPmtGroup2.AppendLine(tSql);
                                            cCNVB.cVB_CNSumDiscPmt += oItem.DiscAmt;
                                            cBalTotal -= oItem.DiscAmt;
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                //bool bDPResult = cCNSP.SP_SQLbExecute(oW_SqlDPPmtGroup2.ToString());
                //cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtGP] Update " + tDP + " Result : " + bDPResult.ToString());
                //bool bDTResult = cCNSP.SP_SQLbExecute(oW_SqlDTPmtGroup2.ToString());
                //cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbCALPmtGP] Update " + tDT + " Result : " + bDTResult.ToString());
                //bResult = bDPResult || bDTResult;
                return true;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbCALPmtGP] Error : " + ex.Message);
                return false;
            }
        }

