        //*Tao 63-05-05 Update Temp Sale Header
        private bool C_PRCbUpdSaleHD()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUpdSaleHD] ============ START ============");
                bool bResult = false;
                string tHD = "TSHD" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tSql = "";
                int nPoint = int.Parse(cCNSP.SP_SQLtFunction("SUM", "FCSdtNet", tDT, "WHERE (FTShdDocNo='" + tShdDocNo + "') AND (FTSdtLotNo='1')", "0")) / 100;
                int nCntAllPdt = int.Parse(cCNSP.SP_SQLtFunction("COUNT", "FTShdDocNo", tDT, "WHERE (FTShdDocNo='" + tShdDocNo + "') AND (FTSdtStaPdt='1')", "0"));
                int nCntFood = int.Parse(cCNSP.SP_SQLtFunction("COUNT", "FTShdDocNo", tDT, "WHERE (FTShdDocNo='" + tShdDocNo + "') AND (FTSdtStaPdt='1') AND (FTAccCode='1')", "0"));
                string tRecFlag = "3";
                if (nCntAllPdt > 0)
                {
                    tRecFlag = (nCntAllPdt == nCntFood ? "1" : "2");
                }
                tSql = "UPDATE " + tHD + " WITH(ROWLOCK)";
                tSql += "\n SET FTShdStaDoc='1'"; //1:����?�
                tSql += "\n ,FCShdMnyCxx=" + nPoint;
                tSql += "\n ,FTShdStaPaid='3'"; //3:���??
                tSql += "\n ,FTShdApvCode='" + tUserCode + "'";
                tSql += "\n ,FCShdPaid=FCShdGrand"; //�?��������=�? grand
                tSql += "\n ,FTShdStaVatSend='" + (cCNVB.bVB_CNBillVatSend ? "1" : "2") + "'";
                tSql += "\n ,FTShdDocTime='" + DateTime.Now.ToString("HH:mm:ss") + "'";
                tSql += "\n ,FTPjcCode='" + tRecFlag + "'";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                //tSql += "\n AND FTShdDocType='" + tShdDocType + "'";
                bResult = cCNSP.SP_SQLbExecute(tSql);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUpdSaleHD] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbUpdSaleHD] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 63-05-05 Update Count Bill
        private bool C_PRCbUpdCountBill()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUpdCountBill] ============ START ============");
                bool bResult = false;
                string tHD = "TSHD" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tSql = "";
                //bool bDisc = cCNSP.SP_SQLtFunction("", "FTShdDisChgTxt", tHD, "WHERE (FTShdDocNo='" + tShdDocNo + "') AND (ISNULL(FTShdDisChgTxt,'')<>'')") == "" ? false : true; //����?? �������
                double cGrand = double.Parse(cCNSP.SP_SQLtFunction("", "FCShdGrand", tHD, "WHERE FTShdDocNo='" + tShdDocNo + "'", "0"));
                tSql = "SELECT FTLogCode,FTShdDocType,FTPosCode FROM TPSTCountBill WITH(NOLOCK)";
                tSql += "\n WHERE FTLogCode='" + tLogCode + "'";
                tSql += "\n AND FTShdDocType='" + tShdDocType + "'";
                tSql += "\n AND FTPosCode='" + tPosCode + "'";
                //tSql += "\n AND FTShdApvCode='" + tUserCode + "'";
                tSql += "\n AND FTCblStaOnline='1'"; //1=OnLine ,0=OffLine
                using (DataTable oDbTblCntBill = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblCntBill != null)
                    {
                        if (oDbTblCntBill.Rows.Count > 0)
                        {
                            //Update Count Bill
                            tSql = "DECLARE @tUserUpd VARCHAR(50)";
                            tSql += "\n SET @tUserUpd = '" + tUserName + "'";
                            tSql += "\n UPDATE TPSTCountBill WITH(ROWLOCK)";
                            tSql += "\n SET FNCblCountBill=FNCblCountBill + 1";
                            tSql += "\n ,FCCblTotal=FCCblTotal + " + String.Format("{0:F2}", cGrand);
                            tSql += "\n ," + cCNCS.tCS_CNLastFedUpd;
                            tSql += "\n WHERE FTLogCode='" + tLogCode + "'";
                            tSql += "\n AND FTShdDocType='" + tShdDocType + "'";
                            tSql += "\n AND FTPosCode='" + tPosCode + "'";
                            tSql += "\n AND FTCblStaOnline='1'"; //1=OnLine ,0=OffLine                            
                        }
                        else
                        {
                            //Insert Count Bill
                            tSql = "DECLARE @tUserIns VARCHAR(50)";
                            tSql += "\n SET @tUserIns = '" + tUserName + "'";
                            tSql += "\n INSERT INTO TPSTCountBill";
                            tSql += "\n (FTLogCode,FTShdDocType,FTPosCode,FTCblStaOnline,FNCblCountBill,FCCblTotal,FDCblDocDate,FTCblSatSend";
                            tSql += "\n ," + cCNCS.tCS_CNLastFedIns;
                            tSql += "\n ) VALUES (";
                            tSql += "\n '" + tLogCode + "','" + tShdDocType + "','" + tPosCode + "','" + "1" + "',1," + String.Format("{0:F2}", cGrand) + ",'" + cCNSP.SP_DTEtByFormat(dSaleDate) + "','0'";
                            tSql += "\n ," + cCNCS.tCS_CNLastValIns + ")";
                        }
                        bResult = cCNSP.SP_SQLbExecute(tSql);
                    }
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUpdCountBill] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbUpdCountBill] Error : " + ex.Message);
                return false;
            }
        }


