        //*Tao 62-11-25 Gen XML
        private bool C_PRCbGenSaleXML()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbGenSaleXML] ============ START ============");
                bool bResult = false;
                string tXML = "TXML" + tPosCode;
                string tSql = "";
                tSql = "INSERT INTO " + tXML + " (FTShdDocno,FDShdDocDate) VALUES('" + tShdDocNo + "','" + cCNSP.SP_DTEtByFormat(dSaleDate) + "')";
                if (cCNSP.SP_SQLbExecute(tSql))
                {
                    if (cCNVB.tVB_CNAPathExp == "") { cCNVB.tVB_CNAPathExp = @"C:\$xml"; }
                    string tFileNameXML = cCNVB.tVB_CNAPathExp + @"\" + cCNSP.SP_DTEtByFormat(dSaleDate, "yyMMdd") + @"\" + tShdDocNo + ".xml";
                    tSql = "exec master..xp_fileexist '" + tFileNameXML + "'";
                    bResult = cCNSP.SP_SQLbExecute(tSql);
                    if (!bResult)
                    {
                        Thread.Sleep(10000);
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbGenSaleXML] ReExecute : ");
                        bResult = cCNSP.SP_SQLbExecute(tSql);
                    }
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbGenSaleXML] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbGenSaleXML] Error : " + ex.Message);
                return false;
            }
