        //*Tao 63-05-07 Export Temp Sale
        private bool C_PRCbExpTmpSale()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbExpTmpSale] ============ START ============");
                bool bResult = false;
                string tHD = "TSHD" + tPosCode;
                string tDT = "TSDT" + tPosCode;
                string tRC = "TSRC" + tPosCode;
                string tCD = "TSCD" + tPosCode;
                string tSql = "";
                tSql = "SELECT *";
                tSql += "\n FROM " + tHD + " WITH(NOLOCK)";
                tSql += "\n WHERE FTShdDocNo='" + tShdDocNo + "'";
                //tSql += "\n AND FTShdDocType='" + tShdDocType + "'";
                using (DataTable oDbTblHD = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oDbTblHD != null)
                    {
                        if (oDbTblHD.Rows.Count > 0)
                        {
                            using (SqlConnection oDbCon = new SqlConnection(cCNVB.tVB_ConStr))
                            {
                                oDbCon.Open();
                                if (oDbCon.State == ConnectionState.Open)
                                {
                                    SqlTransaction oDbTrans = oDbCon.BeginTransaction();
                                    try
                                    {
                                        //?��������?�?
                                        tSql = "DELETE FROM TSSalHD WITH(ROWLOCK) WHERE FTShdDocNo='" + tShdDocNo + "';";
                                        tSql += "\n DELETE FROM TSSalDT WITH(ROWLOCK) WHERE FTShdDocNo='" + tShdDocNo + "';";
                                        tSql += "\n DELETE FROM TSSalRC WITH(ROWLOCK) WHERE FTShdDocNo='" + tShdDocNo + "';";
                                        tSql += "\n DELETE FROM TSSalCD WITH(ROWLOCK) WHERE FTShdDocNo='" + tShdDocNo + "';";
                                        cCNSP.SP_SQLbExecute(tSql, oDbCon, oDbTrans);
                                        if (cCNSP.SP_SqlbBulkCopy(oDbTblHD, "TSSalHD", oDbCon, oDbTrans)) //��� HD ?�� ���??��
                                        {
                                            DataTable oDbTblDT = cCNSP.SP_SQLoFunction("", "*", tDT, "WHERE FTShdDocNo='" + tShdDocNo + "'");
                                            DataTable oDbTblRC = cCNSP.SP_SQLoFunction("", "*", tRC, "WHERE FTShdDocNo='" + tShdDocNo + "'");
                                            DataTable oDbTblCD = cCNSP.SP_SQLoFunction("", "*", tCD, "WHERE FTShdDocNo='" + tShdDocNo + "'");
                                            if ((oDbTblDT != null) && (oDbTblRC != null) && (oDbTblCD != null))
                                            {
                                                bool bDTResult = cCNSP.SP_SqlbBulkCopy(oDbTblDT, "TSSalDT", oDbCon, oDbTrans);
                                                bool bRCResult = cCNSP.SP_SqlbBulkCopy(oDbTblRC, "TSSalRC", oDbCon, oDbTrans);
                                                bool bCDResult = cCNSP.SP_SqlbBulkCopy(oDbTblCD, "TSSalCD", oDbCon, oDbTrans);
                                                if ((bDTResult) && (bRCResult) && (bCDResult))
                                                {
                                                    oDbTrans.Commit();
                                                    bResult = true;
                                                }
                                            }
                                        }
                                        if (!bResult) //�������������� Rollback
                                        {
                                            oDbTrans.Rollback();
                                        }
                                    }
                                    catch (SqlException ex)
                                    {
                                        oDbTrans.Rollback();
                                        cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbExpTmpSale] Error : " + ex.Message);
                                        bResult = false;
                                    }
                                }
                            }
                        }
                    }
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbExpTmpSale] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbExpTmpSale] Error : " + ex.Message);
                return false;
            }
        }

        //*Tao 62-11-25 �??�?�?�?�����?
        private bool C_PRCbUPDTypePmt2DT()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUPDTypePmt2DT] ============ START ============");
                bool bResult = false;
                string tDT = "TSDT" + tPosCode;
                string tSql = "";
                //tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                //tSql += "\n SET TSDT" + tPosCode + ".FTPmhCode=TSPT" + tPosCode + ".FTPmhDocNo";
                //tSql += "\n ,TSDT" + tPosCode + ".FTPmhType=TSPT" + tPosCode + ".FNSpmType";
                //tSql += "\n FROM TSPT" + tPosCode + " WITH(NOLOCK),TSDT" + tPosCode + " WITH(NOLOCK)";
                //tSql += "\n WHERE ((FTPdtBarX=FTSdtBarCode) OR (FTPdtBarY=FTSdtBarCode) OR (FTPdtBarZ=FTSdtBarCode))";
                //tSql += "\n AND (FCSpmAmtDiscZ>0) AND (FCSpmQtyUsedZ>0)";
                //tSql += "\n AND (FTShdDocNo='" + tShdDocNo + "')";

                tSql = "UPDATE " + tDT + " WITH(ROWLOCK)";
                tSql += "\n SET " + tDT + ".FTPmhCode=EP.FTPmhDocNo";
                tSql += "\n ," + tDT + ".FTPmhType=EP.FNSpmType";
                tSql += "\n FROM (SELECT * FROM (";
                tSql += "\n SELECT ROW_NUMBER() OVER (PARTITION BY DP.FNSdtSeqNo ORDER BY DP.FCDtpDis DESC) AS FNPdtRow,DP.FTPmhDocNo,DP.FNSpmType,DP.FNSdtSeqNo, DP.FCDtpDis";
                tSql += "\n FROM TSDP002 DP,TSDT002 DT WHERE (DT.FTShdDocNo=DP.FTShdDocNo) AND (DT.FTSdtBarCode=DP.FTDtpBarCode)";
                tSql += "\n AND (DP.FNSpmType>0) AND (DP.FCDtpDis>0) AND (DT.FTShdDocNo='" + tShdDocNo + "')";
                tSql += "\n ) EX WHERE FNPdtRow=1) EP";
                tSql += "\n WHERE (" + tDT + ".FTShdDocNo='" + tShdDocNo + "') AND " + tDT + ".FNSdtSeqNo=EP.FNSdtSeqNo";
                bResult = cCNSP.SP_SQLbExecute(tSql);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_PRCbUPDTypePmt2DT] SumPmtNoVat : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCcCALPmtNoVat] Error : " + ex.Message);
                return false;
            }
        }

