        public bool C_GETbPmtProduct()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[cAdaNewPmt] V." + VersionDll + "");
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GETtPmtProduct] ============ START ============");
                C_SETxAllValue();
                bool bSuccess = false;
                bool bCalByPMTGrpType1 = false;
                bool bCalByPMTGrpType25 = false;
                bool bCalByPMTGrpType26 = false;
                bool bCalByPMTGrpType27 = false;
                //*Tao 63-01-13 FNDtpseqNo ����? �??���?
                string tSqlDT = "SELECT TOP 1 FNSdtSeqNo, FCSdtQtyAll FROM " + cCNVB.tVB_TmpDT + " WITH(NOLOCK) WHERE FTShdDocNo='" + cCNVB.tVB_ShdDocNo + "'";
                tSqlDT += "\n AND FTShdDocType='1'"; //?�?�?��
                tSqlDT += "\n ORDER BY FNSdtSeqNo DESC";
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GETtPmtProduct] tSqlDT : " + tSqlDT);
                using (DataTable oDbTblDT = cCNSP.SP_SQLoExecute(tSqlDT))
                {
                    if (oDbTblDT.Rows.Count > 0)
                    {
                        //*Tao 62-12-06 Get Vat Rate ��������
                        if (cVatRate == 0)
                        {
                            cVatRate = cCNPM.PM_GETcVatRate();
                            cCNVB.cVB_VatRate = cVatRate;
                        }

                        nW_MaxSeqDT = int.Parse(oDbTblDT.Rows[0]["FNSdtSeqNo"].ToString());
                        nW_QtyAllDT = int.Parse(oDbTblDT.Rows[0]["FCSdtQtyAll"].ToString());

                        //*Tao 63-01-13 ?������ ?�?/?% �??���?
                        string tSqlCD = "DELETE FROM " + cCNVB.tVB_TmpCD + " WITH(ROWLOCK)";
                        tSqlCD += "\n WHERE FTShdDocNo='" + cCNVB.tVB_ShdDocNo + "'";
                        tSqlCD += "\n AND ISNULL(FTDtpStaGetPmt,'')='5'"; // FTDtpStaGetPmt 5 = ?�? / ?% �?���? 
                        tSqlCD += "\n AND ISNULL(FCDtpPmtQtyGet,0)=0"; // 0 = ������?��?�����������

                        cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GETtPmtProduct] tSqlCD : " + tSqlCD);
                        cCNSP.SP_SQLoExecute(tSqlCD);
                    }
                }

                tW_SeqUpdDP = "'0'"; //*Tao 62-12-11 �������?�??
                for (int i = 0; i < tW_SeqUsedByType.Length; i++) tW_SeqUsedByType[i] = "'0'"; //*Thana 2026-05-22 Reset track used items per type
                bCalByPMTGrpType1 = W_CHKbCalByPMTGrpType1(); //*Tao 62-12-11 ���? ������?�?

                //Krisana 2025-11-12 Comsheet/2025-148 Promotion Type 25, 26, 27 �����������??�?����???�?��?
                bCalByPMTGrpType25 = W_CHKbCalByPMTGrpType25(); //*Krisana 2025-05-20 CR-Fix Price for Complex Promotion
                bCalByPMTGrpType26 = W_CHKbCalByPMTGrpType26(); //*Krisana 2025-06-04 CR-Fix Price for Complex Promotion
                bCalByPMTGrpType27 = W_CHKbCalByPMTGrpType27(); //*Krisana 2025-06-01 CR-Fix Price for Complex Promotion

                if (bCalByPMTGrpType1 == true && bCalByPMTGrpType25 == true && bCalByPMTGrpType26 == true && bCalByPMTGrpType27 == true) //Krisana 2025-05-20 ������� Check Error �?��??? Promotion (module: W_CHKbCalByPMTGrpType1)
                {
                    bSuccess = true;
                }
                else
                {
                    bSuccess = false;
                }

                //Krisana 2026-02-04 Update Running No. Field: FNDtpSeqNo Table: TSCDxxx
                C_PRCbUpdateSeqCD();

                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GETtPmtProduct] ============  END  ============");
                return bSuccess;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_GETtAllProduct] Error : " + ex.Message);
                return false;
            }
        }

        //*Zen 63-05-03 Promotion Coupon
        public bool C_GETbPmtCoupon()
        {
            DataTable oDbTblPmtActive = new DataTable();
      
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "[cAdaNewPmt] V." + VersionDll + "");
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GETbPmtCoupon] ============ START ============");
                C_SETxAllValue();
                bool bSuccess = false;
                //*Zen �� Promotion ��� Active ?
                string tSqlChk = "SELECT TOP 1 HD.FTPmhDocNo,HD.FTPmhGetType,ISNULL(HD.FTPmhStaJob,'0') FTPmhStaJob  ";
                tSqlChk += "\n ,PARSENAME( REPLACE(HD.FTSplCode,';','.'),4) as PdtCondi";
                tSqlChk += "\n ,PARSENAME( REPLACE(HD.FTSplCode,';','.'),3) as PdtGrp";
                tSqlChk += "\n ,PARSENAME( REPLACE(HD.FTSplCode,';','.'),2) as PdtMem";
                tSqlChk += "\n ,PARSENAME( REPLACE(HD.FTSplCode,';','.'),1) as PdtRcvType";
                tSqlChk += "\n FROM TCNTPdtPmtHD HD WITH(NOLOCK)";
                tSqlChk += "\n WHERE ( '"+ cCNVB.dVB_SaleDate.ToString("yyyy-MM-dd") + "' BETWEEN HD.FDPmhDStart AND HD.FDPmhDStop)";
                tSqlChk += "\n AND (HD.FTPmhClosed<>'1')";
                tSqlChk += "\n AND (HD.FTPmhRetOrWhs<>'2')";
                tSqlChk += "\n AND (HD.FTPmhStaPrcDoc='1')";
                tSqlChk += "\n AND (HD.FNPmhStaAct='1')";
                tSqlChk += "\n AND ('"+ cCNVB.tVB_BchCode + "' BETWEEN HD.FTPmhBchFrm AND HD.FTPmhBchTo)";
                tSqlChk += "\n AND (HD.FNSpmType ='23')";
                //FTPmhGetType 5 = 1 ��� 1 �??
                //FTPmhGetType 6 = 1 ��� ���???
                tSqlChk += "\n AND (HD.FTPmhGetType IN (5,6))";
                tSqlChk += "\n ORDER BY HD.FDPmhDStart DESC";
               
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GETbPmtCoupon] tSqlChk : " + tSqlChk);
                oDbTblPmtActive = cCNSP.SP_SQLoExecute(tSqlChk);

                
                if (oDbTblPmtActive.Rows.Count > 0)
                {
                    //����� Promotion Coupon ��� Active
                    //Get ������ Promotion Coupon ������?�
                    
                    if (W_CHKbCalByPMTCoupon(oDbTblPmtActive))
                    {
                        bSuccess = true;
                    }
                    else
                    {
                        bSuccess = false;
                    }

                }
                else
                {
                    bSuccess = true;   //*Thana 64-07-13  
                    //bSuccess = false;
                    cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GETbPmtCoupon] Promotion Coupon not found ");
                }
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_GETbPmtCoupon] ============  END  ============");
                return bSuccess;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_GETbPmtCoupon] Error : " + ex.Message);
                return false;
            }
        }

        private void C_SETxAllValue()
        {
            try
            {
                cCNVB.tVB_Server = tServer;
                cCNVB.tVB_DB = tDB;
                cCNVB.tVB_DBUserCode = tUser;
                cCNVB.tVB_DBUserPwd = tPwd;
                cCNVB.tVB_BchCode = tBchCode;
                cCNVB.tVB_PosCode = tPosCode;
                cCNVB.tVB_UserCode = tUserCode;
                cCNVB.tVB_UserName = tUserName;
                cCNVB.tVB_LogCode = tLogCode;
                cCNVB.tVB_ShdDocNo = tShdDocNo;
                cCNVB.tVB_ShdDocType = tShdDocType;
                cCNVB.bVB_IsMember = bIsMember;
                cCNVB.dVB_SaleDate = dSaleDate;
                cCNVB.tVB_CNRetVATInOrEx = tRetVATInOrEx;
                cCNVB.cVB_VatRate = cVatRate;

                cCNVB.tVB_TmpHD = "TSHD" + tPosCode;
                cCNVB.tVB_TmpDT = "TSDT" + tPosCode;
                cCNVB.tVB_TmpRC = "TSRC" + tPosCode;
                cCNVB.tVB_TmpPM = "TSPM" + tPosCode;
                cCNVB.tVB_TmpPT = "TSPT" + tPosCode;
                cCNVB.tVB_TmpDP = "TSDP" + tPosCode;
                cCNVB.tVB_TmpPG = "TSPG" + tPosCode;
                cCNVB.tVB_TmpPP = "TSPP" + tPosCode;
                cCNVB.tVB_TmpCD = "TSCD" + tPosCode; //*Tao 63-01-03 ���?���� �?�������??

                cCNSP.SP_SETxDBConfig();
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_SETxAllValue] Error : " + ex.Message);
            }
        }

        //*Tao 63-01-06 Map SpmCode from SpmType
        private string W_GETtSpmCode(int pnSpmType)
        {
            string tResult = "";
            try
            {
                switch (pnSpmType)
                {
                    case 94:
                        tResult = "011";
                        break;
                    case 95:
                        tResult = "012";
                        break;
                    case 96:
                        tResult = "013";
                        break;
                    case 97:
                        tResult = "014";
                        break;
                    case 98:
                        tResult = "015";
                        break;
                    case 99:
                        tResult = "016";
                        break;
                    case 100:
                        tResult = "017";
                        break;
                    case 93:
                        tResult = "018";
                        break;
                    case 92:
                        tResult = "019";
                        break;
                    case 91:
                        tResult = "020";
                        break;
                    default:
                        tResult = pnSpmType.ToString("000");
                        break;
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_GETtSpmCode] Error : " + ex.Message);
                tResult = pnSpmType.ToString("000");
            }
            return tResult;
        }

