        public bool W_CHKbCalByPMTGrpType1()
        {
            //*Tao 62-12-11 �??������� Type 1-11 (���������?�?�� + �?�������??�?�?��?�����������?��? TSDPxxx) 
            //*====== Concept =====*
            //������?�?��� ��?�?�?���? TSDTxxx ���� ��?���?����??��? TPDPxxx �?�?�?�?�������?�� (1 ���)
            //���?��?���? ����������??�?��?�� �����??���� Buy(X), Ret(Y), Get(Z) TSDTxxx => TSPTxxx
            //�?������������ �?����?���������� ��� ������ �����?�?��?������??�?����?��?
            //�?����� �������?? Get(X) ��???��������������?? �?�����?������?�� �?���? TSDTxxx ��� TSDPxxx
            //��???��?? ����������� ��� �����������
            //�?�?��������? �??��?? ��?����?? �������??������ �?������ Buy(X), Ret(Y), Get(Z)
            //*====== ��?�?�? �� =====*
            //*====== Promotion Remark ======*
            //* + �?����?������������������?�����?�������?�?�������� ��������?���?�������� AdaStoreFront ��������?�??��������������?�����?�?� FTPdtNoDis : 1 = ����?, 2 = ���?
            //* + FTSdtVatType : 1 = ��?�? Vat, 2 = ���? Vat
            //* + Table SaleDT �������?�? Vat FCSdtVat ��� FCSdtVatable = 0 : ��?�?�? AdaStoreFront
            //* + �??��???�?����� 
            //*   1. �?�?��?����?�?�?��?
            //*   2. �?�?��?���???�?�?��?
            //*   3. �?�?��?��������?�?��?
            //*====== Promotion Remark ======*

            //double cPriAdjZ_total = 0;      //*Thana 65-07-08   Type 024

            //cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType1] : Start Calculate ");     //*Thana 65-07-05   Type 024
            try
            {
                string tSplCode;
                string tPbnCode;
                string tSql = "";
                bool bType1Success = false;
                bool bChkUpdate = false;
                //*Tao 63-01-03 ����?��???���������?�� 1-11
                oW_SqlDTClearPmt = new StringBuilder();
                oW_SqlDPClearPmt = new StringBuilder();
                oW_SqlCDClearPmt = new StringBuilder();
                oW_SqlDPPmtGroup1 = new StringBuilder();
                oW_SqlDTPmtGroup1 = new StringBuilder();
                oW_SqlCDPmtGroup1 = new StringBuilder();

                oW_SqlDTPmtGroup1_Type3 = new StringBuilder();

                List<string> lsttDT = new List<string>();

                #region Clear Promotion
                W_PRCxClearDPPmt(); //����������?�� TSDPxxx
                W_PRCxClearDTPmt(); //����������?�� TSDTxxx
                W_PRCxClearCDPmt(); //����������?�� TSCDxxx
                W_SQLbExecute(1);
                #endregion Clear Promotion

                nW_CDSeqNo = 0;
                //*Tao 62-12-06 ��? TSPTxxx �??
                tSql = "SELECT * FROM (";
                //*Thana 65-08-02   CFM/2022 - 029 rework
                tSql += "SELECT PT.FTPmhDocNo + CASE WHEN PT.FNSpmType IN ('24','28') THEN '|' + FTPdtCodeX ELSE '' END AS FTPmhDocNo";
                tSql += ", PT.FTPmhName, PT.FDPmhDStart, PT.FDPmhDStop, PT.FDPmhTStart, PT.FDPmhTStop, PT.FNSpmType, FTSpmGetType, FCSpmDisAmt, FCSpmDisPer";
                //tSql += "SELECT PT.FTPmhDocNo, PT.FTPmhName, PT.FDPmhDStart, PT.FDPmhDStop, PT.FDPmhTStart, PT.FDPmhTStop, PT.FNSpmType, FTSpmGetType, FCSpmDisAmt, FCSpmDisPer";
                tSql += "\n ,FTPdtCodeX, FTPdtBarX, FTPdtNameX, FCQtyPmtX, FCAmtPmtX, MAX(FCSpmPriOrgX) AS FCSpmPriOrgX, MAX(FCSpmPriAdjX) AS FCSpmPriAdjX, MAX(FCSpmPriNewX) AS FCSpmPriNewX, SUM(FCSpmQtyKeyX) AS FCSpmQtyKeyX";
                tSql += "\n ,FTPdtCodeY, FTPdtBarY, FTPdtNameY, FCQtyPmtY, FCAmtPmtY, MAX(FCSpmPriOrgY) AS FCSpmPriOrgY, MAX(FCSpmPriAdjY) AS FCSpmPriAdjY, MAX(FCSpmPriNewY) AS FCSpmPriNewY, SUM(FCSpmQtyKeyY) AS FCSpmQtyKeyY";
                tSql += "\n ,FTPdtCodeZ, FTPdtBarZ, FTPdtNameZ, FCQtyPmtZ, FCAmtPmtZ, MAX(FCSpmPriOrgZ) AS FCSpmPriOrgZ, MAX(FCSpmPriAdjZ) AS FCSpmPriAdjZ, MAX(FCSpmPriNewZ) AS FCSpmPriNewZ, SUM(FCSpmQtyKeyZ) AS FCSpmQtyKeyZ";
                tSql += "\n ,MIN(FDSpmTimeIns) AS FDSpmTimeIns, MAX(FNSpmSeqScan) AS FNSpmSeqScan";
                tSql += "\n ,MAX(ISNULL(PmtHD.FTPmhGetType,'')) AS FTPmhGetType";
                tSql += "\n ,MAX(ISNULL(Tier.FTSpmStaInc, '0')) AS FTSpmStaInc, MAX(ISNULL(Tier.FCSpmTier, 0)) AS FCSpmTier"; //*Thana 2026-05-21 Non-Sale Req
                tSql += "\n ,ISNULL((CASE PT.FNSpmType WHEN 9 THEN (CASE MAX(ISNULL(PmtHD.FTPmhGetType,'')) WHEN 1 THEN MAX(FCSpmWQtyDiv) ELSE 0 END) ELSE 0 END),0) AS FCSpmWQtyDiv"; //*Tao 63-03-30 Type9 �������?? ?���� ? �?
                //*Tao 63-03-18 The Best of Best ����??��������?�?��? �??�?��?? ��������?��?
                if (bIsMember)
                {
                    // *Tao 63 - 03 - 12 �������??
                    tSql += "\n ,MAX(FCSpmPriAdjZ + (CASE PT.FNSpmType WHEN 9 THEN (CASE (ISNULL(PmtHD.FTPmhGetType,'')) WHEN 1 THEN (FCSpmWQtyDiv) ELSE 0 END) ELSE 0 END))"; //*Tao 63-03-12 Type9 �������?? ?����        
                }
                else
                {
                    tSql += "\n ,MAX(FCSpmPriAdjZ)"; //*Tao 63-03-12 �������?? 
                }
                //*Tao 63-04-01 ����??�?��� X ��� ����??�?���Y �?���� ��?��??? �?��?�����?��??
                tSql += ("* ISNULL((CASE PT.FNSpmType");
                tSql += "\n WHEN 1 THEN (CASE WHEN FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / (FCQtyPmtX + FCQtyPmtZ)) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN FLOOR(SUM(FCSpmQtyKeyZ) / (CASE WHEN (FTPdtBarX = FTPdtBarZ) THEN (FCQtyPmtX + FCQtyPmtZ) ELSE FCQtyPmtZ END)) ELSE FLOOR(((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / (FCQtyPmtX + FCQtyPmtZ))) END)"; //Type 1: BUY X = 1 GET X = 1
                tSql += "\n WHEN 2 THEN (CASE WHEN FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) / FCQtyPmtX) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) ELSE FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) / FCQtyPmtX) END)"; //Type 2: BUY X = 1 GET Y = 1             
                tSql += "\n WHEN 3 THEN (CASE WHEN FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / (FCQtyPmtX + FCQtyPmtZ)) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN FLOOR(SUM(FCSpmQtyKeyZ) / (CASE WHEN (FTPdtBarX = FTPdtBarZ) THEN (FCQtyPmtX + FCQtyPmtZ) ELSE FCQtyPmtZ END)) ELSE FLOOR(((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / (FCQtyPmtX + FCQtyPmtZ))) END)"; //Type 3: BUY X > 1 GET X = 1
                tSql += "\n WHEN 4 THEN (CASE WHEN FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) / FCQtyPmtX) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) ELSE FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) / FCQtyPmtX) END)"; //Type 4: BUY X > 1 GET Y = 1
                tSql += "\n WHEN 9 THEN (CASE WHEN FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / FCQtyPmtX) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN  FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) ELSE FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / FCQtyPmtX) END)";  //Type 9:    
                //*Thana 65-07-05   Type 24 / Type 28 Non-Sale: per-item discount
                tSql += "\n WHEN 24 THEN (CASE WHEN FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / FCQtyPmtX) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN  FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) ELSE FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / FCQtyPmtX) END)"; 
                tSql += "\n WHEN 28 THEN (CASE WHEN FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / FCQtyPmtX) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN  FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) ELSE FLOOR((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0 AND FCSpmQtyKeyZ > 0) / FCQtyPmtX) END)"; 

                tSql += "\n WHEN 10 THEN FLOOR(CASE FCAmtPmtX WHEN 0 THEN (CASE MAX(ISNULL(PmtHD.FTPmhGetType,'')) WHEN '5' THEN 1 ELSE (((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) + SUM(FCSpmQtyKeyZ)) / (FCQtyPmtX + FCQtyPmtZ)) END) ELSE (CASE MAX(ISNULL(PmtHD.FTPmhGetType,'')) WHEN '5' THEN 1 ELSE (((MAX(FCSpmPriOrgX) * (SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0)) / FCAmtPmtX)) END) END)"; //Type 10 ���??�?� ? �?
                tSql += "\n WHEN 94 THEN FLOOR((CASE MAX(ISNULL(PmtHD.FTPmhGetType,'')) WHEN '5' THEN 1 ELSE (((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) + SUM(FCSpmQtyKeyZ)) / (FCQtyPmtX + FCQtyPmtZ)) END))"; //Type 11 ���??�?? ? ���
                tSql += "\n WHEN 22 THEN (CASE WHEN FLOOR(((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) + (SELECT SUM(FCSpmQtyKeyY) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FCSpmQtyKeyY > 0)) / (FCQtyPmtX + FCQtyPmtY)) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN  FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) ELSE FLOOR(((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) + (SELECT SUM(FCSpmQtyKeyY) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FCSpmQtyKeyY > 0)) / (FCQtyPmtX + FCQtyPmtY)) END)";

                tSql += "\n ELSE (CASE WHEN FLOOR(((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) + (SELECT SUM(FCSpmQtyKeyY) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FCSpmQtyKeyY > 0)) / (FCQtyPmtX + FCQtyPmtY)) >= FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) THEN FLOOR(SUM(FCSpmQtyKeyZ) / FCQtyPmtZ) ELSE FLOOR(((SELECT SUM(FCSpmQtyKeyX) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo=PT.FTPmhDocNo AND FCSpmQtyKeyX > 0) + (SELECT SUM(FCSpmQtyKeyY) FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FCSpmQtyKeyY > 0)) / (FCQtyPmtX + FCQtyPmtY)) END)"; //Type 5,6,7,8:
                tSql += "\n END),0) AS FCSpmTotalPriAdj"; //�����?�??��??�?�?��?�?� (�������???��??...�?���?�)
                tSql += "\n ,PmtHD.FTSplCode, PmtHD.FTPbnCode"; //Krisana 2025-06-17 CFR ? POS Promotion Type 3_Buy Product (Same Group) more than 1 item get X% and X Baht
                tSql += "\n FROM " + cCNVB.tVB_TmpPT + " PT WITH(NOLOCK) ";

                tSql += "\n INNER JOIN TCNTPdtPmtHD PmtHD WITH(NOLOCK) ";
                tSql += "\n ON PT.FTPmhDocNo = PmtHD.FTPmhDocNo ";

                tSql += "\n LEFT JOIN TSysPmtTier Tier WITH(NOLOCK) "; //*Thana 2026-05-21 Non-Sale Req
                tSql += "\n ON PT.FNSpmType = Tier.FNSpmType AND PT.FTSpmGetType = Tier.FTPmcGetType "; //*Thana 2026-05-21 Non-Sale Req

                //*Thana 65-07-05   Type 024
                //tSql += "\n WHERE PT.FNSpmType IN (" + cCNCS.tCS_PMTGrpType1 + ")";
                if (bIsMember)
                {
                    tSql += "\n WHERE PT.FNSpmType IN (" + cCNCS.tCS_PMTGrpType1 + ")";   
                }
                else
                {
                    tSql += "\n WHERE ((PT.FNSpmType IN (" + cCNCS.tCS_PMTGrpType1_not24 + ")) OR (PT.FNSpmType = '24' and ISNULL(PmtHD.FTPmhStaJob,'2') = '2') OR (PT.FNSpmType = '28'))";
                }
