                tSql += "\n WHERE D.FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "' ";
                tSql += "\n   AND D.FTSdtBarCode IN( ";
                tSql += "\n         PT.FTPdtBarX, ";
                tSql += "\n         PT.FTPdtBarY, ";
                tSql += "\n         PT.FTPdtBarZ ";
                tSql += "\n   ) ";
                tSql += "\n ) ";

                tSql += "\n GROUP BY PT.FTPmhDocNo, PT.FDPmhDStart, PT.FTPmhName, PT.FDPmhDStop, PT.FDPmhTStart, PT.FDPmhTStop, PT.FNSpmType, FTSpmGetType, FCSpmDisAmt, FCSpmDisPer";
                tSql += "\n ,FTPdtCodeX, FTPdtBarX, FTPdtNameX, FCQtyPmtX, FCAmtPmtX";
                tSql += "\n ,FTPdtCodeY, FTPdtBarY, FTPdtNameY, FCQtyPmtY, FCAmtPmtY";
                tSql += "\n ,FTPdtCodeZ, FTPdtBarZ, FTPdtNameZ, FCQtyPmtZ, FCAmtPmtZ";
                tSql += "\n ,PmtHD.FTSplCode, PmtHD.FTPbnCode";     //Krisana 2025-06-17 CFR ? POS Promotion Type 3_Buy Product (Same Group) more than 1 item get X% and X Baht
                tSql += ")xxx";
                tSql += "\n WHERE FCSpmQtyKeyX > 0 ";
                tSql += "\n AND FCSpmQtyKeyZ > 0";

                tSql += "\n ORDER BY FTSpmStaInc ASC, FCSpmTier DESC, FCSpmTotalPriAdj DESC, FCSpmPriAdjZ DESC, FCSpmQtyKeyZ DESC, FCSpmQtyKeyX, FCSpmQtyKeyY"; //*Thana 2026-05-21 Non-Sale Req
                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType1] tSql : " + tSql);
