                            //cCNSP.SP_ADDxLog("LogPmtPrc", "[Thana check >> 3.33]");       //*Thana 65-07-05   Type 024
                            //cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType1] Thana Check 2");     //*Thana 65-07-05   Type 024
                            if (oW_SqlDPPmtGroup1.Length > 0) { W_PRCxClearDPPmt(); } //����������?�� TSDPxxx
                            if (oW_SqlDTPmtGroup1.Length > 0) { W_PRCxClearDTPmt(); } //����������?�� TSDTxxx
                            if (oW_SqlCDPmtGroup1.Length > 0) { W_PRCxClearCDPmt(); } //����������?�� TSCDxxx
                            if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                            {
                                W_SQLbExecute_ProType3();
                                //cCNSP.SP_ADDxLog("LogPmtPrc", "[Thana check >> 3.34] ");       //*Thana 65-07-05   Type 024
                                bType1Success = true;
