                                //cCNSP.SP_ADDxLog("LogPmtPrc", "[Thana check >> 3.35] ");       //*Thana 65-07-05   Type 024
                                bType1Success = false;
                            }
                        }
                        else
                        {
                            //cCNSP.SP_ADDxLog("LogPmtPrc", "[Thana check >> 3.36] ");       //*Thana 65-07-05   Type 024
                            //cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType1] : call W_PRCxClearDPPmt DTPmt CDPmt");  //*Thana 64-12-22   CFM/2021 - 083
                            //*Tao 63-02-07 ��������������� ��������������
                            W_PRCxClearDPPmt(); //����������?�� TSDPxxx
                            W_PRCxClearDTPmt(); //����������?�� TSDTxxx
                            W_PRCxClearCDPmt(); //����������?�� TSCDxxx
                            if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                            {
                                W_SQLbExecute_ProType3();
                                bType1Success = true;
                            }
                            else
                            {
                                bType1Success = false;
                            }
                        }
                    }
                
                    //*Thana 64-12-22   CFM/2021 - 083
                    else
                    {
                        //cCNSP.SP_ADDxLog("LogPmtPrc", "[Thana check >> 3.37] ");       //*Thana 65-07-05   Type 024
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType1] : call W_PRCxClearDTPmt - Start");
                        //*Tao 63-02-07 ��������������� ��������������
