                        W_PRCxClearDTPmt(); //����������?�� TSDTxxx
                        W_PRCxClearCDPmt(); //����������?�� TSCDxxx
                        if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                        {
                            W_SQLbExecute_ProType3();
                            bType1Success = true;
                        }
                        else
                        {
                            bType1Success = false;
                        }
                        cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType1] : call W_PRCxClearDTPmt - End");
                    }
                    //*Thana 64-12-22   CFM/2021 - 083
                }
                return bType1Success;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_CHKxCalByPMTGrpType1] Error : " + ex.Message);
                return false;
            }
        }

        //*== Function ���?��?���? Update ��?�? ���?�?������?�����������
        private static void W_PRCxClearDTPmt()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "======= W_PRCxClearDTPmt ======");
                //���?��?���? Update ��?���?�?����������������
                string tSql = "";
                tSql = "SELECT FNSdtSeqNo, FTSdtVatType, FCSdtQty, FCSdtB4DisChg, FTShdVATInOrEx";
                tSql += "\n FROM " + cCNVB.tVB_TmpDT + " WITH(NOLOCK)";
                //tSql += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "' AND FCSdtPmtQtyGet > 0 AND FTSdtStaPdt = '1'";
                tSql += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "' AND FTSdtStaPdt = '1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                tSql += "\n ORDER BY FNSdtSeqNo";
                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_PRCxClearDTPmt] tSql : " + tSql);
                using (DataTable oDbTbl = cCNSP.SP_SQLoExecute(tSql))
                {
                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_PRCxClearDTPmt] oDbTbl.Rows.Count : " + oDbTbl.Rows.Count);
                    if (oDbTbl.Rows.Count > 0)
                    {
                        int nSeqNo = 0;
                        string tVatType, tVATInOrEx;
                        double cQty = 0, cPrice = 0, cVat = 0, cVatable = 0;
                        string tSqlUpDT = "";
                        oW_SqlDTClearPmt = new StringBuilder();
                        for (int i = 0; i < oDbTbl.Rows.Count; i++)
                        {
                            nSeqNo = int.Parse(oDbTbl.Rows[i]["FNSdtSeqNo"].ToString());
                            tVatType = oDbTbl.Rows[i]["FTSdtVatType"].ToString();
                            cQty = double.Parse(oDbTbl.Rows[i]["FCSdtQty"].ToString());
                            cPrice = double.Parse(oDbTbl.Rows[i]["FCSdtB4DisChg"].ToString());
                            tVATInOrEx = oDbTbl.Rows[i]["FTShdVATInOrEx"].ToString();
                            cVat = (tVatType == "1" ? cCNSP.SP_CALcVatValue((tVATInOrEx == "1" ? false : true), cPrice, cCNPM.cPM_VatRate) : 0);
                            cVatable = ((tVatType == "1") ? cPrice - cVat : 0);  //1:vat, 2:novat (0)
                            tSqlUpDT = "UPDATE " + cCNVB.tVB_TmpDT + " WITH(ROWLOCK)";
                            tSqlUpDT += "\n SET FTSdtDisChgTxt = '', FCSdtDis = 0, FCSdtChg = 0, FCSdtNet = FCSdtB4DisChg, FCSdtVat = " + String.Format("{0:F2}", cVat) + ", FCSdtVatable = " + String.Format("{0:F2}", cVatable) + ", FCSdtPmtQtyGet = 0 ";
                            tSqlUpDT += "\n ,FTSdtPmhCpnDocNo = '', FCSdtPmhCpnGetQty = 0, FCSdtPmhCpnValue = 0, FCSdtDisGP = 0, FTPmhCode = '', FTPmhType = 0"; //Clear All Promotion Group2 (������?��?��)
                            //tSqlUpDT += "\n ,FTPdtName = CASE WHEN LEFT(FTPdtName, 1) = '*' THEN SUBSTRING(FTPdtName, 2, LEN(FTPdtName)) ELSE FTPdtName END";
                            //tSqlUpDT += "\n ,FTPmhCode = '',FTPmhType = ''"; //Clear All Promotion
                            tSqlUpDT += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "' AND FNSdtSeqNo = " + nSeqNo + ";";
                            cCNSP.SP_ADDxLog("LogPmtPrc", "[W_PRCxClearDTPmt] tSqlUpDT : " + tSqlUpDT);
                            oW_SqlDTClearPmt.AppendLine(tSqlUpDT);
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_PRCxClearDTPmt] Error : " + ex.Message);
            }
        }

        //*Tao 63-01-03 ��?����������� TSDPxxx ��?�?�� UPDATE ����
        private static void W_PRCxClearDPPmt()
        {
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "======= W_PRCxClearDPPmt ======");
