                tSql += "\n , FTDtpPmhBillDocNo = '', FTDtpPmhCpnDocNo = '', FCDtpPmhCpnGetQty = 0, FCDtpPmhCpnValue = 0, FCDtpDisGP = 0"; //Clear All Promotion Group2 (������?��?��)
                tSql += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                tSql += "\n AND FNSpmType IN (0," + cCNCS.tCS_PMTGrpType1 + ");"; // SpmType 0 = ��?? �? / ��?? % (����?����)
                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_PRCxClearDPPmt] tSql : " + tSql);
