                                                    : pnSeqDTPmtRef[0]);

                                    tSqlUpDP += "\n , FNDtpQtyPmtX = 1, FNDtpQtyPmtGetX = 1, FNDtpQtyPmtLeftX = 0"; //*Tao 62-12-09 ������ ������������ Export
                                    tSqlUpDP += "\n WHERE FNDtpSeqNo = " + nDPSeqNo;
                                    tSqlUpDP += "\n AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';"; //*Tao 62-12-04 ���� Seq Scan
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_PRCxUpdDPGetPro [X] : " + pnPmtType + "] tSqlUpDP : " + tSqlUpDP);
                                    oW_SqlDPPmtGroup1.AppendLine(tSqlUpDP);
                                    nW_CDSeqNo += 1;
                                    C_PRCbSavePmtDP2CD(nW_CDSeqNo, nDPSeqNo); //*Tao 63-01-03 �?�������??������������
                                    W_PRCxUpdateUsedSeq(pnPmtType, nDPSeqNo, pbStaInc); //*Thana 2026-05-22 Non-Sale Req
                                    cSumNetGetPro = cSumNetGetPro - cPdtNet;
                                    if (cSumNetGetPro == 0 || cSumNetGetPro < 0)
                                    {
                                        iX = oDbTblDP.Rows.Count;
                                    }
                                }
                            }
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_PRCxUpdDPGetPro] Error : " + ex.Message);
            }
        }

