                {
                    oDbCon.Open();
                    SqlCommand oDbCmd = new SqlCommand();
                    oDbCmd.CommandType = CommandType.Text;
                    SqlTransaction oDbTrans = oDbCon.BeginTransaction();
                    oDbCmd.Connection = oDbCon;
                    oDbCmd.Transaction = oDbTrans;

                    try
                    {
                        switch (pnPmtGroup)
                        {
