                                {
                                    oDbCmd.CommandText = oW_SqlDPPmtGroup1.ToString();
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] SqlDPPmtGroup1 : " + oW_SqlDPPmtGroup1.ToString());
                                    oDbCmd.ExecuteNonQuery();
                                }
                                if (oW_SqlCDClearPmt.Length > 0)
                                {
                                    oDbCmd.CommandText = oW_SqlCDClearPmt.ToString();
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] SqlCDClearPmt : " + oW_SqlCDClearPmt.ToString());
                                    oDbCmd.ExecuteNonQuery();
                                }
                                if (oW_SqlCDPmtGroup1.Length > 0)
                                {
                                    oDbCmd.CommandText = oW_SqlCDPmtGroup1.ToString();
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] SqlCDPmtGroup1 : " + oW_SqlCDPmtGroup1.ToString());
                                    oDbCmd.ExecuteNonQuery();
                                }

                                // Attempt to commit the transaction.
                                oDbTrans.Commit();
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] Commit ");
                                oW_SqlDTClearPmt.Length = 0;
                                oW_SqlDTPmtGroup1.Length = 0;
                                oW_SqlDPClearPmt.Length = 0;
                                oW_SqlDPPmtGroup1.Length = 0;
                                oW_SqlCDClearPmt.Length = 0;
                                oW_SqlCDPmtGroup1.Length = 0;
                                break;
                            case 2: //������?��?��
                                if (oW_SqlHDPmtGroup2.Length > 0)
                                {
                                    oDbCmd.CommandText = oW_SqlHDPmtGroup2.ToString();
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] SqlHDPmtGroup2 : " + oW_SqlHDPmtGroup2.ToString());
                                    oDbCmd.ExecuteNonQuery();

                                }
                                if (oW_SqlDTPmtGroup2.Length > 0)
                                {
                                    oDbCmd.CommandText = oW_SqlDTPmtGroup2.ToString();
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] SqlDTPmtGroup2 : " + oW_SqlDTPmtGroup2.ToString());
                                    oDbCmd.ExecuteNonQuery();
                                }
                                if (oW_SqlRCPmtGroup2.Length > 0)
                                {
                                    oDbCmd.CommandText = oW_SqlRCPmtGroup2.ToString();
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] SqlRCPmtGroup2 : " + oW_SqlRCPmtGroup2.ToString());
                                    oDbCmd.ExecuteNonQuery();
                                }
                                if (oW_SqlDPPmtGroup2.Length > 0)
                                {
                                    oDbCmd.CommandText = oW_SqlDPPmtGroup2.ToString();
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] SqlDPPmtGroup2 : " + oW_SqlDPPmtGroup2.ToString());
                                    oDbCmd.ExecuteNonQuery();
                                }
                                if (oW_SqlCDPmtGroup2.Length > 0)
                                {
                                    oDbCmd.CommandText = oW_SqlCDPmtGroup2.ToString();
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] SqlCDPmtGroup2 : " + oW_SqlCDPmtGroup2.ToString());
                                    oDbCmd.ExecuteNonQuery();
                                }
                                // Attempt to commit the transaction.
                                oDbTrans.Commit();
                                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_SQLbExecute] Commit ");
                                oW_SqlHDPmtGroup2.Length = 0;
                                oW_SqlDTPmtGroup2.Length = 0;
                                oW_SqlRCPmtGroup2.Length = 0;
                                oW_SqlDPPmtGroup2.Length = 0;
                                oW_SqlCDPmtGroup2.Length = 0;
                                break;
                            default:
                                break;
                        }
                        return true;
                    }
                    catch (SqlException exSql)
                    {
                        cCNSP.SP_ADDxLog("LogPmtErr", "[PM_SQLbExecute] Error : " + exSql.Message);
                        cCNSP.SP_ADDxLog("LogPmtErr", "[PM_SQLbExecute] Commit Exception Type : " + exSql.GetType());
                        // Attempt to roll back the transaction.
                        try
                        {
                            oDbTrans.Rollback();
                            cCNSP.SP_ADDxLog("LogPmtPrc", "[PM_SQLbExecute] Rollback ");
                        }
                        catch (Exception ex2)
                        {
                            cCNSP.SP_ADDxLog("LogPmtErr", "[PM_SQLbExecute] Error : " + ex2.Message);
                            cCNSP.SP_ADDxLog("LogPmtErr", "[PM_SQLbExecute] Rollback Exception Type : " + ex2.GetType());
                        }
                        switch (pnPmtGroup)
                        {
                            case 1: //���������?��
                                oW_SqlDTClearPmt.Length = 0;
                                oW_SqlDTPmtGroup1.Length = 0;
                                oW_SqlDPClearPmt.Length = 0;
                                oW_SqlDPPmtGroup1.Length = 0;
                                oW_SqlCDClearPmt.Length = 0;
                                oW_SqlCDPmtGroup1.Length = 0;
                                break;
                            case 2: //������?��?��
                                oW_SqlHDPmtGroup2.Length = 0;
                                oW_SqlDTPmtGroup2.Length = 0;
                                oW_SqlRCPmtGroup2.Length = 0;
                                oW_SqlDPPmtGroup2.Length = 0;
                                oW_SqlCDPmtGroup2.Length = 0;
                                break;
                            default:
                                break;
                        }
                        return false;
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[PM_SQLbExecute] Error : " + ex.Message);
                switch (pnPmtGroup)
                {
                    case 1: //���������?��
                        oW_SqlDTClearPmt.Length = 0;
                        oW_SqlDTPmtGroup1.Length = 0;
                        oW_SqlDPClearPmt.Length = 0;
                        oW_SqlDPPmtGroup1.Length = 0;
                        oW_SqlCDClearPmt.Length = 0;
                        oW_SqlCDPmtGroup1.Length = 0;
                        break;
                    case 2: //������?��?��
                        oW_SqlHDPmtGroup2.Length = 0;
                        oW_SqlDTPmtGroup2.Length = 0;
                        oW_SqlRCPmtGroup2.Length = 0;
                        oW_SqlDPPmtGroup2.Length = 0;
                        oW_SqlCDPmtGroup2.Length = 0;
                        break;
                    default:
                        break;
                }
                return false;
            }
        }

