        #region Calculate Promotion Coupon
        public bool W_CHKbCalByPMTCoupon(DataTable poDbTbl)
        {
            string tStatus = "";
            try
            {
                //*Zen
                //FTPmhGetType 5 = 1 ��� 1 �??
                //FTPmhGetType 6 = 1 ��� ���???
                //FTSplCode �����?�
                //PdtCondi ���?� �?��� 1 �?���������?�� 0 �?��?�������?��
                //PdtGrp ���?� �?��� 1 �?���������?�� 0 �?��?�������?��
                SqlCommand oDbCmd = new SqlCommand();
                SqlConnection oDbCon = new SqlConnection(cCNVB.tVB_ConStr);
                oDbCon.Open();
                oDbCmd.Parameters.Add(new SqlParameter("ptPosCode", SqlDbType.VarChar, 5)).Value = cCNVB.tVB_PosCode;
                oDbCmd.Parameters.Add(new SqlParameter("ptBchCode", SqlDbType.VarChar, 5)).Value = cCNVB.tVB_BchCode;
                oDbCmd.Parameters.Add(new SqlParameter("pdSaleDate", SqlDbType.DateTime)).Value = cCNVB.dVB_SaleDate.ToString("yyyy-MM-dd");
                oDbCmd.Parameters.Add(new SqlParameter("ptShdDocNo", SqlDbType.VarChar, 20)).Value = cCNVB.tVB_ShdDocNo;
                if (cCNVB.bVB_IsMember)
                {
                    oDbCmd.Parameters.Add(new SqlParameter("ptIsMember", SqlDbType.VarChar, 1)).Value = "1" ;
                }
                else
                {
                    oDbCmd.Parameters.Add(new SqlParameter("ptIsMember", SqlDbType.VarChar, 1)).Value = "2" ;
                }
                oDbCmd.Parameters.Add(new SqlParameter("ptResult", SqlDbType.VarChar,50)).Direction = ParameterDirection.Output;
                oDbCmd.Connection = oDbCon;
                oDbCmd.CommandText = "STP_PRCtPromotionCpn";
                oDbCmd.CommandType = CommandType.StoredProcedure;

                oDbCmd.ExecuteNonQuery();

                tStatus = oDbCmd.Parameters["ptResult"].Value.ToString();
                if (tStatus == "Success")
                {
                    return true;
                }
                else
                {
                    cCNSP.SP_ADDxLog("LogPmtErr", "[W_CHKbCalByPMTCoupon] Error : " + tStatus);
                    return false;
                }


                
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_CHKxCalByPMTGrpType1] Error : " + ex.Message);
                return false;
            }
        }
