        public bool W_CHKbCalByPMTGrpType25()
        {
            try
            {
                #region Variable
                string tSql = "";
                string tSqlDT = "";                
                string tSqlDPSum = "";
                string tSqlUpDT = "";
                string tSqlUpDP = "";

                bool bType25Success = true;
                bool bChkPmt25 = false;
                bool bChkPdtPmt = false;
                bool bChkPdtinPmt = false;
                bool bChkDupPmt = false;
                var oTblTmpPT = new DataTable();
                //var oTblTmpDT = new DataTable();
                var oTblTmpDP = new DataTable();

                string tPmtCode = "";
                string tPmhGetType = "";
                string tPmcGetType = "";
                string tGetType = "";
                string tPdtCodeX = "";
                string tPmtCodeGetPro = "";
                string tlstPmtSeqNo = "";
                string tlstDPSeqNo = "";
                
                int nPmtTypeGetPro;
                int nPmtType;
                int nPdtCount;
                int nSumSeqNoRef;

                double cPmtMaxDiscount;
                double cPmtDiscount;
                double cQtyPmt;
                double cQtyPdtPmt;
                double cSumB4DisChg;
                double cSumDiscount;
                double cMaxPdt;
                double cMaxinPdt;

                string tSeqNoRef;

                List<string> lsttPmtSeqNo = new List<string>();      //�� FNSdtSeqNo ������������ Type 25 �����
                List<string> lsttDPSeqNo = new List<string>(); 

                //����?��???���������?��
                oW_SqlDTClearPmt = new StringBuilder();
                oW_SqlDPClearPmt = new StringBuilder();
                oW_SqlCDClearPmt = new StringBuilder();
                oW_SqlDPPmtGroup1 = new StringBuilder();
                oW_SqlDTPmtGroup1 = new StringBuilder();
                oW_SqlCDPmtGroup1 = new StringBuilder();
                nW_CDSeqNo = 0;
                cPmtMaxDiscount = 0.0;
                bChkPmt25 = false;
                bChkPdtPmt = false;
                tPmtCode = "";
                tPmtCodeGetPro = "";
                cQtyPdtPmt = 0;
                nPmtTypeGetPro = 0;
                #endregion Variable

                //��?����?�?��� = 1, �?�??�� = 7
                int pdToday = (int)DateTime.Now.DayOfWeek; // Sunday = 0, Monday = 1, ..., Saturday = 6

                // ��?��� Monday = 1, Sunday = 7
                pdToday = (pdToday + 6) % 7 + 1;

                #region SQL Check Promotion

                tSql = "DECLARE @Now DATETIME = GETDATE(); ";
                tSql += "\n DECLARE @NowDate DATE = CAST(@Now AS DATE); ";
                tSql += "\n DECLARE @NowTime TIME = CAST(@Now AS TIME); ";

                tSql += "\n SELECT * FROM (";
                tSql += "\n SELECT PT.FTPmhDocNo";
                tSql += "\n  , PT.FTPmhName, PT.FDPmhDStart, PT.FDPmhDStop, PT.FDPmhTStart, PT.FDPmhTStop, PT.FNSpmType, FTSpmGetType, FCSpmDisAmt, FCSpmDisPer, FCQtyPmtZ";
                tSql += "\n    ,FTPdtCodeX, FTPdtBarX, FTPdtNameX, FCQtyPmtX, FCAmtPmtX, MAX(FCSpmPriOrgX) AS FCSpmPriOrgX, MAX(FCSpmPriAdjX) AS FCSpmPriAdjX, MAX(FCSpmPriNewX) AS FCSpmPriNewX, SUM(FCSpmQtyKeyX) AS FCSpmQtyKeyX";
                //tSql += "\n    , FTPdtCodeY, FTPdtBarY, FTPdtNameY, FCQtyPmtY, FCAmtPmtY, MAX(FCSpmPriOrgY) AS FCSpmPriOrgY, MAX(FCSpmPriAdjY) AS FCSpmPriAdjY, MAX(FCSpmPriNewY) AS FCSpmPriNewY, SUM(FCSpmQtyKeyY) AS FCSpmQtyKeyY";
                //tSql += "\n     , FTPdtCodeZ, FTPdtBarZ, FTPdtNameZ, FCQtyPmtZ, FCAmtPmtZ, MAX(FCSpmPriOrgZ) AS FCSpmPriOrgZ, MAX(FCSpmPriAdjZ) AS FCSpmPriAdjZ, MAX(FCSpmPriNewZ) AS FCSpmPriNewZ, SUM(FCSpmQtyKeyZ) AS FCSpmQtyKeyZ";
                tSql += "\n      , MIN(FDSpmTimeIns) AS FDSpmTimeIns, MAX(FNSpmSeqScan) AS FNSpmSeqScan";
                tSql += "\n       , MAX(ISNULL(PmtHD.FTPmhGetType, '')) AS FTPmhGetType";
                tSql += "\n       , MAX(ISNULL(Tier.FTSpmStaInc, '0')) AS FTSpmStaInc, MAX(ISNULL(Tier.FCSpmTier, 0)) AS FCSpmTier"; //*Thana 2026-05-22 Non-Sale Req
                //tSql += "\n        , ISNULL((CASE PT.FNSpmType WHEN 9 THEN(CASE MAX(ISNULL(PmtHD.FTPmhGetType, '')) WHEN 1 THEN MAX(FCSpmWQtyDiv) ELSE 0 END) ELSE 0 END),0) AS FCSpmWQtyDiv";
                tSql += "\n         , FCQtyPmtZ AS FCSpmTotalPriAdj, PmtCD.FTPmcGetType";
                //tSql += "\n   FROM " + cCNVB.tVB_TmpPT + " PT WITH(NOLOCK), TCNTPdtPmtHD PmtHD WITH(NOLOCK), TCNTPdtPmtCD PmtCD WITH(NOLOCK) ";

                tSql += "\n   FROM " + cCNVB.tVB_TmpPT + " PT WITH(NOLOCK) ";
                tSql += "\n   INNER JOIN TCNTPdtPmtHD PmtHD WITH(NOLOCK) ";
                tSql += "\n       ON PT.FTPmhDocNo = PmtHD.FTPmhDocNo ";
                tSql += "\n   INNER JOIN TCNTPdtPmtCD PmtCD WITH(NOLOCK) ";
                tSql += "\n       ON PT.FTPmhDocNo = PmtCD.FTPmhDocNo ";
                tSql += "\n   LEFT JOIN TSysPmtTier Tier WITH(NOLOCK) "; //*Thana 2026-05-22 Non-Sale Req
                tSql += "\n       ON PT.FNSpmType = Tier.FNSpmType AND PT.FTSpmGetType = Tier.FTPmcGetType "; //*Thana 2026-05-22 Non-Sale Req

                tSql += "\n   WHERE (PT.FNSpmType = 25)";
                tSql += "\n   AND PT.FTPmhDocNo = PmtHD.FTPmhDocNo";
                tSql += "\n   AND PT.FTPmhDocNo=PmtCD.FTPmhDocNo  AND PT.FTPdtBarX=PmtCD.FTPmdBarCodeBuy  ";
                tSql += "\n   AND FCQtyPmtZ > 0";
                //tSql += "\n   AND(CAST(GETDATE() AS DATE) BETWEEN CAST(PT.FDPmhDStart AS DATE) AND CAST(PT.FDPmhDStop AS DATE))";
                //tSql += "\n   AND(CAST(GETDATE() AS TIME)) BETWEEN CAST(PT.FDPmhTStart AS TIME) AND CAST(PT.FDPmhTStop AS TIME)";

                tSql += "\n AND @Now >= PT.FDPmhDStart ";
                tSql += "\n AND @Now<DATEADD(DAY, 1, PT.FDPmhDStop) ";

                tSql += "\n AND CAST(@Now AS TIME) ";
                tSql += "\n BETWEEN CAST(PT.FDPmhTStart AS TIME) ";
                tSql += "\n AND CAST(PT.FDPmhTStop AS TIME) ";

                tSql += "\n   AND ((SUBSTRING(';' + PmtHD.FTPgpChain + ';', (" + pdToday + " * 2), 1) = '1' OR (PmtHD.FTPgpChain is null) OR (PmtHD.FTPgpChain = '')))	";

                tSql += "\n AND( ";
                tSql += "\n       CASE ";
                tSql += "\n           WHEN PT.FTSpmGetType IN (1, 2, 3) AND PT.FCSpmDisAmt > 0 THEN 1 ";
                tSql += "\n           WHEN PT.FTSpmGetType = 4          AND PT.FCSpmDisPer > 0 THEN 1 ";
                tSql += "\n           ELSE 0 ";
                tSql += "\n       END ";
                tSql += "\n       ) = 1 ";

                /* ��?�� barcode ���?���� 1 ��� ����?�� */
                tSql += "\n AND EXISTS( ";
                tSql += "\n SELECT 1 ";
                tSql += "\n FROM " + cCNVB.tVB_TmpDT + " D WITH(NOLOCK) ";
                tSql += "\n WHERE D.FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "' ";
                tSql += "\n   AND D.FTSdtBarCode IN ( PT.FTPdtBarX ) ";
                tSql += "\n ) ";

                tSql += "\n    GROUP BY PT.FTPmhDocNo, PT.FDPmhDStart, PT.FTPmhName, PT.FDPmhDStop, PT.FDPmhTStart, PT.FDPmhTStop, PT.FNSpmType, FTSpmGetType, FCSpmDisAmt, FCSpmDisPer";
                tSql += "\n   ,FTPdtCodeX, FTPdtBarX, FTPdtNameX, FCQtyPmtX, FCAmtPmtX";
                tSql += "\n    ,FTPdtCodeY, FTPdtBarY, FTPdtNameY, FCQtyPmtY, FCAmtPmtY";
                tSql += "\n   ,FTPdtCodeZ, FTPdtBarZ, FTPdtNameZ, FCQtyPmtZ, FCAmtPmtZ, PmtCD.FTPmcGetType";
