                                        if (lsttDPSeqNo.Count > 0 && tlstDPSeqNo.Trim().Length > 0) { tSqlDT += "\n  AND FNDtpSeqNo NOT IN (" + tlstDPSeqNo + ")"; }
                                        tSqlDT += "\n  AND FTDtpBarCode IN (SELECT FTPmdBarCodeBuy";
