                                                    tSqlUpDP = "UPDATE " + cCNVB.tVB_TmpDP + " WITH(ROWLOCK)";
                                                    tSqlUpDP += "\n SET FTPmhDocNo = '" + tPmtCodeGetPro + "', FNSpmType = " + nPmtTypeGetPro + ", FCDtpDis = " + string.Format("{0:F2}", cDis);
                                                    tSqlUpDP += "\n , FTDtpStaGetPmt = '3', FCDtpPmtQtyGet = 1";    //*Tao 62-12-06 �?����?����������� (FTDtpStaGetPmt 0:None, 1:������?���� 1 (1-11) ��?�� (DT), 2:������?���� 1 (1-11) ������� (CO), 3: ���?�������, 4:���?������?��������?��, FCDtpPmtQtyGet=�??�?��?�����?��??�������)
                                                    tSqlUpDP += "\n , FNDtpSdtSeqNoRef = " + nSdtSeqNoRef + ", FNDtpQtyPmtX = 0, FNDtpQtyPmtGetX = 0, FNDtpQtyPmtLeftX = 0";    // ������ ������������ Export

                                                    tSqlUpDP += "\n WHERE FNDtpSeqNo = " + nDPSeqNo;
                                                    tSqlUpDP += "\n AND FNSdtSeqNo = " + nDTSeqNo + " AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType25 : " + nPmtTypeGetPro + "] tSqlUpDP : " + tSqlUpDP);
                                                    oW_SqlDPPmtGroup1.AppendLine(tSqlUpDP);
                                                    nW_CDSeqNo += 1;
                                                    C_PRCbSavePmtDP2CD(nW_CDSeqNo, nDPSeqNo); //�?�������??������������
                                                    W_PRCxUpdateUsedSeq(nPmtType, nDPSeqNo, (oTblTmpPT.Rows[i]["FTSpmStaInc"].ToString() == "1")); //*Thana 2026-05-22 Non-Sale Req
                                                    if (oTblTmpPT.Rows[i]["FTSpmStaInc"].ToString() != "1") 
                                                    {
                                                        W_AddxDatatoList(ref lsttPmtSeqNo, nDPSeqNo.ToString()); //*Thana 2026-05-22 Non-Sale Req
                                                    }
                                                }

                                                tSeqNoRef = string.Join(",", lsttSeqNoRef.ToArray());

                                                //Clear Promotion ����������??
                                                W_PRCxClearTempDTPmt25_27(tSeqNoRef); //����������?�� TSDTxxx
                                                W_PRCxClearTempDPPmt25_27(tSeqNoRef); //����������?�� TSDPxxx
                                                W_PRCxClearTempCDPmt25_27(tSeqNoRef); //����������?�� TSCDxxx

                                                if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                                                {
                                                    //�?�?��??�??��??��?�� ?���? TSDTxxx
                                                    if (lsttSeqNo.Count > 0)
                                                    {
                                                        for (int n = 0; n < lsttSeqNo.Count; n++)
                                                        {
                                                            string[] aDTDetail = lsttSeqNo[n].Split('|');
                                                            nSeqNo = int.Parse(aDTDetail[0]);
                                                            tVATInOrEx = aDTDetail[1];
                                                            tVatType = aDTDetail[2];

                                                            tSql = "SELECT SUM(FCDtpNet) AS FCDtpNet_SUM, SUM(FCDtpDis) AS FCDtpDis_SUM";
                                                            tSql += "\n  FROM " + cCNVB.tVB_TmpDP + " WITH(NOLOCK)";
                                                            tSql += "\n  WHERE FNSdtSeqNo = " + nSeqNo.ToString();
                                                            tSql += "\n  AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                                                            tSql += "\n  GROUP BY FTShdDocNo,FNSdtSeqNo";

                                                            using (DataTable oDbTblDTx = cCNSP.SP_SQLoExecute(tSql))
                                                            {
                                                                if (oDbTblDTx.Rows.Count > 0)
                                                                {

                                                                    #region Cal Discount by Pro. rate
                                                                    //�??��??��� Pro Rate
                                                                    cNetB4Dis = double.Parse(oDbTblDTx.Rows[0]["FCDtpNet_SUM"].ToString());
                                                                    cDis = double.Parse(oDbTblDTx.Rows[0]["FCDtpDis_SUM"].ToString());


                                                                    if (cDis == 0)
                                                                    {
                                                                        tDisChgTxt = "";
                                                                    }
                                                                    else if (cDis < 0)
                                                                        tDisChgTxt = String.Format("{0:F2}", (cDis * -1));
                                                                    else
                                                                    {
                                                                        tDisChgTxt = "-" + String.Format("{0:F2}", cDis);
                                                                    }
                                                                    cNet = cNetB4Dis - cDis; //�?��?����?�?�?������� = �??�?? - �??����?
                                                                    cVat = (tVatType == "1" ? cCNSP.SP_CALcVatValue((tVATInOrEx == "1" ? false : true), cNet, cCNVB.cVB_VatRate) : 0);
                                                                    cVatable = ((tVatType == "1") ? cNet - cVat : 0);  //1:vat, 2:novat (0)
                                                                    #endregion Cal Discount by Pro. rate

                                                                    tSqlUpDT = "UPDATE " + cCNVB.tVB_TmpDT + " WITH(ROWLOCK)";
                                                                    tSqlUpDT += "\n SET FTSdtDisChgTxt = '" + tDisChgTxt + "', FCSdtDis = " + String.Format("{0:F2}", cDis) + ", FCSdtNet = " + String.Format("{0:F2}", cNet) + ", FCSdtVat = " + String.Format("{0:F2}", cVat) + ", FCSdtVatable = " + String.Format("{0:F2}", cVatable) + ", FCSdtPmtQtyGet = 1";
                                                                    tSqlUpDT += "\n , FTPmhCode = '" + tPmtCodeGetPro + "', FTPmhType = '" + nPmtTypeGetPro + "'";
                                                                    tSqlUpDT += "\n , FTPdtName = CASE WHEN LEFT(FTPdtName, 1) <> '*' THEN '*' + FTPdtName ELSE FTPdtName END";
                                                                    tSqlUpDT += "\n WHERE FNSdtSeqNo = " + nSeqNo + " AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                                                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType25 : " + nPmtTypeGetPro + "] tSqlUpDT : " + tSqlUpDT);
                                                                    oW_SqlDTPmtGroup1.AppendLine(tSqlUpDT);
                                                                }
                                                            }
                                                        }
                                                    }

                                                    if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                                                    {
                                                        bType25Success = true;
                                                    }
                                                    else
                                                    {
                                                        bType25Success = false;
                                                    }
                                                }
                                                else
                                                {
                                                    bType25Success = false;
                                                }                                                
                                            }
                                        }
                                    }
                                    bChkPdtPmt = true;
                                }
                                else
                                {
                                    bChkPdtPmt = false;
                                }

                                ////�??�?��?�����������?�����������
                                tlstDPSeqNo = string.Join(",", lsttDPSeqNo.ToArray());
                                cMaxPdt = W_GETcMaxPdt25(tExcludeSeq, tPmtCode, tlstDPSeqNo); //*Thana 2026-05-22 Non-Sale Req
                            }
                        }                                                
                    }
                }
                return bType25Success;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_CHKbCalByPMTGrpType25] Error : " + ex.Message);
                return false;
            }
        }

        //*== Function ���?��?���? Update ��?�? ���?�?������?�����������
        private static void W_PRCxClearTempDTPmt25_27(string ptListSeqNoRef)
        {
            string tSql = "";
            try
            {
                cCNSP.SP_ADDxLog("LogPmtPrc", "======= W_PRCxClearTempDTPmt25 - 27 ======");
                //���?��?���? Update ��?���?�?����������������
                tSql = "SELECT DT.FNSdtSeqNo, FTSdtVatType, FCSdtQty, FCSdtB4DisChg, FTShdVATInOrEx";
                tSql += "\n  FROM " + cCNVB.tVB_TmpDT + " DT WITH(NOLOCK)";
                tSql += "\n  LEFT JOIN " + cCNVB.tVB_TmpDP + " DP";
                tSql += "\n     ON DT.FNSdtSeqNo = DP.FNSdtSeqNo";
                tSql += "\n     AND DT.FTShdDocNo = DP.FTShdDocNo";
                tSql += "\n     AND DT.FTSdtBarCode = DP.FTDtpBarCode";
                tSql += "\n  WHERE DT.FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "' AND DT.FTSdtStaPdt = '1'"; //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)
                if (ptListSeqNoRef.Trim().Length > 0) { tSql += "\n  AND DP.FNDtpSdtSeqNoRef IN (" + ptListSeqNoRef + ")"; }

                using (DataTable oDbTbl = cCNSP.SP_SQLoExecute(tSql))
                {
                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_PRCxClearDTPmt] oDbTbl.Rows.Count : " + oDbTbl.Rows.Count);
                    if (oDbTbl.Rows.Count > 0)
                    {
                        int nSeqNo = 0;
                        string tVatType, tVATInOrEx;
                        double cQty = 0, cPrice = 0, cVat = 0, cVatable = 0;
                        string tSqlUpDT = "";
                        oW_SqlDTClearPmt = new StringBuilder();
                        for (int i = 0; i < oDbTbl.Rows.Count; i++)
                        {
                            nSeqNo = int.Parse(oDbTbl.Rows[i]["FNSdtSeqNo"].ToString());
                            tVatType = oDbTbl.Rows[i]["FTSdtVatType"].ToString();
                            cQty = double.Parse(oDbTbl.Rows[i]["FCSdtQty"].ToString());
                            cPrice = double.Parse(oDbTbl.Rows[i]["FCSdtB4DisChg"].ToString());
                            tVATInOrEx = oDbTbl.Rows[i]["FTShdVATInOrEx"].ToString();
                            cVat = (tVatType == "1" ? cCNSP.SP_CALcVatValue((tVATInOrEx == "1" ? false : true), cPrice, cCNPM.cPM_VatRate) : 0);
                            cVatable = ((tVatType == "1") ? cPrice - cVat : 0);  //1:vat, 2:novat (0)
                            tSqlUpDT = "UPDATE " + cCNVB.tVB_TmpDT + " WITH(ROWLOCK)";
                            tSqlUpDT += "\n SET FTSdtDisChgTxt = '', FCSdtDis = 0, FCSdtChg = 0, FCSdtNet = FCSdtB4DisChg, FCSdtVat = " + String.Format("{0:F2}", cVat) + ", FCSdtVatable = " + String.Format("{0:F2}", cVatable) + ", FCSdtPmtQtyGet = 0 ";
                            tSqlUpDT += "\n ,FTSdtPmhCpnDocNo = '', FTPmhCode = '', FTPmhType = 0, FCSdtPmhCpnGetQty = 0, FCSdtPmhCpnValue = 0, FCSdtDisGP = 0"; //Clear All Promotion Group2 (������?��?��)
                            tSqlUpDT += "\n ,FTPdtName = CASE WHEN LEFT(FTPdtName, 1) = '*' THEN SUBSTRING(FTPdtName, 2, LEN(FTPdtName)) ELSE FTPdtName END";
                            tSqlUpDT += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "' AND FNSdtSeqNo = " + nSeqNo.ToString() ;
                            cCNSP.SP_SQLoExecute(tSqlUpDT);
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_PRCxClearTempDTPmt25_27] Error : " + ex.Message + " tSql : " + tSql);
            }
        }

