        public static void W_AddxDatatoList(ref List<string> pList, string nValue)
        {
            try
            {
                if (!pList.Contains(nValue))
                {
                    pList.Add(nValue);
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_AddxDatatoList] Error : " + ex.Message);
            }
        }

        public static void W_DelxDataFromList(ref List<string> pList, string nValue)
        {
            try
            {
                if (pList.Contains(nValue))
                {
                    pList.Remove(nValue);
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_DelxDataFromList] Error : " + ex.Message);
            }
        }

        public static double W_GETcMaxPdt25(string ptlstPmtSeqNo, string ptPmtCode, string ptlstDPSeqNo)
        {
            string tSql = "";
            try
            {                
                tSql = "SELECT COUNT(FTDtpBarCode) As FNPdtCount FROM " + cCNVB.tVB_TmpDP + "";
                tSql += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                tSql += "\n       AND FTSdtStaPdt = '1'";           //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)                                                                           
                tSql += "\n       AND ISNULL(FTPdtNoDis,'')='2'";   //Flag allow discount
                if (ptlstPmtSeqNo.Trim().Length > 0) { tSql += "\n       AND FNDtpSeqNo NOT IN (" + ptlstPmtSeqNo + ")"; }
                if (ptlstDPSeqNo.Trim().Length > 0) { tSql += "\n       AND FNDtpSeqNo NOT IN (" + ptlstDPSeqNo + ")"; }
                tSql += "\n       AND FTDtpBarCode IN (SELECT FTPmdBarCodeBuy";
                tSql += "\n             FROM TCNTPdtPmtDT";
                tSql += "\n             WHERE FTPmhDocNo = '" + ptPmtCode + "' AND FNSpmType = 25";
                tSql += "\n             GROUP BY FTPmdBarCodeBuy)";

                using (DataTable oTblDP = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oTblDP.Rows.Count > 0) 
                    {
                        return double.Parse(oTblDP.Rows[0]["FNPdtCount"].ToString());
                    }
                    else
                    {
                        return 0;
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_GETcMaxPdt] Error : " + ex.Message + " SQL = " + tSql);
                return 0;
            }
        }

        public static double W_GETcMaxPdt26(string ptlstPmtSeqNo, string ptPmtCode, string ptlstDPSeqNo)
        {
            string tSql = "";
            try
            {
                tSql = "SELECT COUNT(FTDtpBarCode) As FNPdtCount FROM " + cCNVB.tVB_TmpDP + "";
                tSql += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                tSql += "\n AND FTSdtStaPdt = '1'";           //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)                                                                           
                tSql += "\n AND ISNULL(FTPdtNoDis,'')='2'";   //Flag allow discount
                if (ptlstPmtSeqNo.Trim().Length > 0) { tSql += "\n  AND FNDtpSeqNo NOT IN (" + ptlstPmtSeqNo + ")"; }
                if (ptlstDPSeqNo.Trim().Length > 0) { tSql += "\n   AND FNDtpSeqNo NOT IN (" + ptlstDPSeqNo + ")"; }
                tSql += "\n AND FTDtpBarCode IN ";
                tSql += "\n (SELECT FTPmdBarCodeBuy";
                tSql += "\n FROM TCNTPdtPmtDT";
                tSql += "\n WHERE FTPmhDocNo = '" + ptPmtCode + "' AND FNSpmType = 26";
                tSql += "\n GROUP BY FTPmdBarCodeBuy";
                tSql += "\n UNION ";
                tSql += "\n ";
                tSql += "\n SELECT DISTINCT CO.FTPmoBarCodeCo";
                tSql += "\n FROM TCNTPdtPmtCO CO WITH(NOLOCK)";
                tSql += "\n LEFT JOIN " + cCNVB.tVB_TmpPT + " PT ON CO.FTPmhDocNo = PT.FTPmhDocNo AND CO.FTPmdBarCodeBuy = PT.FTPdtBarX";
                tSql += "\n WHERE CO.FTPmhDocNo = '" + ptPmtCode + "'";
                tSql += "\n )";

                //tSql += "\n AND FTDtpBarCode IN (SELECT DISTINCT FTPdtBarX FROM " + cCNVB.tVB_TmpPT + " WITH(NOLOCK) WHERE FTPmhDocNo = '" + ptPmtCode + "')";

                using (DataTable oTblDP = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oTblDP.Rows.Count > 0)
                    {
                        return double.Parse(oTblDP.Rows[0]["FNPdtCount"].ToString());
                    }
                    else
                    {
                        return 0;
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_GETcMaxPdt26] Error : " + ex.Message + " SQL = " + tSql);
                return 0;
            }
        }

