        public static bool W_CHKcPmtPdt(ref List<string> pList, double pcQtyPmt, string pListPmtSeqNo, string pListDPSeqNo,string ptPmtCode, double pcPmtMaxDiscount)
        {
            var oTblTmpDP = new DataTable();
            List<string> lsttRefSeqNo = new List<string>();
            List<string> lsttDtpSeqNo = new List<string>();
            string tSeqNoRef = "";
            string tSql = "";
            double cSumDtpDis = 0;
            try
            {
                tSql += "SELECT TOP " + pcQtyPmt.ToString() + " FNDtpSeqNo, FTDtpBarCode, FCDtpNet, FCDtpDis, FNDtpSdtSeqNoRef, FTPmhDocNo";
                tSql += "\n  FROM " + cCNVB.tVB_TmpDP;
                tSql += "\n  WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                tSql += "\n  AND FTSdtStaPdt = '1'";           //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)                                                                           
                tSql += "\n  AND ISNULL(FTPdtNoDis,'')='2'";   //Flag allow discount
                if (pListPmtSeqNo.Trim().Length > 0) { tSql += "\n  AND FNDtpSeqNo NOT IN (" + pListPmtSeqNo + ")"; }
                if (pListDPSeqNo.Trim().Length > 0) { tSql += "\n  AND FNDtpSeqNo NOT IN (" + pListDPSeqNo + ")"; }
                tSql += "\n  AND FTDtpBarCode IN (SELECT FTPmdBarCodeBuy";
                tSql += "\n                        FROM TCNTPdtPmtDT";
                tSql += "\n                        WHERE FTPmhDocNo = '" + ptPmtCode + "' AND FNSpmType = 25";
                tSql += "\n                        GROUP BY FTPmdBarCodeBuy)";
                tSql += "\n  ORDER BY FCDtpNet ASC, FNDtpSeqNo ASC";

                using (DataTable oTblDP = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oTblDP.Rows.Count > 0)
                    {
                        for (int irow = 0; irow < oTblDP.Rows.Count; irow++)
                        {
                            if (oTblDP.Rows[irow]["FNDtpSdtSeqNoRef"] != null && int.Parse(oTblDP.Rows[irow]["FNDtpSdtSeqNoRef"].ToString()) > 0)
                            {
                                W_AddxDatatoList(ref lsttRefSeqNo, oTblDP.Rows[irow]["FNDtpSdtSeqNoRef"].ToString());
                            }
                            if (oTblDP.Rows[irow]["FNDtpSeqNo"] != null && oTblDP.Rows[irow]["FTPmhDocNo"] != null && int.Parse(oTblDP.Rows[irow]["FNDtpSeqNo"].ToString()) > 0 && oTblDP.Rows[irow]["FTPmhDocNo"].ToString().Trim() != "")
                            {
                                W_AddxDatatoList(ref lsttDtpSeqNo, oTblDP.Rows[irow]["FNDtpSeqNo"].ToString());
