        private static double W_GETcCalTotalDiscount(List<cCNVB.cVB_PdtItem> poItems, Dictionary<string, double> pdPmt)
        {
            double cTotal = 0.0;
            foreach (var pitem in poItems)
            {
                if (pdPmt.ContainsKey(pitem.FTPdtBarcode))
                {
                    cTotal += pdPmt[pitem.FTPdtBarcode] * pitem.FnQty;
                }
            }
            return cTotal;
        }

        //����??�������?�������� ������?��������? type 25
        public static double W_GETcSUMPdt(string ptSeqNoRef)
        {
            string tSql = "";
            try
            {
                tSql = "SELECT SUM(FCDtpDis) as FCDtpDis_sum";
                tSql += "\n  FROM " + cCNVB.tVB_TmpDP;
                tSql += "\n  WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                if (ptSeqNoRef.Trim().Length > 0)   { tSql += "\n  AND FNDtpSdtSeqNoRef in (" + ptSeqNoRef + ")"; }
                tSql += "\n  AND FTSdtStaPdt = '1'";           //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)                                                                           
                tSql += "\n  AND ISNULL(FTPdtNoDis,'')='2'";   //Flag allow discount

                using (DataTable oTblDP = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oTblDP.Rows.Count > 0)
                    {
                        return double.Parse(oTblDP.Rows[0]["FCDtpDis_sum"].ToString());
                    }
                    else
                    {
                        return 0;
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_GETcMaxPdt] Error : " + ex.Message + " SQL = " + tSql);
                return 0;
            }
        }

        //�� Max FNDtpSeqNo ?��? TSCDxxx
        public static int W_MaxnDtpSeqNo()
        {
            string tSql = "";
            try
            {
                tSql = "SELECT MAX(FNDtpSeqNo) as FNDtpSeqNo_Max";
                tSql += "\n  FROM " + cCNVB.tVB_TmpCD;
                tSql += "\n  WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";

                using (DataTable oTblCD = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oTblCD.Rows.Count > 0)
                    {
                        return int.Parse(oTblCD.Rows[0]["FNDtpSeqNo_Max"].ToString());
                    }
                    else
                    {
                        return 0;
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_MaxnDtpSeqNo] Error : " + ex.Message + " SQL = " + tSql);
                return 0;
            }
        }

