                tSql += "\n xxx.FCSpmPriNewX, ";

                tSql += "\n CO1.FTPdtCode AS FTPdtCodeY, ";
                tSql += "\n CO1.FTPmoBarCodeCo AS FTPdtBarY, ";
                tSql += "\n CO1.FTPdtName AS FTPdtNameY, ";
                tSql += "\n CO1.FCPmoBuyQty AS FCQtyPmtY, ";
                tSql += "\n CO1.FCPmoOrgPri AS FCSpmPriOrgY, ";

                tSql += "\n CO2.FTPdtCode AS FTPdtCodeZ, ";
                tSql += "\n CO2.FTPmoBarCodeCo AS FTPdtBarZ, ";
                tSql += "\n CO2.FTPdtName AS FTPdtNameZ, ";
                tSql += "\n CO2.FCPmoBuyQty AS FCQtyPmtZ, ";
                tSql += "\n CO2.FCPmoOrgPri AS FCSpmPriOrgZ, ";

                tSql += "\n xxx.FDPmhDStart, ";
                tSql += "\n xxx.FTPmhName, ";
                tSql += "\n xxx.FDPmhDStop, ";
                tSql += "\n xxx.FDPmhTStart, ";
                tSql += "\n xxx.FDPmhTStop, ";
                tSql += "\n xxx.FDSpmTimeIns, ";
                tSql += "\n xxx.FNSpmSeqScan, ";
                tSql += "\n xxx.FNSpmType, ";
                tSql += "\n xxx.FTSpmGetType, ";
                tSql += "\n xxx.FTSpmStaInc, xxx.FCSpmTier "; //*Thana 2026-05-22 Non-Sale Req
                tSql += "\n FROM( ";
                tSql += "\n     SELECT ";
                tSql += "\n         PT.FTPmhDocNo, ";
                tSql += "\n         PT.FDPmhDStart, ";
                tSql += "\n         PT.FTPmhName, ";
                tSql += "\n         PT.FDPmhDStop, ";
                tSql += "\n         PT.FDPmhTStart, ";
                tSql += "\n         PT.FDPmhTStop, ";
                tSql += "\n         PT.FNSpmType, ";
                tSql += "\n         PT.FTSpmGetType, ";

                tSql += "\n         PT.FTPdtCodeX, ";
                tSql += "\n         PT.FTPdtBarX, ";
                tSql += "\n         PT.FTPdtNameX, ";
                tSql += "\n         PT.FCQtyPmtX, ";

                tSql += "\n         MAX(PT.FCSpmPriOrgX) AS FCSpmPriOrgX, ";
                tSql += "\n         MAX(PT.FCSpmPriNewX) AS FCSpmPriNewX, ";
                tSql += "\n         MIN(PT.FDSpmTimeIns) AS FDSpmTimeIns, ";
                tSql += "\n         MAX(PT.FNSpmSeqScan) AS FNSpmSeqScan, ";
                tSql += "\n         MAX(ISNULL(Tier.FTSpmStaInc, '0')) AS FTSpmStaInc, MAX(ISNULL(Tier.FCSpmTier, 0)) AS FCSpmTier "; //*Thana 2026-05-22 Non-Sale Req
                tSql += "\n     FROM " + cCNVB.tVB_TmpPT + " PT WITH(NOLOCK) ";
                tSql += "\n     INNER JOIN TCNTPdtPmtHD PmtHD WITH(NOLOCK) ";
                tSql += "\n         ON PT.FTPmhDocNo = PmtHD.FTPmhDocNo ";
                tSql += "\n     LEFT JOIN TSysPmtTier Tier WITH(NOLOCK) "; //*Thana 2026-05-22 Non-Sale Req
                tSql += "\n         ON PT.FNSpmType = Tier.FNSpmType AND PT.FTSpmGetType = Tier.FTPmcGetType "; //*Thana 2026-05-22 Non-Sale Req
                tSql += "\n     INNER JOIN " + cCNVB.tVB_TmpDT + " DT WITH(NOLOCK) ";
                tSql += "\n         ON DT.FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "' ";
                tSql += "\n         AND DT.FTSdtBarCode IN ( PT.FTPdtBarX ) ";
                tSql += "\n     WHERE PT.FNSpmType = 27 ";
                tSql += "\n       AND PT.FCSpmQtyKeyZ > 0 ";

                tSql += "\n       AND( ";
                tSql += "\n       CASE ";
                tSql += "\n           WHEN PT.FTSpmGetType IN (1, 2, 3) AND PT.FCSpmDisAmt > 0 THEN 1 ";
                tSql += "\n           WHEN PT.FTSpmGetType = 4          AND PT.FCSpmDisPer > 0 THEN 1 ";
                tSql += "\n           ELSE 0 ";
                tSql += "\n       END ";
                tSql += "\n       ) = 1 ";

                tSql += "\n       AND @Now >= PT.FDPmhDStart ";
                tSql += "\n       AND @Now<DATEADD(DAY, 1, PT.FDPmhDStop) ";

                tSql += "\n       AND CAST(@Now AS TIME) ";
                tSql += "\n       BETWEEN CAST(PT.FDPmhTStart AS TIME) ";
                tSql += "\n       AND CAST(PT.FDPmhTStop AS TIME) ";

                tSql += "\n       AND( ";
                tSql += "\n             SUBSTRING(';' + PmtHD.FTPgpChain + ';', (" + pdToday + " * 2), 1) = '1' ";
                tSql += "\n             OR PmtHD.FTPgpChain IS NULL ";
                tSql += "\n             OR PmtHD.FTPgpChain = '' ";
                tSql += "\n           ) ";
                tSql += "\n     GROUP BY ";
                tSql += "\n         PT.FTPmhDocNo, ";
                tSql += "\n         PT.FDPmhDStart, ";
                tSql += "\n         PT.FTPmhName, ";
                tSql += "\n         PT.FDPmhDStop, ";
                tSql += "\n         PT.FDPmhTStart, ";
                tSql += "\n         PT.FDPmhTStop, ";
