                                                            nQtyDiv = nSumQtyZDiv; //�??���������??�??�����?�?�? GET
                                                        }
                                                        cW_QtyDiv[nGetPro, nGetType] = nQtyDiv;
                                                    }
                                                    else
                                                    {
                                                        cW_QtyDiv[nGetPro, nGetType] = 0;
                                                        goto NextLoopPT;
                                                    }
                                                }

                                                cW_SumQty[nGetPro, nGetType] = cSumQty; //�??�?��?�����                                           
                                                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType27 : " + nPmtTypeGetPro + "] cW_QtyDiv[" + nGetPro + ", " + nGetType + "] : " + cW_QtyDiv[nGetPro, nGetType]);
                                            }

                                            //���??�??��������� ���?��
                                            if (cW_QtyDiv[nGetPro, nGetType] > 0 && cW_SumQty[nGetPro, nGetType] > 0)
                                            {
                                                cPmtMaxDiscount = 0.0;
                                                cPmtDiscount = 0.0;
                                                nSumSeqNoRef = 0;
                                                bChkPdtinPmt = true;
                                                tlstPmtSeqNo = string.Join(",", lsttPmtSeqNo.ToArray());
                                                tlstDPSeqNo = string.Join(",", lsttDPSeqNo.ToArray());

                                                #region �?�����?�?��?������??
                                                nPdtCount = 0;
                                                cSumB4DisChg = 0.0;
                                                cSumDiscount = 0.0;

                                                tSqlDPSum = "SELECT COUNT(FTDtpBarCode) As FNPdtCount, SUM(FCDtpNet) as FCDtpNet_sum, SUM(FCDtpDis) as FCDtpDis_sum, SUM(FNDtpSdtSeqNoRef) as FNDtpSdtSeqNoRef_sum";
                                                tSqlDPSum += "\n  FROM (";
                                                tSqlDPSum += "\n  SELECT FTDtpBarCode, FCDtpNet, FCDtpDis, FNDtpSdtSeqNoRef";
                                                tSqlDPSum += "\n  FROM " + cCNVB.tVB_TmpDP;
                                                tSqlDPSum += "\n  WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                                                tSqlDPSum += "\n  AND FTSdtStaPdt = '1'";           //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)                                                                           
                                                tSqlDPSum += "\n  AND ISNULL(FTPdtNoDis,'')='2'";   //Flag allow discount
                                                tSqlDPSum += "\n  AND FNDtpSeqNo NOT IN (" + tlstPmtSeqNo + ")";
                                                if (tSeqDP.Trim().Length > 0) { tSqlDPSum += "\n  AND FNDtpSeqNo IN (" + tSeqDP + ")"; }
                                                tSqlDPSum += "\n  ) AS TopPdt"; 
                                                //tSqlDPSum += "\n  AND FTDtpBarCode IN (SELECT FTPmdBarCodeBuy";
                                                //tSqlDPSum += "\n                        FROM TCNTPdtPmtDT";
                                                //tSqlDPSum += "\n                        WHERE FTPmhDocNo = '" + tPmtCode + "' AND FNSpmType = 27";
                                                //tSqlDPSum += "\n                        GROUP BY FTPmdBarCodeBuy)";
                                                //tSqlDPSum += "\n  ORDER BY FCDtpNet ASC, FNDtpSeqNo ASC) AS TopPdt";

                                                using (DataTable oTblDPSum = cCNSP.SP_SQLoExecute(tSqlDPSum))
                                                {
                                                    if (oTblDPSum.Rows.Count > 0)
                                                    {
                                                        nPdtCount = int.Parse(oTblDPSum.Rows[0]["FNPdtCount"].ToString());
                                                        cSumB4DisChg = double.Parse(oTblDPSum.Rows[0]["FCDtpNet_sum"].ToString());
                                                        cSumDiscount = double.Parse(oTblDPSum.Rows[0]["FCDtpDis_sum"].ToString());
                                                        nSumSeqNoRef = int.Parse(oTblDPSum.Rows[0]["FNDtpSdtSeqNoRef_sum"].ToString());  //���?�?������?��?���������������������
                                                    }
                                                }
                                                #endregion �?�����?�?��?������??

                                                //����??�������������?�?������� Type 27
                                                cPmtDiscount = W_GETcPmtDiscount26_27(tlstPmtSeqNo, tSeqDP, tPmtCode, tPmtGetType, nPmtType);

                                                if (nPdtCount > 0 && cPmtDiscount > 0)
                                                {
                                                    //�??��??�? Promotion �������??�?����?
                                                    cPmtMaxDiscount = cPmtDiscount;

                                                    bChkDupPmt = false;
                                                    if (nSumSeqNoRef > 0)
                                                    {
                                                        //�?��?��??������������������ ��?��?�?�������?��?������??���?��� type 27 �������                                                            
                                                        tlstDPSeqNo = string.Join(",", lsttDPSeqNo.ToArray());
                                                        bChkDupPmt = W_CHKcPmtPdt27(ref lsttDPSeqNo, tlstPmtSeqNo, tlstDPSeqNo, tPmtCode, cPmtMaxDiscount);
                                                    }

                                                    if (cPmtMaxDiscount > cSumDiscount && !bChkDupPmt)
                                                    {
                                                        bChkPmt27 = true;       //�� Promotion Type 27 ��������??�?���� Type �����
                                                        tPmtCodeGetPro = tPmtCode;
                                                        //tPmhGetType = oTblTmpPT.Rows[i]["FTPmhGetType"].ToString();
                                                        //tGetType = tPmtGetType; //Type �?������?�����? ��� 1 = �?�����, 2 = ?�??, 3 = ?�� %

                                                        tlstDPSeqNo = string.Join(",", lsttDPSeqNo.ToArray());
                                                        bChkPdtinPmt = true;
                                                    }
                                                    else
                                                    {
                                                        bChkPmt27 = false;
                                                        tlstPmtSeqNo = string.Join(",", lsttPmtSeqNo.ToArray());
                                                        tlstDPSeqNo = string.Join(",", lsttDPSeqNo.ToArray());
                                                        cMaxinPdt = W_GETcMaxPdt27(tlstPmtSeqNo, tPmtCode, tlstDPSeqNo); //�??�?��?�����������?������� 
                                                    }
                                                }
                                                else if (nPdtCount > 0 && cPmtDiscount <= 0)
                                                {
                                                    if (tSeqDP.Length > 0)
                                                    {
                                                        //Krisana 2025-08-15 ��������� DPSeqNo �����??�?�?��� <= �??���
                                                        string[] aSeqDP = tSeqDP.Split(',');

                                                        for (int n = 0; n < aSeqDP.Length; n++)
                                                        {
                                                            W_AddxDatatoList(ref lsttDPSeqNo, aSeqDP[n].Trim());
                                                        }

                                                        tlstDPSeqNo = string.Join(",", lsttDPSeqNo.ToArray());
                                                        cMaxinPdt = W_GETcMaxPdt27(tlstPmtSeqNo, tPmtCode, tlstDPSeqNo); //�??�?��?�����������?������� 
                                                        bChkPmt27 = false;
                                                    }
                                                }

                                                //�� Promotion Type 27 ��������??�?���� Type �����
                                                if (bChkPmt27 == true && cPmtMaxDiscount > 0)
                                                {
                                                    tSeqNoRef = "";
                                                    //�� GET � TSDTxxx ���??�� UPDATE ��?�������������?? ����??�?��?����� Promotion type 27
                                                    //�?�?��??�??��??��?�� ?���? TSDPxxx, TSCDxxx

                                                    tSqlDT = "SELECT * ";
                                                    tSqlDT += "\n  FROM " + cCNVB.tVB_TmpDP + " DP WITH(NOLOCK)";
                                                    tSqlDT += "\n  LEFT JOIN " + cCNVB.tVB_TmpDT + " DT";
                                                    tSqlDT += "\n     ON DT.FNSdtSeqNo = DP.FNSdtSeqNo";
                                                    tSqlDT += "\n     AND DT.FTShdDocNo = DP.FTShdDocNo";
                                                    tSqlDT += "\n     AND DT.FTSdtBarCode = DP.FTDtpBarCode";
                                                    tSqlDT += "\n  WHERE DP.FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                                                    tSqlDT += "\n  AND DT.FTSdtStaPdt = '1'";           //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)                                                                           
                                                    tSqlDT += "\n  AND ISNULL(DT.FTPdtNoDis,'')='2'";   //Flag allow discount
                                                    tSqlDT += "\n  AND FNDtpSeqNo NOT IN (" + tlstPmtSeqNo + ")";
                                                    if (tSeqDP.Trim().Length > 0) { tSqlDT += "\n  AND FNDtpSeqNo IN (" + tSeqDP + ")"; }
                                                    tSqlDT += "\n  ORDER BY DP.FCDtpNet ASC, DP.FNDtpSeqNo ASC";

                                                    using (DataTable oDbTblTmpDTx = cCNSP.SP_SQLoExecute(tSqlDT))
                                                    {
                                                        double cTotalAmt;   //�?��?��?������������ 
                                                        double cTotalDis;   //��??�?�?�����

                                                        if (oDbTblTmpDTx.Rows.Count > 0)
                                                        {
                                                            #region Variable
                                                            object oSum = oDbTblTmpDTx.Compute("SUM(FCDtpNet)", string.Empty);
                                                            cTotalAmt = Convert.ToDouble(oSum);

                                                            int nDPSeqNo = 0;
                                                            int nDTSeqNo = 0;
                                                            int nSdtSeqNoRef = 0;
                                                            List<string> lsttSeqNo = new List<string>();
                                                            List<string> lsttSeqNoRef = new List<string>();

                                                            oW_SqlDTClearPmt.Length = 0;
                                                            oW_SqlDTPmtGroup1.Length = 0;
                                                            oW_SqlDPClearPmt.Length = 0;
                                                            oW_SqlDPPmtGroup1.Length = 0;
                                                            oW_SqlCDClearPmt.Length = 0;
                                                            oW_SqlCDPmtGroup1.Length = 0;

                                                            oW_SqlDTPmtGroup1 = new StringBuilder();
                                                            oW_SqlDPPmtGroup1 = new StringBuilder();
                                                            oW_SqlCDPmtGroup1 = new StringBuilder();

                                                            double cNet = 0;
                                                            double cVat;
                                                            double cVatable;
                                                            double cNetB4Dis;
                                                            double cDis;
                                                            double cSumDis;
                                                            string tVATInOrEx;
                                                            string tVatType;
                                                            string tDisChgTxt;
                                                            int nSeqNo;

                                                            cTotalDis = cPmtMaxDiscount;
                                                            cSumDis = 0;
                                                            #endregion Variable

                                                            nW_CDSeqNo = W_MaxnDtpSeqNo();
                                                            //�?�?��??�??��??��?�� ?���? TSDPxxx, TSCDxxx
                                                            for (int iDt = 0; iDt < oDbTblTmpDTx.Rows.Count; iDt++)
                                                            {
                                                                nSdtSeqNoRef = int.Parse(oDbTblTmpDTx.Rows[0]["FNSdtSeqNo"].ToString());
                                                                nDPSeqNo = int.Parse(oDbTblTmpDTx.Rows[iDt]["FNDtpSeqNo"].ToString());
                                                                nDTSeqNo = int.Parse(oDbTblTmpDTx.Rows[iDt]["FNSdtSeqNo"].ToString());
                                                                tVATInOrEx = oDbTblTmpDTx.Rows[iDt]["FTShdVATInOrEx"].ToString();
                                                                tVatType = oDbTblTmpDTx.Rows[iDt]["FTSdtVatType"].ToString();
                                                                W_AddxDatatoList(ref lsttSeqNoRef, oDbTblTmpDTx.Rows[iDt]["FNDtpSdtSeqNoRef"].ToString());
                                                                W_AddxDatatoList(ref lsttSeqNo, nDTSeqNo.ToString() + "|" + tVATInOrEx + "|" + tVatType);

                                                                #region Cal Discount by Pro. rate
                                                                //�??��??��� Pro Rate
                                                                cNetB4Dis = double.Parse(oDbTblTmpDTx.Rows[iDt]["FCDtpNet"].ToString());
                                                                //nSeqNo = int.Parse(oDbTblTmpDTx.Rows[iDt]["FNSdtSeqNo"].ToString());
                                                                cDis = 0;

                                                                //��??�?�?��?���?���?���� Pro ������??����� - ������?��??��??�?����� (���?�?�?��� diff �?��??)
                                                                if (iDt == (oDbTblTmpDTx.Rows.Count - 1))
                                                                {
                                                                    if (cTotalDis > cSumDis)
                                                                    {
                                                                        cDis = cTotalDis - cSumDis;
                                                                    }
                                                                    else
                                                                    {
                                                                        cDis = 0;
                                                                    }
                                                                }
                                                                else
                                                                {
                                                                    //��??�?�?��?�?�� = (��??�?�?����� / �?��?��?������������) * �??�?��?�?��
                                                                    cDis = Math.Round((cTotalDis / cTotalAmt) * cNetB4Dis, 2);
                                                                    cSumDis += cDis;
                                                                }
                                                                #endregion Cal Discount by Pro. rate

                                                                tSqlUpDP = "UPDATE " + cCNVB.tVB_TmpDP + " WITH(ROWLOCK)";
                                                                tSqlUpDP += "\n SET FTPmhDocNo = '" + tPmtCodeGetPro + "', FNSpmType = " + nPmtTypeGetPro + ", FCDtpDis = " + string.Format("{0:F2}", cDis);
                                                                tSqlUpDP += "\n , FTDtpStaGetPmt = '3', FCDtpPmtQtyGet = 1";    //*Tao 62-12-06 �?����?����������� (FTDtpStaGetPmt 0:None, 1:������?���� 1 (1-11) ��?�� (DT), 2:������?���� 1 (1-11) ������� (CO), 3: ���?�������, 4:���?������?��������?��, FCDtpPmtQtyGet=�??�?��?�����?��??�������)
                                                                tSqlUpDP += "\n , FNDtpSdtSeqNoRef = " + nSdtSeqNoRef + ", FNDtpQtyPmtX = 0, FNDtpQtyPmtGetX = 0, FNDtpQtyPmtLeftX = 0";    // ������ ������������ Export

                                                                tSqlUpDP += "\n WHERE FNDtpSeqNo = " + nDPSeqNo;
                                                                tSqlUpDP += "\n AND FNSdtSeqNo = " + nDTSeqNo + " AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                                                                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType27 : " + nPmtTypeGetPro + "] tSqlUpDP : " + tSqlUpDP);
                                                                oW_SqlDPPmtGroup1.AppendLine(tSqlUpDP);
                                                                nW_CDSeqNo += 1;
                                                    C_PRCbSavePmtDP2CD(nW_CDSeqNo, nDPSeqNo); //�?�������??������������
                                                    W_PRCxUpdateUsedSeq(nPmtType, nDPSeqNo, (oDbTblTmpPT.Rows[i]["FTSpmStaInc"].ToString() == "1")); //*Thana 2026-05-22 Non-Sale Req
                                                    if (oDbTblTmpPT.Rows[i]["FTSpmStaInc"].ToString() != "1") 
                                                    {
                                                        W_AddxDatatoList(ref lsttPmtSeqNo, nDPSeqNo.ToString()); //*Thana 2026-05-22 Non-Sale Req
                                                    }
                                                }

                                                            tSeqNoRef = string.Join(",", lsttSeqNoRef.ToArray());

                                                            //Clear Promotion ����������??
                                                            W_PRCxClearTempDTPmt25_27(tSeqNoRef); //����������?�� TSDTxxx
                                                            W_PRCxClearTempDPPmt25_27(tSeqNoRef); //����������?�� TSDPxxx
                                                            W_PRCxClearTempCDPmt25_27(tSeqNoRef); //����������?�� TSCDxxx

                                                            if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                                                            {
                                                                //�?�?��??�??��??��?�� ?���? TSDTxxx
                                                                if (lsttSeqNo.Count > 0)
                                                                {
                                                                    for (int n = 0; n < lsttSeqNo.Count; n++)
                                                                    {
                                                                        string[] aDTDetail = lsttSeqNo[n].Split('|');
                                                                        nSeqNo = int.Parse(aDTDetail[0]);
                                                                        tVATInOrEx = aDTDetail[1];
                                                                        tVatType = aDTDetail[2];

                                                                        tSql = "SELECT SUM(FCDtpNet) AS FCDtpNet_SUM, SUM(FCDtpDis) AS FCDtpDis_SUM";
                                                                        tSql += "\n  FROM " + cCNVB.tVB_TmpDP + " WITH(NOLOCK)";
                                                                        tSql += "\n  WHERE FNSdtSeqNo = " + nSeqNo.ToString();
                                                                        tSql += "\n  AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                                                                        tSql += "\n  GROUP BY FTShdDocNo,FNSdtSeqNo";

                                                                        using (DataTable oDbTblDTx = cCNSP.SP_SQLoExecute(tSql))
                                                                        {
                                                                            if (oDbTblDTx.Rows.Count > 0)
                                                                            {

                                                                                #region Cal Discount by Pro. rate
                                                                                //�??��??��� Pro Rate
                                                                                cNetB4Dis = double.Parse(oDbTblDTx.Rows[0]["FCDtpNet_SUM"].ToString());
                                                                                cDis = double.Parse(oDbTblDTx.Rows[0]["FCDtpDis_SUM"].ToString());


                                                                                if (cDis == 0)
                                                                                {
                                                                                    tDisChgTxt = "";
                                                                                }
                                                                                else if (cDis < 0)
                                                                                    tDisChgTxt = String.Format("{0:F2}", (cDis * -1));
                                                                                else
                                                                                {
                                                                                    tDisChgTxt = "-" + String.Format("{0:F2}", cDis);
                                                                                }
                                                                                cNet = cNetB4Dis - cDis; //�?��?����?�?�?������� = �??�?? - �??����?
                                                                                cVat = (tVatType == "1" ? cCNSP.SP_CALcVatValue((tVATInOrEx == "1" ? false : true), cNet, cCNVB.cVB_VatRate) : 0);
                                                                                cVatable = ((tVatType == "1") ? cNet - cVat : 0);  //1:vat, 2:novat (0)
                                                                                #endregion Cal Discount by Pro. rate

                                                                                tSqlUpDT = "UPDATE " + cCNVB.tVB_TmpDT + " WITH(ROWLOCK)";
                                                                                tSqlUpDT += "\n SET FTSdtDisChgTxt = '" + tDisChgTxt + "', FCSdtDis = " + String.Format("{0:F2}", cDis) + ", FCSdtNet = " + String.Format("{0:F2}", cNet) + ", FCSdtVat = " + String.Format("{0:F2}", cVat) + ", FCSdtVatable = " + String.Format("{0:F2}", cVatable) + ", FCSdtPmtQtyGet = 1";
                                                                                tSqlUpDT += "\n , FTPmhCode = '" + tPmtCodeGetPro + "', FTPmhType = '" + nPmtTypeGetPro + "'";
                                                                                tSqlUpDT += "\n , FTPdtName = CASE WHEN LEFT(FTPdtName, 1) <> '*' THEN '*' + FTPdtName ELSE FTPdtName END";
                                                                                tSqlUpDT += "\n WHERE FNSdtSeqNo = " + nSeqNo + " AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                                                                                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType27 : " + nPmtTypeGetPro + "] tSqlUpDT : " + tSqlUpDT);
                                                                                oW_SqlDTPmtGroup1.AppendLine(tSqlUpDT);
                                                                            }
                                                                        }
                                                                    }
                                                                }

                                                                if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                                                                {
                                                                    bType27Success = true;
                                                                }
                                                                else
                                                                {
                                                                    bType27Success = false;
                                                                }
                                                            }
                                                            else
                                                            {
                                                                bType27Success = false;
                                                            }
                                                        }
                                                    }
                                                    //bChkPdtPmt = true;
                                                }
                                                else
                                                {
                                                    bChkPdtPmt = false;
                                                }
                                            }
                                            else
                                            {
                                                bChkPmt27 = false;
                                            }
                                        }
                                    }
                                    else
                                    {
                                        bChkPmt27 = false;
                                    }
                                }

                                //�???�?��?�����������?������?�����������
                                tlstPmtSeqNo = string.Join(",", lsttPmtSeqNo.ToArray());
                                tlstDPSeqNo = string.Join(",", lsttDPSeqNo.ToArray());
                                cMaxPdt = W_GETcMaxPdt27(tlstPmtSeqNo, tPmtCode, tlstDPSeqNo); //�??�?��?�����������?������?�����������
                                if (cSumQtyPmt > cMaxPdt || !bChkPmt27)
                                {
                                    bChkPdtPmt = true;  //�?�? loop while
                                }
                                else
                                {
                                    if (cMaxPdt < 1)
                                    {
                                        bChkPdtPmt = true;
                                        break;
                                    }
                                }

                                for (int nlst = 0; nlst < lsttDPSeqNo.Count; nlst++)
                                {
                                    W_AddxDatatoList(ref lsttPmtSeqNo, lsttDPSeqNo[nlst].ToString());
                                }

                            }

                            NextLoopPT:
                                continue;
                        }
                    }
                }
                return bType27Success;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_CHKxCalByPMTGrpType27] Error : " + ex.Message);
                return false;
            }
        }

        public static double W_GETcPmtDiscount(string ptPmtSeqNo, string ptSeqDP, string ptPmhDocNo, string ptPmdGetType, int nPmtType)
        {
            string tSql = "";
            double cPmtDiscount = 0.0;
            try
            {
                
                tSql = " SELECT FTDtpBarCode, FCDtpNet, FNDtpSeqNo"; //*Thana 2026-05-22 Non-Sale Req (Add FCDtpNet)
                tSql += "\n  FROM " + cCNVB.tVB_TmpDP;
                tSql += "\n  WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                tSql += "\n  AND FTSdtStaPdt = '1'";           //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)                                                                           
                tSql += "\n  AND ISNULL(FTPdtNoDis,'')='2'";   //Flag allow discount
                tSql += "\n  AND FNDtpSeqNo NOT IN (" + ptPmtSeqNo + ")";
                if (ptSeqDP.Trim().Length > 0) { tSql += "\n  AND FNDtpSeqNo IN (" + ptSeqDP + ")"; }

                using (DataTable oTblDP = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oTblDP.Rows.Count > 0)
                    {
                        for (int i = 0; i < oTblDP.Rows.Count; i++)
                        {
                            double cDtpNet = double.Parse(oTblDP.Rows[i]["FCDtpNet"].ToString()); //*Thana 2026-05-22 Non-Sale Req

                            //Krisana 2025-08-07 Fix Issue ���??�?� ���?��?�����������?���
                            if (nPmtType == 3)
                            {
                                //Krisana 2025-08-08 comsheet 2025-098 �?�?��?����?? TCNMPdtBar Field: FCPdtRetPri1
                                tSql = "SELECT";
                                tSql += "\n  ISNULL(SUM(SubPmt.FCPmcPriNew), 0) AS FCPmcPriNew_SUM,";
                                tSql += "\n  ISNULL(SUM(SubPmt.FCPmcPriDisAmt), 0) AS FCPmcPriDisAmt_SUM,";
                                tSql += "\n  ISNULL(SUM(SubPmt.FCPmcPriDisPer), 0) AS FCPmcPriDisPer_SUM";
                                tSql += "\nFROM (";
                                tSql += "\n    SELECT TOP 1 *";
                                tSql += "\n    FROM TCNTPdtPmtCD WITH (NOLOCK)";
                                tSql += "\n    WHERE FTPmhDocNo = '" + ptPmhDocNo + "'";
                                tSql += "\n      AND FTPmcBarCodeGet = '" + oTblDP.Rows[i]["FTDtpBarCode"].ToString() + "'";
                                tSql += "\n) AS SubPmt";
                            }
                            else //case type 26, 27
                            {
                                //Krisana 2025-08-08 comsheet 2025-098 �?�?��?����?? TCNMPdtBar Field: FCPdtRetPri1
                                tSql = " SELECT";
                                tSql += " ISNULL(SUM(PmtCD.FCPmcPriNew), 0) AS FCPmcPriNew_SUM,";
                                tSql += " ISNULL(SUM(PmtCD.FCPmcPriDisAmt), 0) AS FCPmcPriDisAmt_SUM,";
                                tSql += " ISNULL(SUM(PmtCD.FCPmcPriDisPer), 0) AS FCPmcPriDisPer_SUM";
                                tSql += " FROM TCNTPdtPmtCD PmtCD WITH(NOLOCK)";
                                tSql += "\n  WHERE PmtCD.FTPmhDocNo = '" + ptPmhDocNo + "'";
                                tSql += "\n  AND PmtCD.FTPmcBarCodeGet = '" + oTblDP.Rows[i]["FTDtpBarCode"].ToString() + "'";
                                tSql += " AND PmtCD.FNPmcSeq = 1";
                            }

                            using (DataTable oTblDP_Dis = cCNSP.SP_SQLoExecute(tSql))
                            {
                                if (oTblDP_Dis.Rows.Count > 0)
                                {
                                    //�??��??�? Promotion �������??�?����?
                                    switch (ptPmdGetType)
                                    {
                                        case "3":   //?�?
                                            cPmtDiscount += double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriDisAmt_SUM"].ToString());
                                            break;
                                        case "4":   //? %
                                            cPmtDiscount += cDtpNet * (double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriDisPer_SUM"].ToString()) / 100.0); //*Thana 2026-05-22 Non-Sale Req (Use cDtpNet)
                                            break;
                                        case "2":   //�?�����
                                            cPmtDiscount += cDtpNet - double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriNew_SUM"].ToString()); //*Thana 2026-05-22 Non-Sale Req (Use cDtpNet)
                                            break;
                                        case "1":   //���
                                            cPmtDiscount += cDtpNet; //*Thana 2026-05-22 Non-Sale Req (Use cDtpNet)
                                            break;
                                        default:   
                                            cPmtDiscount += cDtpNet - double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriNew_SUM"].ToString()); //*Thana 2026-05-22 Non-Sale Req (Use cDtpNet)
                                            break;
                                    }
                                }
                                else
                                {
                                    return 0.0;
                                }
                            }
                        }
                    }
                }

                return cPmtDiscount;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_GETcPmtDiscount] Error : " + ex.Message + " SQL = " + tSql);
                return 0.0;
            }
        }


        public static double W_GETcPmtDiscount26_27(string ptPmtSeqNo, string ptSeqDP, string ptPmhDocNo, string ptPmdGetType, int nPmtType)
        {
            string tSql = "";
            double cPmtDiscount = 0.0;
            double cSumPmcOrgPri = 0.0;
            try
            {

                tSql = " SELECT FTDtpBarCode, FCDtpNet, FNDtpSeqNo"; //*Thana 2026-05-22 Non-Sale Req (Add FCDtpNet)
                tSql += "\n  FROM " + cCNVB.tVB_TmpDP;
                tSql += "\n  WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                tSql += "\n  AND FTSdtStaPdt = '1'";           //??��?��� 1:�?���, 2:�?�?, 3:�?��, 4: ?��? (Void)                                                                           
                tSql += "\n  AND ISNULL(FTPdtNoDis,'')='2'";   //Flag allow discount
                tSql += "\n  AND FNDtpSeqNo NOT IN (" + ptPmtSeqNo + ")";
                if (ptSeqDP.Trim().Length > 0) { tSql += "\n  AND FNDtpSeqNo IN (" + ptSeqDP + ")"; }

                using (DataTable oTblDP = cCNSP.SP_SQLoExecute(tSql))
                {
                    if (oTblDP.Rows.Count > 0)
                    {
                        for (int i = 0; i < oTblDP.Rows.Count; i++)
                        {
                            double cDtpNet = double.Parse(oTblDP.Rows[i]["FCDtpNet"].ToString()); //*Thana 2026-05-22 Non-Sale Req

                            //Krisana 2025-08-07 Fix Issue ���??�?� ���?��?�����������?���
                            if (nPmtType == 3)
                            {
                                //Krisana 2025-08-08 comsheet 2025-098 �?�?��?����?? TCNMPdtBar Field: FCPdtRetPri1
                                tSql = "SELECT";
                                tSql += "\n  ISNULL(SUM(SubPmt.FCPmcPriNew), 0) AS FCPmcPriNew_SUM,";
                                tSql += "\n  ISNULL(SUM(SubPmt.FCPmcPriDisAmt), 0) AS FCPmcPriDisAmt_SUM,";
                                tSql += "\n  ISNULL(SUM(SubPmt.FCPmcPriDisPer), 0) AS FCPmcPriDisPer_SUM";
                                tSql += "\nFROM (";
                                tSql += "\n    SELECT TOP 1 *";
                                tSql += "\n    FROM TCNTPdtPmtCD WITH (NOLOCK)";
                                tSql += "\n    WHERE FTPmhDocNo = '" + ptPmhDocNo + "'";
                                tSql += "\n      AND FTPmcBarCodeGet = '" + oTblDP.Rows[i]["FTDtpBarCode"].ToString() + "'";
                                tSql += "\n) AS SubPmt";
                            }
                            else //case type 26, 27
                            {
                                //Krisana 2025-08-08 comsheet 2025-098 �?�?��?����?? TCNMPdtBar Field: FCPdtRetPri1
                                tSql = " SELECT";
                                tSql += " ISNULL(SUM(PmtCD.FCPmcPriNew), 0) AS FCPmcPriNew_SUM,";
                                tSql += " ISNULL(SUM(PmtCD.FCPmcPriDisAmt), 0) AS FCPmcPriDisAmt_SUM,";
                                tSql += " ISNULL(SUM(PmtCD.FCPmcPriDisPer), 0) AS FCPmcPriDisPer_SUM";
                                tSql += " FROM TCNTPdtPmtCD PmtCD WITH(NOLOCK)";
                                tSql += "\n  WHERE PmtCD.FTPmhDocNo = '" + ptPmhDocNo + "'";
                                tSql += "\n  AND PmtCD.FTPmcBarCodeGet = '" + oTblDP.Rows[i]["FTDtpBarCode"].ToString() + "'";
                                tSql += " AND PmtCD.FNPmcSeq = 1";
                            }

                            using (DataTable oTblDP_Dis = cCNSP.SP_SQLoExecute(tSql))
                            {
                                if (oTblDP_Dis.Rows.Count > 0)
                                {
                                    //�??��??�? Promotion �������??�?����?
                                    switch (ptPmdGetType)
                                    {
                                        case "3":   //?�?
                                            cPmtDiscount += double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriDisAmt_SUM"].ToString());
                                            break;
                                        case "4":   //? %
                                            cPmtDiscount += cDtpNet * (double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriDisPer_SUM"].ToString()) / 100.0); //*Thana 2026-05-22 Non-Sale Req (Use cDtpNet)
                                            break;
                                        case "2":   //�?�����
                                            //cPmtDiscount += double.Parse(oTblDP_Dis.Rows[0]["FCPmcOrgPri"].ToString()) - double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriNew_SUM"].ToString());

                                            //Krisana 2025-11-12 Comsheet/2025-148
                                            cSumPmcOrgPri += cDtpNet; //*Thana 2026-05-22 Non-Sale Req (Use cDtpNet)
                                            if (cPmtDiscount == 0 || (cPmtDiscount < double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriNew_SUM"].ToString())))
                                            {
                                                cPmtDiscount = double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriNew_SUM"].ToString());
                                            }                                            
                                            break;
                                        case "1":   //���
                                            cPmtDiscount += cDtpNet; //*Thana 2026-05-22 Non-Sale Req (Use cDtpNet)
                                            break;
                                        default:
                                            cPmtDiscount += cDtpNet - double.Parse(oTblDP_Dis.Rows[0]["FCPmcPriNew_SUM"].ToString()); //*Thana 2026-05-22 Non-Sale Req (Use cDtpNet)
                                            break;
                                    }
                                }
                                else
                                {
                                    return 0.0;
                                }
                            }
                        }
                    }
                }

                //Krisana 2025-11-12 Comsheet/2025-148 ����? Logic ?�??? �?�����
                if (ptPmdGetType == "2")
                {
                    cPmtDiscount = cSumPmcOrgPri - cPmtDiscount;
                }

                return cPmtDiscount;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_GETcPmtDiscount26_27] Error : " + ex.Message + " SQL = " + tSql);
                return 0.0;
            }
        }

