                //tSql += "\n             xxx.FTPdtBarZ ";
                //tSql += "\n       ) ";
                //tSql += "\n ) ";

                tSql += "\n ORDER BY FCAmtPmtX ASC, FCAmtPmtY ASC, FCAmtPmtZ ASC, FCSpmQtyKeyZ DESC, FCQtyPmtX, FCQtyPmtY";
                #endregion SQL Check Promotion

                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType26] tSql : " + tSql);
                using (DataTable oDbTblTmpPTx = cCNSP.SP_SQLoExecute(tSql))
                {
                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType26] oDbTblTmpPTx.Rows.Count : " + oDbTblTmpPTx.Rows.Count);
                    if (oDbTblTmpPTx.Rows.Count > 0)
                    {
                        lsttPmtSeqNo = new List<string>();
                        W_AddxDatatoList(ref lsttPmtSeqNo, "0");

