                        oDbTblTmpPT = oDbTblTmpPTx.DefaultView.ToTable();
                        
                        for (int i = 0; i < oDbTblTmpPT.Rows.Count; i++)
                        {
                            bChkPdtPmt = false;
                            bChkPmt26 = false;
                            cSumQtyPmt = 0;

                            tPdtBarX = oDbTblTmpPT.Rows[i]["FTPdtBarX"].ToString();
                            tPdtBarY = oDbTblTmpPT.Rows[i]["FTPdtBarY"].ToString();
                            //tPdtBarZ = oDbTblTmpPT.Rows[i]["FTPdtBarZ"].ToString();
                            tPmtCode = oDbTblTmpPT.Rows[i]["FTPmhDocNo"].ToString();

                            nPmtTypeGetPro = int.Parse(oDbTblTmpPT.Rows[i]["FNSpmType"].ToString()); //*Puii 62-09-12 STAR Project [PR02] Update TSDP
                            nPmtType = int.Parse(oDbTblTmpPT.Rows[i]["FNSpmType"].ToString()); //Type �?������� 1-20
                            //tPmhGetType = oDbTblTmpPT.Rows[i]["FTPmhGetType"].ToString(); //*Tao 63-03-18 FTPmhGetType --> 5 = �������?��?���?� / ?�?��, 6 = �?���?��?���?� / ?�?��

                            string[] aPmtCode = tPmtCode.Split('|');
                            if (aPmtCode.Length > 1)
                            {
                                tPmtCode = aPmtCode[0];
                                tPdtCodeX = aPmtCode[1];
                            }
                            else
                            {
                                tPdtCodeX = "";
                            }

                            tPmtGetType = oDbTblTmpPT.Rows[i]["FTSpmGetType"].ToString();
                            nGetPro = nPmtType - 1; //������?�����?
                            nGetType = int.Parse(tPmtGetType) - 1; //Type �?������?�����? ��� �?�����, ?�??, ?�� %
                            tPmdGetType = tPmtGetType.ToString();
                            cW_QtyDiv[nGetPro, nGetType] = 0;
