                                        cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType26] cW_SumQty[" + nGetPro + ", " + nGetType + "] : " + cW_SumQty[nGetPro, nGetType]);
                                    }

