                                    //tPdtBarRetPro2 = tPdtBarZ;
                                    tPmtCodeGetPro = tPmtCode;

                                    tPdtCodeXGetPro = tPdtCodeX; //*Thana 65-08-02   CFM/2022 - 029 rework
                                    nPmtTypeGetProLast = nPmtTypeGetPro; //*Thana 65-08-02   CFM/2022 - 029 rework

                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType26] tPmtCodeGetPro : " + tPmtCodeGetPro);
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType26] tPdtCodeXGetPro : " + tPdtCodeXGetPro);  //*Thana 65-08-02   CFM/2022 - 029 rework
                                    cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType26] nPmtTypeGetPro : " + nPmtTypeGetPro.ToString());  //*Thana 65-08-02   CFM/2022 - 029 rework

