                                                                    if (cTotalDis > cSumDis)
                                                                    {
                                                                        cDis = cTotalDis - cSumDis;
                                                                    }
                                                                    else
                                                                    {
                                                                        cDis = 0;
                                                                    }
                                                                }
                                                                else
                                                                {
                                                                    //��??�?�?��?�?�� = (��??�?�?����� / �?��?��?������������) * �??�?��?�?��
                                                                    cDis = Math.Round((cTotalDis / cTotalAmt) * cNetB4Dis, 2);
                                                                    cSumDis += cDis;
                                                                }
                                                                #endregion Cal Discount by Pro. rate

                                                                tSqlUpDP = "UPDATE " + cCNVB.tVB_TmpDP + " WITH(ROWLOCK)";
                                                                tSqlUpDP += "\n SET FTPmhDocNo = '" + tPmtCodeGetPro + "', FNSpmType = " + nPmtTypeGetPro + ", FCDtpDis = " + string.Format("{0:F2}", cDis);
                                                                tSqlUpDP += "\n , FTDtpStaGetPmt = '3', FCDtpPmtQtyGet = 1";    //*Tao 62-12-06 �?����?����������� (FTDtpStaGetPmt 0:None, 1:������?���� 1 (1-11) ��?�� (DT), 2:������?���� 1 (1-11) ������� (CO), 3: ���?�������, 4:���?������?��������?��, FCDtpPmtQtyGet=�??�?��?�����?��??�������)
                                                                tSqlUpDP += "\n , FNDtpSdtSeqNoRef = " + nSdtSeqNoRef + ", FNDtpQtyPmtX = 0, FNDtpQtyPmtGetX = 0, FNDtpQtyPmtLeftX = 0";    // ������ ������������ Export

                                                                tSqlUpDP += "\n WHERE FNDtpSeqNo = " + nDPSeqNo;
                                                                tSqlUpDP += "\n AND FNSdtSeqNo = " + nDTSeqNo + " AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                                                                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType26 : " + nPmtTypeGetPro + "] tSqlUpDP : " + tSqlUpDP);
                                                                oW_SqlDPPmtGroup1.AppendLine(tSqlUpDP);
                                                                nW_CDSeqNo += 1;
                                                                C_PRCbSavePmtDP2CD(nW_CDSeqNo, nDPSeqNo); //�?�������??������������
                                                                W_PRCxUpdateUsedSeq(nPmtType, nDPSeqNo, (oDbTblTmpPT.Rows[i]["FTSpmStaInc"].ToString() == "1")); //*Thana 2026-05-22 Non-Sale Req
                                                                if (oDbTblTmpPT.Rows[i]["FTSpmStaInc"].ToString() != "1") 
                                                                {
                                                                    W_AddxDatatoList(ref lsttPmtSeqNo, nDPSeqNo.ToString());
                                                                }
                                                            }

                                                            tSeqNoRef = string.Join(",", lsttSeqNoRef.ToArray());

                                                            //Clear Promotion ����������??
                                                            W_PRCxClearTempDTPmt25_27(tSeqNoRef); //����������?�� TSDTxxx
                                                            W_PRCxClearTempDPPmt25_27(tSeqNoRef); //����������?�� TSDPxxx
                                                            W_PRCxClearTempCDPmt25_27(tSeqNoRef); //����������?�� TSCDxxx

                                                            if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                                                            {
                                                                //�?�?��??�??��??��?�� ?���? TSDTxxx
                                                                if (lsttSeqNo.Count > 0)
                                                                {
                                                                    for (int n = 0; n < lsttSeqNo.Count; n++)
                                                                    {
                                                                        string[] aDTDetail = lsttSeqNo[n].Split('|');
                                                                        nSeqNo = int.Parse(aDTDetail[0]);
                                                                        tVATInOrEx = aDTDetail[1];
                                                                        tVatType = aDTDetail[2];

                                                                        tSql = "SELECT SUM(FCDtpNet) AS FCDtpNet_SUM, SUM(FCDtpDis) AS FCDtpDis_SUM";
                                                                        tSql += "\n  FROM " + cCNVB.tVB_TmpDP + " WITH(NOLOCK)";
                                                                        tSql += "\n  WHERE FNSdtSeqNo = " + nSeqNo.ToString();
                                                                        tSql += "\n  AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                                                                        tSql += "\n  GROUP BY FTShdDocNo,FNSdtSeqNo";

                                                                        using (DataTable oDbTblDTx = cCNSP.SP_SQLoExecute(tSql))
                                                                        {
                                                                            if (oDbTblDTx.Rows.Count > 0)
                                                                            {

                                                                                #region Cal Discount by Pro. rate
                                                                                //�??��??��� Pro Rate
                                                                                cNetB4Dis = double.Parse(oDbTblDTx.Rows[0]["FCDtpNet_SUM"].ToString());
                                                                                cDis = double.Parse(oDbTblDTx.Rows[0]["FCDtpDis_SUM"].ToString());


                                                                                if (cDis == 0)
                                                                                {
                                                                                    tDisChgTxt = "";
                                                                                }
                                                                                else if (cDis < 0)
                                                                                    tDisChgTxt = String.Format("{0:F2}", (cDis * -1));
                                                                                else
                                                                                {
                                                                                    tDisChgTxt = "-" + String.Format("{0:F2}", cDis);
                                                                                }
                                                                                cNet = cNetB4Dis - cDis; //�?��?����?�?�?������� = �??�?? - �??����?
                                                                                cVat = (tVatType == "1" ? cCNSP.SP_CALcVatValue((tVATInOrEx == "1" ? false : true), cNet, cCNVB.cVB_VatRate) : 0);
                                                                                cVatable = ((tVatType == "1") ? cNet - cVat : 0);  //1:vat, 2:novat (0)
                                                                                #endregion Cal Discount by Pro. rate

                                                                                tSqlUpDT = "UPDATE " + cCNVB.tVB_TmpDT + " WITH(ROWLOCK)";
                                                                                tSqlUpDT += "\n SET FTSdtDisChgTxt = '" + tDisChgTxt + "', FCSdtDis = " + String.Format("{0:F2}", cDis) + ", FCSdtNet = " + String.Format("{0:F2}", cNet) + ", FCSdtVat = " + String.Format("{0:F2}", cVat) + ", FCSdtVatable = " + String.Format("{0:F2}", cVatable) + ", FCSdtPmtQtyGet = 1";
                                                                                tSqlUpDT += "\n , FTPmhCode = '" + tPmtCodeGetPro + "', FTPmhType = '" + nPmtTypeGetPro + "'";
                                                                                tSqlUpDT += "\n , FTPdtName = CASE WHEN LEFT(FTPdtName, 1) <> '*' THEN '*' + FTPdtName ELSE FTPdtName END";
                                                                                tSqlUpDT += "\n WHERE FNSdtSeqNo = " + nSeqNo + " AND FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                                                                                cCNSP.SP_ADDxLog("LogPmtPrc", "[W_CHKxCalByPMTGrpType26 : " + nPmtTypeGetPro + "] tSqlUpDT : " + tSqlUpDT);
                                                                                oW_SqlDTPmtGroup1.AppendLine(tSqlUpDT);
                                                                            }
                                                                        }
                                                                    }
                                                                }

                                                                if (W_SQLbExecute(1)) //Update Promotion Group1 (���������?��)
                                                                {
                                                                    bType26Success = true;
                                                                }
                                                                else
                                                                {
                                                                    bType26Success = false;
                                                                }
                                                            }
                                                            else
                                                            {
                                                                bType26Success = false;
                                                            }
                                                        }
                                                    }
                                                    //bChkPdtPmt = true;
                                                }
                                                else
                                                {
                                                    bChkPdtPmt = false;
                                                }
                                            }
                                            else
                                            {
                                                bChkPmt26 = false;
                                            }
                                        }
                                    }
                                    else
                                    {
                                        bChkPmt26 = false;
                                    }
                                }

                                //�???�?��?�����������?������?�����������
                                tlstPmtSeqNo = string.Join(",", lsttPmtSeqNo.ToArray());
                                tlstDPSeqNo = string.Join(",", lsttDPSeqNo.ToArray());
                                cMaxPdt = W_GETcMaxPdt26(tlstPmtSeqNo, tPmtCode, tlstDPSeqNo); //�??�?��?�����������?������?�����������
                                if (cSumQtyPmt > cMaxPdt || !bChkPmt26)
                                {
                                    bChkPdtPmt = true;  //�?�? loop while
                                }
                                else
                                {
                                    if (cMaxPdt < 1)
                                    {
                                        bChkPdtPmt = true;
                                        break;
                                    }
                                }

                                for (int nlst = 0; nlst < lsttDPSeqNo.Count; nlst++)
                                {
                                    W_AddxDatatoList(ref lsttPmtSeqNo, lsttDPSeqNo[nlst].ToString());
                                }

                            }

                            NextLoopPT:
                            { continue; }
                        }
                    }
                }
                return bType26Success;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[W_CHKxCalByPMTGrpType26] Error : " + ex.Message);
                return false;
            }
        }

        public bool C_InsPMtoPT(int pnPdtSeq, string ptPdtBarCode, int pnPdtQty = 1) 
        {
            try
            {
                if (cCNSP.C_PRCDeCryptStr(tDllKey, tDllPass, 256) != "AdaNewPmt") return false;
                cCNSP.SP_ADDxLog("LogPmtPrc", "[cAdaNewPmt] V." + VersionDll + "");
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_InsPMtoPT] ============ START ============");
                bool bResult = false;
                cCNSP.SP_SETxDBConfig(tServer, tDB, tUser, tPwd);
                cCNSP.SP_ADDxLog("LogPmtPrc", "[C_InsPMtoPT] DocNo : " + tShdDocNo + ", Seq : " + pnPdtSeq.ToString() + ", BarCode : " + ptPdtBarCode + ", Qty : " + pnPdtQty.ToString());
                cCNVB.tVB_ShdDocNo = tShdDocNo;
                
                if (C_PRCbSavePdt2PT(pnPdtSeq, ptPdtBarCode, pnPdtQty)) //Insert �?��� ������������ ���� TSPTxxx
                {
                    bResult = true;
                }
                else
                {
                    bResult = false;
                }
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_InsPMtoPT] Result : " + bResult.ToString());
                return bResult;
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_InsPMtoPT] Error : " + ex.Message);
                return false;
            }
        }

        private static void C_PRCbUpdateSeqCD()
        {
            DataTable oDbTblCD = null;
            try
            {
                string tSql = "SELECT FNDtpSeqNo FROM TSCD" + cCNVB.tVB_PosCode + " WITH (NOLOCK)";
                tSql += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                oDbTblCD = cCNSP.SP_SQLoExecute(tSql);
                if (oDbTblCD != null && oDbTblCD.Rows.Count > 0)
                {
                    //Re Seq FNDtpSeqNo  
                    tSql = "UPDATE TSCD" + cCNVB.tVB_PosCode + " WITH (ROWLOCK)";
                    tSql += "\n SET FNDtpSeqNo = (FNDtpSeqNo * -1)";
                    tSql += "\n WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "';";
                    cCNSP.SP_SQLoExecute(tSql);

                    //New Running Seqno in TSCDxxx
                    tSql = "SELECT   FNDtpSeqNo , FNSdtSeqNo ";
                    tSql += " FROM  TSCD" + cCNVB.tVB_PosCode + " WITH(NOLOCK)";
                    tSql += " WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                    tSql += " ORDER BY FNSpmType DESC, FNDtpSeqNo ";
                    int nSeqNo = 0;
                    using (DataTable oDbTbl = cCNSP.SP_SQLoExecute(tSql))
                    {
                        for (int iDt = 0; iDt < oDbTbl.Rows.Count; iDt++)
                        {
                            string tFNDtpSeqNo = oDbTbl.Rows[iDt]["FNDtpSeqNo"].ToString();
                            string tFNSdtSeqNo = oDbTbl.Rows[iDt]["FNSdtSeqNo"].ToString();
                            nSeqNo += 1;
                            tSql = "UPDATE TSCD" + cCNVB.tVB_PosCode;
                            tSql += " SET  FNDtpSeqNo=  " + nSeqNo;
                            tSql += " WHERE FTShdDocNo = '" + cCNVB.tVB_ShdDocNo + "'";
                            tSql += " AND FNDtpSeqNo=" + tFNDtpSeqNo;
                            tSql += " AND FNSdtSeqNo=" + tFNSdtSeqNo;
                            cCNSP.SP_SQLbExecute(tSql.ToString());
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                cCNSP.SP_ADDxLog("LogPmtErr", "[C_PRCbUpdateSeqCD] Error : " + ex.Message);
            }
        }

    }
}

